{
  "name": "LogiTrans - Gestão de Fretes",
  "description": "Sistema profissional para controle de viagens, fretes, cadastros de motoristas, veículos e análise inteligente de dados de logística.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Customer {
  id: string;
  name: string;
}

export interface Driver {
  id: string;
  name: string;
}

export interface Vehicle {
  id: string;
  plate: string;
}

export interface Location {
  id: string;
  name: string;
}

export interface Material {
  id: string;
  name: string;
}

export interface FreightRate {
  id: string;
  originId: string;
  destinationId: string;
  pricePerTon: number;
}

export interface Trip {
  id: string;
  date: string;
  invoiceNumber: string;
  customerId: string;
  driverId: string;
  vehicleId: string;
  originId: string;
  destinationId: string;
  materialId: string;
  qtyTons: number;
  pricePerTon: number;
  totalValue: number;
  createdAt: number;
}

export type ViewState = 'dashboard' | 'new_trip' | 'history' | 'registrations' | 'freight_table';
export type RegistrationType = 'customers' | 'drivers' | 'vehicles' | 'locations' | 'materials';

import { 
  Customer, Driver, Vehicle, Location, Material, FreightRate, Trip 
} from './types';

const STORAGE_KEY = 'logitrans_db_v1';

interface DB {
  customers: Customer[];
  drivers: Driver[];
  vehicles: Vehicle[];
  locations: Location[];
  materials: Material[];
  freightRates: FreightRate[];
  trips: Trip[];
  recentIds: Record<string, string[]>;
}

const INITIAL_DB: DB = {
  customers: [{ id: '1', name: 'Agro Industrial Silva' }],
  drivers: [{ id: '1', name: 'João Batista' }],
  vehicles: [{ id: '1', plate: 'ABC-1234' }],
  locations: [{ id: '1', name: 'Porto de Santos' }, { id: '2', name: 'Fazenda Boa Vista' }],
  materials: [{ id: '1', name: 'Soja' }],
  freightRates: [{ id: '1', originId: '2', destinationId: '1', pricePerTon: 150 }],
  trips: [],
  recentIds: {}
};

export const getDB = (): DB => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : INITIAL_DB;
};

export const saveDB = (db: DB) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(db));
};

export const updateRecent = (category: string, id: string) => {
  const db = getDB();
  const recents = db.recentIds[category] || [];
  const filtered = recents.filter(rid => rid !== id);
  db.recentIds[category] = [id, ...filtered].slice(0, 5);
  saveDB(db);
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Truck, 
  History, 
  Settings, 
  Table as TableIcon, 
  Plus, 
  Search, 
  Menu, 
  X, 
  ChevronRight,
  BarChart3,
  Bot
} from 'lucide-react';
import { ViewState, Trip, RegistrationType } from './types';
import { getDB, saveDB } from './db';
import Dashboard from './components/Dashboard';
import NewTripForm from './components/NewTripForm';
import TripHistory from './components/TripHistory';
import Registrations from './components/Registrations';
import FreightTable from './components/FreightTable';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('dashboard');
  const [db, setDb] = useState(getDB());
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [globalSearch, setGlobalSearch] = useState('');

  // Sync state to storage
  useEffect(() => {
    saveDB(db);
  }, [db]);

  const navigate = (nextView: ViewState) => {
    setView(nextView);
    setIsSidebarOpen(false);
  };

  const NavItem = ({ icon: Icon, label, target }: { icon: any, label: string, target: ViewState }) => (
    <button
      onClick={() => navigate(target)}
      className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
        view === target 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
          : 'text-slate-600 hover:bg-slate-100'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Mobile Header */}
      <header className="md:hidden bg-white border-b px-4 py-3 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center space-x-2">
          <div className="bg-blue-600 p-1.5 rounded-lg text-white">
            <Truck size={20} />
          </div>
          <h1 className="font-bold text-lg text-slate-800">LogiTrans</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-600">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </header>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-200 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-4">
          <div className="hidden md:flex items-center space-x-3 px-2 mb-8 mt-2">
            <div className="bg-blue-600 p-2 rounded-xl text-white">
              <Truck size={24} />
            </div>
            <h1 className="font-extrabold text-xl tracking-tight text-slate-800">LogiTrans</h1>
          </div>

          <nav className="flex-1 space-y-2">
            <NavItem icon={BarChart3} label="Dashboard" target="dashboard" />
            <NavItem icon={Plus} label="Nova Viagem" target="new_trip" />
            <NavItem icon={History} label="Histórico" target="history" />
            <NavItem icon={Settings} label="Cadastros" target="registrations" />
            <NavItem icon={TableIcon} label="Tabela de Fretes" target="freight_table" />
          </nav>

          <div className="pt-4 border-t mt-auto">
            <p className="text-xs text-slate-400 px-2 font-medium uppercase tracking-wider mb-2">Desenvolvedor</p>
            <div className="bg-slate-50 p-3 rounded-lg flex items-center space-x-3">
              <div className="w-8 h-8 rounded-full bg-slate-300 flex items-center justify-center text-xs font-bold text-slate-600">AD</div>
              <div>
                <p className="text-sm font-semibold text-slate-700 leading-none">Admin</p>
                <p className="text-xs text-slate-500 mt-1">Nível Supervisor</p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-auto">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <Dashboard 
              navigate={navigate} 
              db={db} 
              onSearch={setGlobalSearch} 
            />
          )}
          {view === 'new_trip' && (
            <NewTripForm 
              db={db} 
              onSave={(newTrip) => {
                setDb(prev => ({ ...prev, trips: [newTrip, ...prev.trips] }));
                navigate('history');
              }}
              onCancel={() => navigate('dashboard')}
            />
          )}
          {view === 'history' && (
            <TripHistory 
              db={db} 
              initialSearch={globalSearch} 
              onDelete={(id) => setDb(prev => ({ ...prev, trips: prev.trips.filter(t => t.id !== id) }))}
            />
          )}
          {view === 'registrations' && (
            <Registrations db={db} setDb={setDb} />
          )}
          {view === 'freight_table' && (
            <FreightTable db={db} setDb={setDb} />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
