const Dashboard: React.FC<DashboardProps> = ({ navigate, db, onSearch }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const stats = [
    { label: 'Viagens no Mês', value: db.trips.length, icon: TrendingUp, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Total Faturado', value: `R$ ${db.trips.reduce((acc: number, t: any) => acc + t.totalValue, 0).toLocaleString('pt-BR')}`, icon: DollarSign, color: 'text-emerald-600', bg: 'bg-emerald-50' },
    { label: 'Toneladas Transportadas', value: `${db.trips.reduce((acc: number, t: any) => acc + t.qtyTons, 0).toLocaleString('pt-BR')}t`, icon: Package, color: 'text-amber-600', bg: 'bg-amber-50' },
    { label: 'Clientes Ativos', value: db.customers.length, icon: Users, color: 'text-indigo-600', bg: 'bg-indigo-50' },
