      <header>
        <h2 className="text-3xl font-extrabold text-slate-900">Bom dia, Gestor</h2>
        <p className="text-slate-500 mt-1">Aqui está o resumo das suas operações logísticas hoje.</p>
      </header>

      {/* Quick Search */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
        <form onSubmit={handleQuickSearch} className="flex flex-col md:flex-row gap-4">
          <div className="flex-1 relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
            <input 
              type="text" 
              placeholder="Busca rápida por NF, Cliente, Motorista ou Placa..."
              className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
