import React, { useState, useMemo } from 'react';
import { Search, Filter, Trash2, Download, Calendar, Truck, User, MapPin } from 'lucide-react';
import { Trip } from '../types';

interface TripHistoryProps {
  db: any;
  initialSearch: string;
  onDelete: (id: string) => void;
}

const TripHistory: React.FC<TripHistoryProps> = ({ db, initialSearch, onDelete }) => {
  const [searchTerm, setSearchTerm] = useState(initialSearch);
  const [filter, setFilter] = useState({
    date: '',
    customerId: '',
    driverId: '',
    vehicleId: '',
    materialId: ''
  });

  const filteredTrips = useMemo(() => {
    return db.trips.filter((trip: Trip) => {
      const customer = db.customers.find((c: any) => c.id === trip.customerId)?.name || '';
      const driver = db.drivers.find((d: any) => d.id === trip.driverId)?.name || '';
      const vehicle = db.vehicles.find((v: any) => v.id === trip.vehicleId)?.plate || '';
      const origin = db.locations.find((l: any) => l.id === trip.originId)?.name || '';
      const dest = db.locations.find((l: any) => l.id === trip.destinationId)?.name || '';

      const matchesSearch = [
        trip.invoiceNumber,
        customer,
        driver,
        vehicle,
        origin,
        dest
      ].some(val => val.toLowerCase().includes(searchTerm.toLowerCase()));

      const matchesFilters = 
        (!filter.date || trip.date === filter.date) &&
        (!filter.customerId || trip.customerId === filter.customerId) &&
        (!filter.driverId || trip.driverId === filter.driverId) &&
        (!filter.vehicleId || trip.vehicleId === filter.vehicleId) &&
        (!filter.materialId || trip.materialId === filter.materialId);

      return matchesSearch && matchesFilters;
    });
  }, [db, searchTerm, filter]);

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Histórico de Viagens</h2>
          <p className="text-slate-500 text-sm">Gerencie e filtre todos os lançamentos realizados.</p>
        </div>
        <button className="flex items-center space-x-2 bg-slate-100 text-slate-600 px-4 py-2 rounded-xl font-semibold hover:bg-slate-200 transition-colors">
          <Download size={18} />
          <span>Exportar CSV</span>
        </button>
      </div>

      {/* Filters Bar */}
      <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-4">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={20} />
          <input 
            type="text" 
            placeholder="Pesquisar por NF, cliente, motorista..."
            className="w-full pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="grid grid-cols-2 md:grid-cols-5 gap-3">
          <select 
            value={filter.customerId}
            onChange={e => setFilter(prev => ({ ...prev, customerId: e.target.value }))}
            className="px-3 py-2 rounded-lg border border-slate-200 text-sm outline-none"
          >
            <option value="">Cliente</option>
            {db.customers.map((c: any) => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
          <select 
            value={filter.driverId}
            onChange={e => setFilter(prev => ({ ...prev, driverId: e.target.value }))}
            className="px-3 py-2 rounded-lg border border-slate-200 text-sm outline-none"
          >
            <option value="">Motorista</option>
            {db.drivers.map((d: any) => <option key={d.id} value={d.id}>{d.name}</option>)}
          </select>
          <select 
            value={filter.vehicleId}
            onChange={e => setFilter(prev => ({ ...prev, vehicleId: e.target.value }))}
            className="px-3 py-2 rounded-lg border border-slate-200 text-sm outline-none"
          >
            <option value="">Veículo</option>
            {db.vehicles.map((v: any) => <option key={v.id} value={v.id}>{v.plate}</option>)}
          </select>
          <select 
            value={filter.materialId}
            onChange={e => setFilter(prev => ({ ...prev, materialId: e.target.value }))}
            className="px-3 py-2 rounded-lg border border-slate-200 text-sm outline-none"
          >
            <option value="">Material</option>
            {db.materials.map((m: any) => <option key={m.id} value={m.id}>{m.name}</option>)}
          </select>
          <input 
            type="date"
            value={filter.date}
            onChange={e => setFilter(prev => ({ ...prev, date: e.target.value }))}
            className="px-3 py-2 rounded-lg border border-slate-200 text-sm outline-none"
          />
        </div>
      </div>

      {/* Trips Table/Cards */}
      <div className="space-y-4">
        {filteredTrips.length === 0 ? (
          <div className="text-center py-20 bg-white rounded-3xl border-2 border-dashed border-slate-100">
            <History size={48} className="mx-auto text-slate-200 mb-4" />
            <p className="text-slate-400 font-medium">Nenhuma viagem encontrada com esses filtros.</p>
          </div>
        ) : (
          <div className="overflow-x-auto rounded-2xl border border-slate-100 shadow-sm">
            <table className="w-full bg-white text-left">
              <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                <tr>
                  <th className="px-6 py-4">Data / NF</th>
                  <th className="px-6 py-4">Cliente / Motorista</th>
                  <th className="px-6 py-4">Rota / Placa</th>
                  <th className="px-6 py-4 text-right">Volume</th>
                  <th className="px-6 py-4 text-right">Valor Total</th>
                  <th className="px-6 py-4"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {filteredTrips.map((trip: Trip) => {
                  const customer = db.customers.find((c: any) => c.id === trip.customerId);
                  const driver = db.drivers.find((d: any) => d.id === trip.driverId);
                  const vehicle = db.vehicles.find((v: any) => v.id === trip.vehicleId);
                  const origin = db.locations.find((l: any) => l.id === trip.originId);
                  const dest = db.locations.find((l: any) => l.id === trip.destinationId);

                  return (
                    <tr key={trip.id} className="hover:bg-slate-50/50 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="flex flex-col">
                          <span className="font-semibold text-slate-900">{new Date(trip.date).toLocaleDateString('pt-BR')}</span>
                          <span className="text-xs text-slate-500 font-mono">NF {trip.invoiceNumber}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex flex-col">
                          <span className="font-medium text-slate-700">{customer?.name}</span>
                          <span className="text-xs text-slate-500">{driver?.name}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex flex-col">
                          <div className="flex items-center text-xs text-slate-600 space-x-1">
                            <span>{origin?.name}</span>
                            <span className="text-slate-300">→</span>
                            <span>{dest?.name}</span>
                          </div>
                          <span className="text-sm font-bold text-blue-600 mt-0.5">{vehicle?.plate}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="font-semibold text-slate-700">{trip.qtyTons}t</span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="font-bold text-slate-900">R$ {trip.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <button 
                          onClick={() => onDelete(trip.id)}
                          className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all opacity-0 group-hover:opacity-100"
                        >
                          <Trash2 size={18} />
                        </button>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default TripHistory;

import React, { useState } from 'react';
import { Search, Plus, Edit2, Trash2, X, Check, User, Users, Truck, MapPin, Package } from 'lucide-react';
import { RegistrationType } from '../types';

interface RegistrationsProps {
  db: any;
  setDb: (fn: (prev: any) => any) => void;
}

const Registrations: React.FC<RegistrationsProps> = ({ db, setDb }) => {
  const [activeTab, setActiveTab] = useState<RegistrationType>('customers');
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [newValue, setNewValue] = useState('');

  const tabs = [
    { id: 'customers', label: 'Clientes', icon: Users, list: db.customers },
    { id: 'drivers', label: 'Motoristas', icon: User, list: db.drivers },
    { id: 'vehicles', label: 'Veículos', icon: Truck, list: db.vehicles },
    { id: 'locations', label: 'Locais', icon: MapPin, list: db.locations },
    { id: 'materials', label: 'Materiais', icon: Package, list: db.materials },
  ];

  const currentTab = tabs.find(t => t.id === activeTab)!;

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newValue.trim()) return;

    setDb(prev => ({
      ...prev,
      [activeTab]: [...prev[activeTab], { 
        id: crypto.randomUUID(), 
        [activeTab === 'vehicles' ? 'plate' : 'name']: newValue 
      }]
    }));
    setNewValue('');
  };

  const handleUpdate = (id: string) => {
    setDb(prev => ({
      ...prev,
      [activeTab]: prev[activeTab].map((item: any) => 
        item.id === id ? { ...item, [activeTab === 'vehicles' ? 'plate' : 'name']: editValue } : item
      )
    }));
    setIsEditing(null);
  };

  const handleDelete = (id: string) => {
    if (!confirm('Deseja excluir este registro?')) return;
    setDb(prev => ({
      ...prev,
      [activeTab]: prev[activeTab].filter((item: any) => item.id !== id)
    }));
  };

  const filteredItems = currentTab.list.filter((item: any) => {
    const val = item.name || item.plate || '';
    return val.toLowerCase().includes(searchTerm.toLowerCase());
  });

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header>
        <h2 className="text-2xl font-bold text-slate-900">Cadastros do Sistema</h2>
        <p className="text-slate-500 text-sm">Gerencie as entidades base da sua operação.</p>
      </header>

      {/* Tabs */}
      <div className="flex overflow-x-auto pb-2 gap-2 scrollbar-hide">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as RegistrationType)}
            className={`flex items-center space-x-2 px-6 py-3 rounded-xl font-bold transition-all whitespace-nowrap ${
              activeTab === tab.id 
                ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' 
                : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-100'
            }`}
          >
            <tab.icon size={18} />
            <span>{tab.label}</span>
          </button>
        ))}
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        {/* Header Actions */}
        <div className="p-6 border-b border-slate-50 bg-slate-50/30 flex flex-col md:flex-row gap-4">
          <form onSubmit={handleAdd} className="flex-1 flex gap-2">
            <input 
              type="text" 
              placeholder={`Novo ${currentTab.label.slice(0, -1)}...`}
              className="flex-1 px-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              value={newValue}
              onChange={e => setNewValue(e.target.value)}
            />
            <button 
              type="submit"
              className="bg-blue-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-blue-700 transition-colors flex items-center space-x-2"
            >
              <Plus size={20} />
              <span className="hidden md:inline">Adicionar</span>
            </button>
          </form>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Pesquisar..."
              className="pl-10 pr-4 py-3 rounded-xl border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none w-full md:w-64"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        {/* List */}
        <div className="divide-y divide-slate-50">
          {filteredItems.length === 0 ? (
            <div className="p-12 text-center text-slate-400 font-medium">
              Nenhum item encontrado.
            </div>
          ) : (
            filteredItems.map((item: any) => (
              <div key={item.id} className="p-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                {isEditing === item.id ? (
                  <div className="flex-1 flex gap-2 items-center">
                    <input 
                      autoFocus
                      type="text" 
                      className="flex-1 px-3 py-2 rounded-lg border border-blue-500 outline-none"
                      value={editValue}
                      onChange={e => setEditValue(e.target.value)}
                    />
                    <button onClick={() => handleUpdate(item.id)} className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg">
                      <Check size={20} />
                    </button>
                    <button onClick={() => setIsEditing(null)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg">
                      <X size={20} />
                    </button>
                  </div>
                ) : (
                  <>
                    <div className="flex items-center space-x-3">
                      <div className="p-2 bg-slate-100 rounded-lg text-slate-500">
                        <currentTab.icon size={18} />
                      </div>
                      <span className="font-semibold text-slate-700">{item.name || item.plate}</span>
                    </div>
                    <div className="flex space-x-2">
                      <button 
                        onClick={() => {
                          setIsEditing(item.id);
                          setEditValue(item.name || item.plate);
                        }}
                        className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => handleDelete(item.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default Registrations;

import React, { useState } from 'react';
import { Search, Plus, Trash2, MapPin, Calculator, AlertCircle } from 'lucide-react';
import { FreightRate } from '../types';

interface FreightTableProps {
  db: any;
  setDb: (fn: (prev: any) => any) => void;
}

const FreightTable: React.FC<FreightTableProps> = ({ db, setDb }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [newRate, setNewRate] = useState({
    originId: '',
    destinationId: '',
    pricePerTon: 0
  });
  const [error, setError] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!newRate.originId || !newRate.destinationId || newRate.pricePerTon <= 0) {
      setError('Preencha todos os campos corretamente.');
      return;
    }

    if (newRate.originId === newRate.destinationId) {
      setError('Origem e destino não podem ser iguais.');
      return;
    }

    const exists = db.freightRates.some(
      (fr: FreightRate) => fr.originId === newRate.originId && fr.destinationId === newRate.destinationId
    );

    if (exists) {
      setError('Esta rota já está cadastrada.');
      return;
    }

    setDb(prev => ({
      ...prev,
      freightRates: [...prev.freightRates, { id: crypto.randomUUID(), ...newRate }]
    }));

    setNewRate({ originId: '', destinationId: '', pricePerTon: 0 });
  };

  const handleDelete = (id: string) => {
    if (!confirm('Deseja excluir esta rota?')) return;
    setDb(prev => ({
      ...prev,
      freightRates: prev.freightRates.filter((fr: FreightRate) => fr.id !== id)
    }));
  };

  const filteredRates = db.freightRates.filter((rate: FreightRate) => {
    const origin = db.locations.find((l: any) => l.id === rate.originId)?.name || '';
    const dest = db.locations.find((l: any) => l.id === rate.destinationId)?.name || '';
    const term = searchTerm.toLowerCase();
    return origin.toLowerCase().includes(term) || dest.toLowerCase().includes(term);
  });

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header>
        <h2 className="text-2xl font-bold text-slate-900">Tabela de Fretes</h2>
        <p className="text-slate-500 text-sm">Configure os valores padrões por rota (tonelada).</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Add Form */}
        <div className="lg:col-span-1">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm sticky top-6">
            <h3 className="font-bold text-slate-800 mb-6 flex items-center space-x-2">
              <Plus size={20} className="text-blue-600" />
              <span>Nova Rota</span>
            </h3>

            <form onSubmit={handleAdd} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Origem</label>
                <select 
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500"
                  value={newRate.originId}
                  onChange={e => setNewRate(prev => ({ ...prev, originId: e.target.value }))}
                >
                  <option value="">Selecione...</option>
                  {db.locations.map((l: any) => <option key={l.id} value={l.id}>{l.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Destino</label>
                <select 
                  className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500"
                  value={newRate.destinationId}
                  onChange={e => setNewRate(prev => ({ ...prev, destinationId: e.target.value }))}
                >
                  <option value="">Selecione...</option>
                  {db.locations.map((l: any) => <option key={l.id} value={l.id}>{l.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Valor por Tonelada (R$)</label>
                <div className="relative">
                  <Calculator className="absolute right-3 top-3 text-slate-400" size={18} />
                  <input 
                    type="number" 
                    step="0.01"
                    className="w-full px-4 py-3 rounded-xl border border-slate-200 outline-none focus:ring-2 focus:ring-blue-500"
                    value={newRate.pricePerTon || ''}
                    onChange={e => setNewRate(prev => ({ ...prev, pricePerTon: Number(e.target.value) }))}
                    placeholder="Ex: 150.00"
                  />
                </div>
              </div>

              {error && (
                <div className="p-3 bg-red-50 border border-red-100 rounded-xl flex items-center space-x-2 text-red-600 text-sm font-medium">
                  <AlertCircle size={16} />
                  <span>{error}</span>
                </div>
              )}

              <button 
                type="submit"
                className="w-full bg-blue-600 text-white py-4 rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 active:scale-95"
              >
                Salvar Rota
              </button>
            </form>
          </div>
        </div>

        {/* List */}
        <div className="lg:col-span-2 space-y-4">
          <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center">
            <Search className="text-slate-400 ml-2" size={20} />
            <input 
              type="text" 
              placeholder="Pesquisar rotas..."
              className="flex-1 px-4 py-2 outline-none"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                <tr>
                  <th className="px-6 py-4">Rota de Transporte</th>
                  <th className="px-6 py-4 text-right">Valor / Tonelada</th>
                  <th className="px-6 py-4"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredRates.length === 0 ? (
                  <tr>
                    <td colSpan={3} className="p-12 text-center text-slate-400 font-medium">Nenhuma rota cadastrada.</td>
                  </tr>
                ) : (
                  filteredRates.map((rate: FreightRate) => {
                    const origin = db.locations.find((l: any) => l.id === rate.originId);
                    const dest = db.locations.find((l: any) => l.id === rate.destinationId);
                    return (
                      <tr key={rate.id} className="hover:bg-slate-50 transition-colors group">
                        <td className="px-6 py-4">
                          <div className="flex items-center space-x-3">
                            <div className="flex flex-col">
                              <span className="font-bold text-slate-700">{origin?.name}</span>
                              <div className="flex items-center space-x-1 text-slate-400">
                                <MapPin size={12} />
