import React, { useState, useEffect, useMemo } from 'react';
// Added Truck to imports to fix "Cannot find name 'Truck'" error
import { Save, X, Info, Calculator, Calendar, Truck } from 'lucide-react';
import { Trip, Customer, Driver, Vehicle, Location, Material, FreightRate } from '../types';
import { updateRecent } from '../db';

interface NewTripFormProps {
  db: any;
  onSave: (trip: Trip) => void;
  onCancel: () => void;
}

const NewTripForm: React.FC<NewTripFormProps> = ({ db, onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    invoiceNumber: '',
    customerId: '',
    driverId: '',
    vehicleId: '',
    originId: '',
    destinationId: '',
    materialId: '',
    qtyTons: 0,
    pricePerTon: 0,
    totalValue: 0
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  // Sorting helper: puts recently used at the top
  const getSortedOptions = <T extends { id: string; name?: string; plate?: string }>(
    list: T[], 
    category: string
  ) => {
    const recents = db.recentIds[category] || [];
    return [...list].sort((a, b) => {
      const aRecent = recents.indexOf(a.id);
      const bRecent = recents.indexOf(b.id);
      if (aRecent !== -1 && bRecent !== -1) return aRecent - bRecent;
      if (aRecent !== -1) return -1;
      if (bRecent !== -1) return 1;
      const aName = a.name || a.plate || '';
      const bName = b.name || b.plate || '';
      return aName.localeCompare(bName);
    });
  };

  // Auto-fill price logic
  useEffect(() => {
    if (formData.originId && formData.destinationId) {
      const rate = db.freightRates.find(
        (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
      );
      if (rate) {
        setFormData(prev => ({ ...prev, pricePerTon: rate.pricePerTon }));
      }
    }
  }, [formData.originId, formData.destinationId, db.freightRates]);

  // Auto-calculate total
  useEffect(() => {
    setFormData(prev => ({ 
      ...prev, 
      totalValue: Number((prev.qtyTons * prev.pricePerTon).toFixed(2)) 
    }));
  }, [formData.qtyTons, formData.pricePerTon]);

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.invoiceNumber) newErrors.invoiceNumber = 'Campo obrigatório';
    if (db.trips.some((t: Trip) => t.invoiceNumber === formData.invoiceNumber)) {
      newErrors.invoiceNumber = 'Nota fiscal já cadastrada';
    }
    if (!formData.customerId) newErrors.customerId = 'Selecione o cliente';
    if (!formData.driverId) newErrors.driverId = 'Selecione o motorista';
    if (!formData.vehicleId) newErrors.vehicleId = 'Selecione o veículo';
    if (!formData.originId) newErrors.originId = 'Selecione a origem';
    if (!formData.destinationId) newErrors.destinationId = 'Selecione o destino';
    if (formData.qtyTons <= 0) newErrors.qtyTons = 'Deve ser maior que zero';

    // Validate route existence in freight table
    const routeExists = db.freightRates.some(
      (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
    );
    if (!routeExists && formData.originId && formData.destinationId) {
      newErrors.route = 'Rota não cadastrada na Tabela de Fretes';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    // Record recents
    updateRecent('customers', formData.customerId);
    updateRecent('drivers', formData.driverId);
    updateRecent('vehicles', formData.vehicleId);

    const newTrip: Trip = {
      ...formData,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    onSave(newTrip);
  };

  const inputClass = (field: string) => `
    w-full px-4 py-3 rounded-xl border outline-none transition-all
    ${errors[field] ? 'border-red-500 bg-red-50' : 'border-slate-200 focus:ring-2 focus:ring-blue-500'}
  `;

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-bold text-slate-900">Novo Lançamento de Viagem</h2>
        <button onClick={onCancel} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Left Column: Core Details */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-4">
            <h3 className="font-bold text-slate-800 flex items-center space-x-2">
              <Info size={18} className="text-blue-500" />
              <span>Dados Principais</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Data</label>
                <div className="relative">
                  <Calendar className="absolute right-3 top-3 text-slate-400" size={18} />
                  <input 
                    type="date" 
                    value={formData.date}
                    onChange={e => setFormData(prev => ({ ...prev, date: e.target.value }))}
                    className={inputClass('date')}
                  />
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Nota Fiscal</label>
                <input 
                  type="text" 
                  placeholder="000.000"
                  value={formData.invoiceNumber}
                  onChange={e => setFormData(prev => ({ ...prev, invoiceNumber: e.target.value }))}
                  className={inputClass('invoiceNumber')}
                />
                {errors.invoiceNumber && <p className="text-xs text-red-500 mt-1">{errors.invoiceNumber}</p>}
              </div>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Cliente</label>
              <select 
                value={formData.customerId}
                onChange={e => setFormData(prev => ({ ...prev, customerId: e.target.value }))}
                className={inputClass('customerId')}
              >
                <option value="">Selecione...</option>
                {getSortedOptions(db.customers, 'customers').map((c: any) => (
                  <option key={c.id} value={c.id}>{c.name}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Motorista</label>
              <select 
                value={formData.driverId}
                onChange={e => setFormData(prev => ({ ...prev, driverId: e.target.value }))}
                className={inputClass('driverId')}
              >
                <option value="">Selecione...</option>
                {getSortedOptions(db.drivers, 'drivers').map((d: any) => (
                  <option key={d.id} value={d.id}>{d.name}</option>
                ))}
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Placa do Veículo</label>
              <select 
                value={formData.vehicleId}
                onChange={e => setFormData(prev => ({ ...prev, vehicleId: e.target.value }))}
                className={inputClass('vehicleId')}
              >
                <option value="">Selecione...</option>
                {getSortedOptions(db.vehicles, 'vehicles').map((v: any) => (
                  <option key={v.id} value={v.id}>{v.plate}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        {/* Right Column: Route and Calculation */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-4">
            <h3 className="font-bold text-slate-800 flex items-center space-x-2">
              <Truck size={18} className="text-blue-500" />
              <span>Rota e Material</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Origem</label>
                <select 
                  value={formData.originId}
                  onChange={e => setFormData(prev => ({ ...prev, originId: e.target.value }))}
                  className={inputClass('originId')}
                >
                  <option value="">Selecione...</option>
                  {getSortedOptions(db.locations, 'locations').map((l: any) => (
                    <option key={l.id} value={l.id}>{l.name}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Destino</label>
                <select 
                  value={formData.destinationId}
                  onChange={e => setFormData(prev => ({ ...prev, destinationId: e.target.value }))}
                  className={inputClass('destinationId')}
                >
                  <option value="">Selecione...</option>
                  {getSortedOptions(db.locations, 'locations').map((l: any) => (
                    <option key={l.id} value={l.id}>{l.name}</option>
                  ))}
                </select>
              </div>
            </div>
            {errors.route && <p className="text-sm font-medium text-red-500 bg-red-50 p-2 rounded-lg">{errors.route}</p>}

            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Material</label>
              <select 
                value={formData.materialId}
                onChange={e => setFormData(prev => ({ ...prev, materialId: e.target.value }))}
                className={inputClass('materialId')}
              >
                <option value="">Selecione...</option>
                {getSortedOptions(db.materials, 'materials').map((m: any) => (
                  <option key={m.id} value={m.id}>{m.name}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="bg-blue-600 p-6 rounded-2xl shadow-lg shadow-blue-100 text-white space-y-4">
            <h3 className="font-bold flex items-center space-x-2">
              <Calculator size={18} />
              <span>Cálculo Automático</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-bold uppercase tracking-wider text-blue-100 mb-1">Quantidade (t)</label>
                <input 
                  type="number" 
                  step="0.01"
                  value={formData.qtyTons}
                  onChange={e => setFormData(prev => ({ ...prev, qtyTons: Number(e.target.value) }))}
                  className="w-full bg-blue-700/50 border border-blue-400 rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-white placeholder-blue-300"
                />
              </div>
              <div>
                <label className="block text-xs font-bold uppercase tracking-wider text-blue-100 mb-1">Valor/Ton (R$)</label>
                <input 
                  type="number" 
                  readOnly
                  value={formData.pricePerTon}
                  className="w-full bg-blue-700/50 border border-blue-400/50 rounded-xl px-4 py-3 outline-none cursor-not-allowed text-blue-200"
                />
              </div>
            </div>

            <div className="pt-4 border-t border-blue-500/50">
              <p className="text-xs font-bold uppercase tracking-wider text-blue-200">Total da Viagem</p>
              <p className="text-3xl font-extrabold">R$ {formData.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            </div>
          </div>
        </div>

        <div className="md:col-span-2 flex items-center justify-end space-x-4 pt-4">
          <button 
            type="button" 
            onClick={onCancel}
            className="px-8 py-3 rounded-xl font-bold text-slate-600 hover:bg-slate-100 transition-colors"
          >
            Cancelar
          </button>
          <button 
            type="submit" 
            className="flex items-center space-x-2 bg-blue-600 text-white px-10 py-3 rounded-xl font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 active:scale-95"
          >
            <Save size={20} />
            <span>Salvar Viagem</span>
          </button>
        </div>
      </form>
    </div>
  );
};

