import React, { useState, useEffect } from 'react';
import { Save, X, Info, Calculator, Calendar, Truck } from 'lucide-react';
import { Trip, FreightRate } from '../types';
import { updateRecent } from '../db';

interface NewTripFormProps {
  db: any;
  onSave: (trip: Trip) => void;
  onCancel: () => void;
}

const NewTripForm: React.FC<NewTripFormProps> = ({ db, onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    date: new Date().toISOString().split('T')[0],
    invoiceNumber: '',
    customerId: '',
    driverId: '',
    vehicleId: '',
    originId: '',
    destinationId: '',
    materialId: '',
    qtyTons: 0,
    pricePerTon: 0,
    totalValue: 0
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const getSortedOptions = <T extends { id: string; name?: string; plate?: string }>(
    list: T[], 
    category: string
  ) => {
    const recents = db.recentIds[category] || [];
    return [...list].sort((a, b) => {
      const aRecent = recents.indexOf(a.id);
      const bRecent = recents.indexOf(b.id);
      if (aRecent !== -1 && bRecent !== -1) return aRecent - bRecent;
      if (aRecent !== -1) return -1;
      if (bRecent !== -1) return 1;
      const aName = a.name || a.plate || '';
      const bName = b.name || b.plate || '';
      return aName.localeCompare(bName);
    });
  };

  useEffect(() => {
    if (formData.originId && formData.destinationId) {
      const rate = db.freightRates.find(
        (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
      );
      if (rate) {
        setFormData(prev => ({ ...prev, pricePerTon: rate.pricePerTon }));
      }
    }
  }, [formData.originId, formData.destinationId, db.freightRates]);

  useEffect(() => {
    setFormData(prev => ({ 
      ...prev, 
      totalValue: Number((prev.qtyTons * prev.pricePerTon).toFixed(2)) 
    }));
  }, [formData.qtyTons, formData.pricePerTon]);

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.invoiceNumber) newErrors.invoiceNumber = 'Campo obrigatório';
    if (db.trips.some((t: Trip) => t.invoiceNumber === formData.invoiceNumber)) {
      newErrors.invoiceNumber = 'Nota fiscal já cadastrada';
    }
    if (!formData.customerId) newErrors.customerId = 'Selecione o cliente';
    if (!formData.driverId) newErrors.driverId = 'Selecione o motorista';
    if (!formData.vehicleId) newErrors.vehicleId = 'Selecione o veículo';
    if (!formData.originId) newErrors.originId = 'Selecione a origem';
    if (!formData.destinationId) newErrors.destinationId = 'Selecione o destino';
    if (formData.qtyTons <= 0) newErrors.qtyTons = 'Deve ser maior que zero';

    const routeExists = db.freightRates.some(
      (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
    );
    if (!routeExists && formData.originId && formData.destinationId) {
      newErrors.route = 'Rota não cadastrada na Tabela de Fretes';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    updateRecent('customers', formData.customerId);
    updateRecent('drivers', formData.driverId);
    updateRecent('vehicles', formData.vehicleId);

    const newTrip: Trip = {
      ...formData,
      id: crypto.randomUUID(),
      createdAt: Date.now()
    };
    onSave(newTrip);
  };

  const inputClass = (field: string, isSelect: boolean = false) => `
    w-full px-4 py-4 rounded-xl border outline-none transition-all
    bg-slate-900 text-white placeholder-slate-400 font-bold text-base
    ${isSelect ? 'dark-select' : ''}
    ${errors[field] ? 'border-red-500 ring-2 ring-red-500/20 shadow-[0_0_0_1px_rgba(239,68,68,0.5)]' : 'border-slate-700 focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500'}
  `;

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight">Novo Lançamento de Viagem</h2>
        <button onClick={onCancel} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
          <X size={28} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Left Column: Core Details */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-50 pb-3">
              <Info size={18} className="text-blue-500" />
              <span>Dados Principais</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider">Data</label>
                <div className="relative">
                  <Calendar className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none" size={18} />
                  <input 
                    type="date" 
                    value={formData.date}
                    onChange={e => setFormData(prev => ({ ...prev, date: e.target.value }))}
                    className={inputClass('date')}
                  />
                </div>
              </div>
              <div className="space-y-1.5">
                <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider">Nota Fiscal</label>
                <input 
                  type="text" 
                  placeholder="Ex: 12345"
                  value={formData.invoiceNumber}
                  onChange={e => setFormData(prev => ({ ...prev, invoiceNumber: e.target.value }))}
                  className={inputClass('invoiceNumber')}
                />
                {errors.invoiceNumber && <p className="text-xs text-red-500 font-bold">{errors.invoiceNumber}</p>}
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider">Cliente</label>
              <select 
                value={formData.customerId}
                onChange={e => setFormData(prev => ({ ...prev, customerId: e.target.value }))}
                className={inputClass('customerId', true)}
              >
                <option value="" className="bg-slate-900">Selecione o Cliente</option>
                {getSortedOptions(db.customers, 'customers').map((c: any) => (
                  <option key={c.id} value={c.id} className="bg-slate-900">{c.name}</option>
                ))}
              </select>
              {errors.customerId && <p className="text-xs text-red-500 font-bold">{errors.customerId}</p>}
            </div>

            <div className="space-y-1.5">
              <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider">Motorista</label>
              <select 
                value={formData.driverId}
                onChange={e => setFormData(prev => ({ ...prev, driverId: e.target.value }))}
                className={inputClass('driverId', true)}
              >
                <option value="" className="bg-slate-900">Selecione o Motorista</option>
                {getSortedOptions(db.drivers, 'drivers').map((d: any) => (
                  <option key={d.id} value={d.id} className="bg-slate-900">{d.name}</option>
                ))}
              </select>
              {errors.driverId && <p className="text-xs text-red-500 font-bold">{errors.driverId}</p>}
            </div>

            <div className="space-y-1.5">
              <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider">Veículo (Placa)</label>
              <select 
                value={formData.vehicleId}
                onChange={e => setFormData(prev => ({ ...prev, vehicleId: e.target.value }))}
                className={inputClass('vehicleId', true)}
              >
                <option value="" className="bg-slate-900">Selecione a Placa</option>
                {getSortedOptions(db.vehicles, 'vehicles').map((v: any) => (
                  <option key={v.id} value={v.id} className="bg-slate-900">{v.plate}</option>
                ))}
              </select>
              {errors.vehicleId && <p className="text-xs text-red-500 font-bold">{errors.vehicleId}</p>}
            </div>
          </div>
        </div>

        {/* Right Column: Route and Calculation */}
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-50 pb-3">
              <Truck size={18} className="text-blue-500" />
              <span>Rota e Material</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider">Origem</label>
                <select 
                  value={formData.originId}
                  onChange={e => setFormData(prev => ({ ...prev, originId: e.target.value }))}
                  className={inputClass('originId', true)}
                >
                  <option value="" className="bg-slate-900">Selecione...</option>
                  {getSortedOptions(db.locations, 'locations').map((l: any) => (
                    <option key={l.id} value={l.id} className="bg-slate-900">{l.name}</option>
                  ))}
                </select>
              </div>
              <div className="space-y-1.5">
                <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider">Destino</label>
                <select 
                  value={formData.destinationId}
                  onChange={e => setFormData(prev => ({ ...prev, destinationId: e.target.value }))}
                  className={inputClass('destinationId', true)}
                >
                  <option value="" className="bg-slate-900">Selecione...</option>
                  {getSortedOptions(db.locations, 'locations').map((l: any) => (
                    <option key={l.id} value={l.id} className="bg-slate-900">{l.name}</option>
                  ))}
                </select>
              </div>
            </div>
            {errors.route && (
              <div className="bg-red-50 p-4 rounded-xl border border-red-200 flex items-center space-x-2">
                <Info size={18} className="text-red-500" />
                <p className="text-sm font-black text-red-700">{errors.route}</p>
              </div>
            )}

            <div className="space-y-1.5">
              <label className="block text-sm font-bold text-slate-500 uppercase tracking-wider">Material</label>
              <select 
                value={formData.materialId}
                onChange={e => setFormData(prev => ({ ...prev, materialId: e.target.value }))}
                className={inputClass('materialId', true)}
              >
                <option value="" className="bg-slate-900">Selecione o Material</option>
                {getSortedOptions(db.materials, 'materials').map((m: any) => (
                  <option key={m.id} value={m.id} className="bg-slate-900">{m.name}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="bg-blue-600 p-8 rounded-2xl shadow-2xl shadow-blue-200 text-white space-y-6">
            <h3 className="font-bold flex items-center space-x-2 border-b border-white/20 pb-3">
              <Calculator size={18} />
              <span>Cálculo de Frete</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="block text-xs font-black uppercase tracking-widest text-blue-100">Quantidade (t)</label>
                <input 
                  type="number" 
                  step="0.01"
                  value={formData.qtyTons || ''}
                  onChange={e => setFormData(prev => ({ ...prev, qtyTons: Number(e.target.value) }))}
                  className="w-full bg-slate-900 text-white border border-blue-400/30 rounded-xl px-4 py-4 outline-none focus:ring-4 focus:ring-white/20 placeholder-blue-300 shadow-inner font-black text-xl"
                  placeholder="0.00"
                />
              </div>
              <div className="space-y-1.5">
                <label className="block text-xs font-black uppercase tracking-widest text-blue-100">Valor/Ton (R$)</label>
                <div className="relative">
                   <input 
                    type="number" 
                    readOnly
                    value={formData.pricePerTon || ''}
                    className="w-full bg-slate-800 text-slate-300 border border-blue-400/10 rounded-xl px-4 py-4 outline-none cursor-not-allowed shadow-inner font-black text-xl"
                  />
                </div>
              </div>
            </div>

            <div className="pt-4">
              <p className="text-xs font-black uppercase tracking-widest text-blue-200 mb-2">Total Estimado da Viagem</p>
              <div className="bg-black/20 p-6 rounded-2xl border border-white/10 backdrop-blur-md">
                <p className="text-4xl font-black tracking-tight">R$ {formData.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
              </div>
            </div>
          </div>
        </div>

        <div className="md:col-span-2 flex items-center justify-end space-x-4 pt-6 mt-4 border-t border-slate-200">
          <button 
            type="button" 
            onClick={onCancel}
            className="px-8 py-4 rounded-xl font-black text-slate-500 hover:bg-slate-100 hover:text-slate-800 transition-all text-lg"
          >
            Descartar
          </button>
          <button 
            type="submit" 
            className="flex items-center justify-center space-x-3 bg-blue-600 text-white px-14 py-5 rounded-2xl font-black hover:bg-blue-700 transition-all shadow-xl shadow-blue-200 active:scale-95 text-xl"
          >
            <Save size={24} />
            <span>Salvar Viagem</span>
          </button>
        </div>
      </form>
    </div>
  );
};

