import { 
  Customer, Driver, Vehicle, Location, Material, FreightRate, Trip 
} from './types';

const API_URL = 'https://script.google.com/macros/s/AKfycbzk7E2yRlmtn2oz9GZWoLAsv2wCW47KKRkKA6OhGHUydzqhss_F39D9k9f7cpbxvpiJ/exec';

export interface DB {
  customers: Customer[];
  drivers: Driver[];
  vehicles: Vehicle[];
  locations: Location[];
  materials: Material[];
  freightRates: FreightRate[];
  trips: Trip[];
  recentIds: Record<string, string[]>;
}

export const INITIAL_DB: DB = {
  customers: [{ id: '1', name: 'Agro Industrial Silva' }],
  drivers: [{ id: '1', name: 'João Batista' }],
  vehicles: [{ id: '1', plate: 'ABC-1234' }],
  locations: [{ id: '1', name: 'Porto de Santos' }, { id: '2', name: 'Fazenda Boa Vista' }],
  materials: [{ id: '1', name: 'Soja' }],
  freightRates: [{ id: '1', originId: '2', destinationId: '1', pricePerTon: 150 }],
  trips: [],
  recentIds: {}
};

/**
 * Busca os dados da Planilha Google
 */
export const fetchDB = async (): Promise<DB> => {
  try {
    const response = await fetch(API_URL);
    if (!response.ok) throw new Error('Erro ao buscar dados');
    const data = await response.json();
    return data && typeof data === 'object' ? data : INITIAL_DB;
  } catch (error) {
    console.error('Erro de conexão com Sheets, usando backup local:', error);
    const local = localStorage.getItem('logitrans_db_backup');
    return local ? JSON.parse(local) : INITIAL_DB;
  }
};

/**
 * Salva os dados na Planilha Google
 */
export const pushDB = async (db: DB): Promise<boolean> => {
  try {
    // Backup local imediato
    localStorage.setItem('logitrans_db_backup', JSON.stringify(db));

    const response = await fetch(API_URL, {
      method: 'POST',
      mode: 'no-cors', // Apps Script Web Apps geralmente requerem no-cors para POST simples
      cache: 'no-cache',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(db)
    });
    return true;
  } catch (error) {
    console.error('Erro ao sincronizar com Sheets:', error);
    return false;
  }
};

export const updateRecent = (db: DB, category: string, id: string): DB => {
  const recents = db.recentIds[category] || [];
  const filtered = recents.filter(rid => rid !== id);
  const newRecents = [id, ...filtered].slice(0, 5);
  return {
    ...db,
    recentIds: { ...db.recentIds, [category]: newRecents }
  };
};

import React, { useState, useEffect } from 'react';
import { 
  Truck, 
  History, 
  Settings, 
  Table as TableIcon, 
  Plus, 
  Menu, 
  X, 
  BarChart3,
  CloudLightning,
  RefreshCw
} from 'lucide-react';
