import { 
  Customer, Driver, Vehicle, Location, Material, FreightRate, Trip 
} from './types';

const API_URL = 'https://script.google.com/macros/s/AKfycbzk7E2yRlmtn2oz9GZWoLAsv2wCW47KKRkKA6OhGHUydzqhss_F39D9k9f7cpbxvpiJ/exec';

export interface DB {
  customers: Customer[];
  drivers: Driver[];
  vehicles: Vehicle[];
  locations: Location[];
  materials: Material[];
  freightRates: FreightRate[];
  trips: Trip[];
  recentIds: Record<string, string[]>;
}

export const INITIAL_DB: DB = {
  customers: [],
  drivers: [],
  vehicles: [],
  locations: [],
  materials: [],
  freightRates: [],
  trips: [],
  recentIds: {}
};

// Mapeamento de tradução de chaves (App -> Planilha)
const mapToSheet = (data: any, type: string) => {
  if (type === 'trips') {
    return data.map((t: Trip) => ({
      id: t.id,
      data: t.date,
      nota_fiscal: t.invoiceNumber,
      cliente_id: t.customerId,
      motorista_id: t.driverId,
      veiculo_id: t.vehicleId,
      local_carregamento_id: t.originId,
      local_descarga_id: t.destinationId,
      material_id: t.materialId,
      quantidade_toneladas: t.qtyTons,
      valor_tonelada: t.pricePerTon,
      valor_total: t.totalValue
    }));
  }
  if (type === 'freightRates') {
    return data.map((f: FreightRate) => ({
      id: f.id,
      local_origem_id: f.originId,
      local_destino_id: f.destinationId,
      valor_tonelada: f.pricePerTon
    }));
  }
  if (type === 'vehicles') {
    return data.map((v: Vehicle) => ({ id: v.id, placa: v.plate }));
  }
  return data; // Clientes, Motoristas, Locais e Materiais usam 'id' e 'nome', igual no código
};

// Mapeamento de tradução de chaves (Planilha -> App)
const mapFromSheet = (data: any, type: string) => {
  if (!Array.isArray(data)) return [];

  if (type === 'trips') {
    return data.map((t: any) => ({
      id: t.id,
      date: t.data,
      invoiceNumber: t.nota_fiscal,
      customerId: t.cliente_id,
      driverId: t.motorista_id,
      vehicleId: t.veiculo_id,
      originId: t.local_carregamento_id,
      destinationId: t.local_descarga_id,
      materialId: t.material_id,
      qtyTons: Number(t.quantidade_toneladas || 0),
      pricePerTon: Number(t.valor_tonelada || 0),
      totalValue: Number(t.valor_total || 0),
      createdAt: Date.now()
    }));
  }
  if (type === 'freightRates') {
    return data.map((f: any) => ({
      id: f.id,
      originId: f.local_origem_id,
      destinationId: f.local_destino_id,
      pricePerTon: Number(f.valor_tonelada || 0)
    }));
  }
  if (type === 'vehicles') {
    return data.map((v: any) => ({ id: v.id, plate: v.placa }));
  }
  return data;
};

/**
 * Busca os dados da Planilha Google e converte para o formato do App
 */
export const fetchDB = async (): Promise<DB> => {
  try {
    const response = await fetch(API_URL);
    if (!response.ok) throw new Error('Erro ao buscar dados');
    const rawData = await response.json();

    // Converte snake_case da planilha para camelCase do App
    const db: DB = {
      customers: mapFromSheet(rawData.Clientes, 'customers'),
      drivers: mapFromSheet(rawData.Motoristas, 'drivers'),
      vehicles: mapFromSheet(rawData.Veiculos, 'vehicles'),
      locations: mapFromSheet(rawData.Locais, 'locations'),
      materials: mapFromSheet(rawData.Materiais, 'materials'),
      freightRates: mapFromSheet(rawData.Fretes, 'freightRates'),
      trips: mapFromSheet(rawData.Viagens, 'trips'),
      recentIds: rawData.Metadata?.recentIds || {}
    };

    return db;
  } catch (error) {
    console.error('Erro de conexão com Sheets, usando backup local:', error);
    const local = localStorage.getItem('logitrans_db_backup');
    return local ? JSON.parse(local) : INITIAL_DB;
  }
};

/**
 * Salva os dados na Planilha Google convertendo para snake_case
 */
export const pushDB = async (db: DB): Promise<boolean> => {
  try {
    localStorage.setItem('logitrans_db_backup', JSON.stringify(db));

    // Prepara o objeto com os nomes das abas e colunas das imagens
    const payload = {
      Viagens: mapToSheet(db.trips, 'trips'),
      Clientes: db.customers,
      Motoristas: db.drivers,
      Veiculos: mapToSheet(db.vehicles, 'vehicles'),
      Locais: db.locations,
      Materiais: db.materials,
      Fretes: mapToSheet(db.freightRates, 'freightRates'),
      Metadata: { recentIds: db.recentIds }
    };

    await fetch(API_URL, {
      method: 'POST',
      mode: 'no-cors',
      cache: 'no-cache',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(payload)
    });
    return true;
  } catch (error) {
    console.error('Erro ao sincronizar:', error);
    return false;
  }
};

export const updateRecent = (db: DB, category: string, id: string): DB => {
  const recents = db.recentIds[category] || [];
  const filtered = recents.filter(rid => rid !== id);
  const newRecents = [id, ...filtered].slice(0, 5);
  return {
