### Importante: O Código do Google Apps Script
Para que este mapeamento funcione, seu Script no Google Sheets deve ser capaz de receber esse objeto e distribuir nas abas. Aqui está um exemplo de como deve ser o seu `doPost` no Apps Script para lidar com essas abas:

```javascript
function doPost(e) {
  var data = JSON.parse(e.postData.contents);
  var ss = SpreadsheetApp.getActiveSpreadsheet();

  // Exemplo para a aba Clientes
  updateSheet(ss, "Clientes", data.Clientes);
  updateSheet(ss, "Motoristas", data.Motoristas);
  updateSheet(ss, "Veiculos", data.Veiculos);
  updateSheet(ss, "Locais", data.Locais);
  updateSheet(ss, "Materiais", data.Materiais);
  updateSheet(ss, "Fretes", data.Fretes);
  updateSheet(ss, "Viagens", data.Viagens);

  return ContentService.createTextOutput("Sucesso");
}

function updateSheet(ss, name, rows) {
  var sheet = ss.getSheetByName(name);
  if (!sheet || !rows || rows.length === 0) return;

  var headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
  sheet.getRange(2, 1, sheet.getLastRow() + 1, sheet.getLastColumn()).clearContent();

  var values = rows.map(row => headers.map(h => row[h] || ""));
  sheet.getRange(2, 1, values.length, headers.length).setValues(values);
}
```

