  const recents = db.recentIds[category] || [];
  const filtered = recents.filter(rid => rid !== id);
  const newRecents = [id, ...filtered].slice(0, 5);
  return {
    ...db,
    recentIds: { ...db.recentIds, [category]: newRecents }
  };
};

