import React, { useState, useEffect } from 'react';
import { 
  Truck, 
  History, 
  Settings, 
  Table as TableIcon, 
  Plus, 
  Menu, 
  X, 
  BarChart3,
  RefreshCw,
  AlertTriangle,
  CheckCircle2,
  WifiOff
} from 'lucide-react';
import { ViewState, Trip } from './types';
import { fetchDB, pushDB, INITIAL_DB, DB } from './db';
import Dashboard from './components/Dashboard';
import NewTripForm from './components/NewTripForm';
import TripHistory from './components/TripHistory';
import Registrations from './components/Registrations';
import FreightTable from './components/FreightTable';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('dashboard');
  const [db, setDb] = useState<DB>(INITIAL_DB);
  const [isLoading, setIsLoading] = useState(true);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [globalSearch, setGlobalSearch] = useState('');
  const [editingTrip, setEditingTrip] = useState<Trip | null>(null);

  const loadData = async () => {
    setIsLoading(true);
    setLoadError(null);
    try {
      const data = await fetchDB();
      setDb(data);
    } catch (error: any) {
      console.error("Erro na carga inicial:", error);
      setLoadError(error.message || "Erro desconhecido de conexão");
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const updateDB = async (newDb: DB) => {
    setDb(newDb);
    setIsSyncing(true);
    setSyncStatus('idle');
    const success = await pushDB(newDb);
    setIsSyncing(false);
    setSyncStatus(success ? 'success' : 'error');

    if (success) {
      setTimeout(() => setSyncStatus('idle'), 3000);
    }
  };

  const navigate = (nextView: ViewState) => {
    if (nextView !== 'new_trip') {
      setEditingTrip(null);
    }
    setView(nextView);
    setIsSidebarOpen(false);
  };

  const handleEditTrip = (trip: Trip) => {
    setEditingTrip(trip);
    setView('new_trip');
  };

  const NavItem = ({ icon: Icon, label, target }: { icon: any, label: string, target: ViewState }) => (
    <button
      onClick={() => navigate(target)}
      className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
        view === target 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
          : 'text-slate-600 hover:bg-slate-100'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center text-white space-y-4">
        <RefreshCw size={48} className="animate-spin text-blue-500" />
        <h2 className="text-xl font-black tracking-widest uppercase">Acessando Planilha Google...</h2>
        <p className="text-slate-400">Estabelecendo túnel de dados seguro</p>
      </div>
    );
  }

  if (loadError) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl border border-red-100 max-w-md w-full space-y-6">
          <div className="bg-red-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto text-red-500">
            <WifiOff size={40} />
          </div>
          <div className="space-y-2">
            <h2 className="text-2xl font-black text-slate-900">Falha na Conexão</h2>
            <p className="text-slate-500">Não conseguimos carregar os dados da sua planilha Google.</p>
            <div className="bg-slate-50 p-3 rounded-xl text-xs font-mono text-red-400 break-all border border-red-50">
              Erro: {loadError}
            </div>
          </div>
          <button 
            onClick={loadData}
            className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all flex items-center justify-center space-x-2"
          >
            <RefreshCw size={20} />
            <span>Tentar Novamente</span>
          </button>
          <p className="text-[10px] text-slate-400 uppercase tracking-widest font-bold">
            Verifique se o script está publicado como "Qualquer pessoa"
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sync Status Notifications */}
      <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end space-y-2">
        {isSyncing && (
          <div className="bg-slate-900 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-white/10 animate-pulse">
            <RefreshCw size={18} className="text-blue-400 animate-spin" />
            <span className="text-xs font-black uppercase tracking-widest">Sincronizando...</span>
          </div>
        )}
        {syncStatus === 'success' && (
          <div className="bg-emerald-600 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-emerald-400 animate-in fade-in slide-in-from-right-4">
            <CheckCircle2 size={18} />
            <span className="text-xs font-black uppercase tracking-widest">Salvo no Google</span>
          </div>
        )}
        {syncStatus === 'error' && (
          <div className="bg-red-600 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-red-400 animate-in shake">
            <AlertTriangle size={18} />
            <div className="flex flex-col">
              <span className="text-xs font-black uppercase tracking-widest">Erro ao Salvar</span>
              <span className="text-[10px] opacity-80">Tentando novamente em segundo plano</span>
            </div>
          </div>
        )}
      </div>

      {/* Mobile Header */}
      <header className="md:hidden bg-white border-b px-4 py-3 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center space-x-2">
          <div className="bg-blue-600 p-1.5 rounded-lg text-white">
            <Truck size={20} />
          </div>
          <h1 className="font-bold text-lg text-slate-800">LogiTrans</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-600">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </header>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-200 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-4">
          <div className="hidden md:flex items-center space-x-3 px-2 mb-8 mt-2">
            <div className="bg-blue-600 p-2 rounded-xl text-white">
              <Truck size={24} />
            </div>
            <h1 className="font-extrabold text-xl tracking-tight text-slate-800">LogiTrans</h1>
          </div>

          <nav className="flex-1 space-y-2">
            <NavItem icon={BarChart3} label="Dashboard" target="dashboard" />
            <NavItem icon={Plus} label="Nova Viagem" target="new_trip" />
            <NavItem icon={History} label="Histórico" target="history" />
            <NavItem icon={Settings} label="Cadastros" target="registrations" />
            <NavItem icon={TableIcon} label="Tabela de Fretes" target="freight_table" />
          </nav>

          <div className="pt-4 border-t mt-auto">
            <div className="bg-slate-50 p-3 rounded-lg flex items-center space-x-3">
              <div className="w-8 h-8 rounded-full bg-slate-300 flex items-center justify-center text-xs font-bold text-slate-600 uppercase">
                {syncStatus === 'error' ? '!' : 'OK'}
              </div>
              <div>
                <p className="text-sm font-semibold text-slate-700 leading-none text-[10px] uppercase">Planilha Nuvem</p>
                <p className={`text-[10px] font-bold mt-1 ${syncStatus === 'error' ? 'text-red-500' : 'text-blue-600'}`}>
                  {syncStatus === 'error' ? 'Erro de Sinc' : 'Conectado'}
                </p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-auto">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <Dashboard 
              navigate={navigate} 
              db={db} 
              onSearch={setGlobalSearch} 
            />
          )}
          {view === 'new_trip' && (
            <NewTripForm 
              db={db} 
              initialData={editingTrip || undefined}
              onSave={(savedTrip) => {
                if (editingTrip) {
                  updateDB({ 
                    ...db, 
                    trips: db.trips.map(t => t.id === savedTrip.id ? savedTrip : t) 
                  });
                } else {
                  updateDB({ ...db, trips: [savedTrip, ...db.trips] });
                }
                setEditingTrip(null);
                navigate('history');
              }}
              onCancel={() => {
                setEditingTrip(null);
                navigate('dashboard');
              }}
            />
          )}
          {view === 'history' && (
            <TripHistory 
              db={db} 
              initialSearch={globalSearch} 
              onEdit={handleEditTrip}
              onDelete={(id) => updateDB({ ...db, trips: db.trips.filter(t => t.id !== id) })}
            />
          )}
          {view === 'registrations' && (
            <Registrations db={db} setDb={(updater) => {
              const newDb = updater(db);
              updateDB(newDb);
            }} />
          )}
          {view === 'freight_table' && (
            <FreightTable db={db} setDb={(updater) => {
              const newDb = updater(db);
              updateDB(newDb);
            }} />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Save, X, Info, Calculator, Calendar, Truck } from 'lucide-react';
import { Trip, FreightRate } from '../types';
import { generateId } from '../db';

interface NewTripFormProps {
  db: any;
  initialData?: Trip;
  onSave: (trip: Trip) => void;
  onCancel: () => void;
}

const NewTripForm: React.FC<NewTripFormProps> = ({ db, initialData, onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    date: initialData?.date || new Date().toISOString().split('T')[0],
    invoiceNumber: initialData?.invoiceNumber || '',
    customerId: initialData?.customerId || '',
    driverId: initialData?.driverId || '',
    vehicleId: initialData?.vehicleId || '',
    originId: initialData?.originId || '',
    destinationId: initialData?.destinationId || '',
    materialId: initialData?.materialId || '',
    qtyTons: initialData?.qtyTons || 0,
    pricePerTon: initialData?.pricePerTon || 0,
    totalValue: initialData?.totalValue || 0
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const getSortedOptions = <T extends { id: string; name?: string; plate?: string }>(
    list: T[], 
    category: string
  ) => {
    const recents = db.recentIds[category] || [];
    return [...list].sort((a, b) => {
      const aRecent = recents.indexOf(a.id);
      const bRecent = recents.indexOf(b.id);
      if (aRecent !== -1 && bRecent !== -1) return aRecent - bRecent;
      if (aRecent !== -1) return -1;
      if (bRecent !== -1) return 1;
      const aName = a.name || a.plate || '';
      const bName = b.name || b.plate || '';
      return aName.localeCompare(bName);
    });
  };

  useEffect(() => {
    // Só atualiza o preço automaticamente se estiver criando um novo lançamento ou se o destino mudar explicitamente
    // Para edição, preservamos o preço original a menos que o usuário mude a rota
    if (formData.originId && formData.destinationId) {
      const rate = db.freightRates.find(
        (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
      );

      // Se estamos editando e a rota é a mesma do initialData, mantemos o preço que já estava (pode ter sido alterado manualmente antes)
      if (initialData && formData.originId === initialData.originId && formData.destinationId === initialData.destinationId) {
        return;
      }

      if (rate) {
        setFormData(prev => ({ ...prev, pricePerTon: rate.pricePerTon }));
      }
    }
  }, [formData.originId, formData.destinationId, db.freightRates]);

  useEffect(() => {
    setFormData(prev => ({ 
      ...prev, 
      totalValue: Number((prev.qtyTons * prev.pricePerTon).toFixed(2)) 
    }));
  }, [formData.qtyTons, formData.pricePerTon]);

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.invoiceNumber) newErrors.invoiceNumber = 'Campo obrigatório';

    // Verifica se a NF já existe (excluindo a própria NF se estiver em modo edição)
    const nfConflict = db.trips.some((t: Trip) => 
      t.invoiceNumber === formData.invoiceNumber && t.id !== initialData?.id
    );
    if (nfConflict) {
      newErrors.invoiceNumber = 'Nota fiscal já cadastrada';
    }

    if (!formData.customerId) newErrors.customerId = 'Selecione o cliente';
    if (!formData.driverId) newErrors.driverId = 'Selecione o motorista';
    if (!formData.vehicleId) newErrors.vehicleId = 'Selecione o veículo';
    if (!formData.originId) newErrors.originId = 'Selecione a origem';
    if (!formData.destinationId) newErrors.destinationId = 'Selecione o destino';
    if (formData.qtyTons <= 0) newErrors.qtyTons = 'Deve ser maior que zero';

    const routeExists = db.freightRates.some(
      (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
    );
    if (!routeExists && formData.originId && formData.destinationId) {
      newErrors.route = 'Rota não cadastrada na Tabela de Fretes';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    const savedTrip: Trip = {
      ...formData,
      id: initialData?.id || generateId(),
      createdAt: initialData?.createdAt || Date.now()
    };
    onSave(savedTrip);
  };

  const inputClass = (field: string, isSelect: boolean = false) => `
    w-full px-4 py-4 rounded-xl border outline-none transition-all
    bg-slate-900 text-white placeholder-slate-400 font-bold text-base shadow-inner
    ${isSelect ? 'dark-select' : ''}
    ${errors[field] ? 'border-red-500 ring-2 ring-red-500/20' : 'border-slate-700 focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500'}
  `;

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight">
          {initialData ? 'Editar Lançamento' : 'Novo Lançamento'}
        </h2>
        <button onClick={onCancel} className="p-2 text-slate-400 hover:text-slate-600 transition-colors">
          <X size={28} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-50 pb-3">
              <Info size={18} className="text-blue-500" />
              <span>Dados da Operação</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Data</label>
                <input 
                  type="date" 
                  value={formData.date}
                  onChange={e => setFormData(prev => ({ ...prev, date: e.target.value }))}
                  className={inputClass('date')}
                />
              </div>
              <div className="space-y-1.5">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Nota Fiscal</label>
                <input 
                  type="text" 
                  placeholder="000.000"
                  value={formData.invoiceNumber}
                  onChange={e => setFormData(prev => ({ ...prev, invoiceNumber: e.target.value }))}
                  className={inputClass('invoiceNumber')}
                />
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Cliente</label>
              <select 
                value={formData.customerId}
                onChange={e => setFormData(prev => ({ ...prev, customerId: e.target.value }))}
                className={inputClass('customerId', true)}
              >
                <option value="" className="bg-slate-900 text-slate-400">Selecionar Cliente</option>
                {getSortedOptions(db.customers, 'customers').map((c: any) => (
                  <option key={c.id} value={c.id} className="bg-slate-900">{c.name}</option>
                ))}
              </select>
            </div>

            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Motorista</label>
              <select 
                value={formData.driverId}
                onChange={e => setFormData(prev => ({ ...prev, driverId: e.target.value }))}
                className={inputClass('driverId', true)}
              >
                <option value="" className="bg-slate-900 text-slate-400">Selecionar Motorista</option>
                {getSortedOptions(db.drivers, 'drivers').map((d: any) => (
                  <option key={d.id} value={d.id} className="bg-slate-900">{d.name}</option>
                ))}
