      loadData();
    } else {
      setIsLoading(false);
    }
  }, []);

  const updateDB = async (newDb: DB) => {
    setDb(newDb);
    setIsSyncing(true);
    setSyncStatus('idle');
    const success = await pushDB(newDb);
    setIsSyncing(false);
    setSyncStatus(success ? 'success' : 'error');

    if (success) {
      setTimeout(() => setSyncStatus('idle'), 3000);
    }
  };

  const navigate = (nextView: ViewState) => {
    if (nextView !== 'new_trip') {
      setEditingTrip(null);
    }
    setView(nextView);
    setIsSidebarOpen(false);
  };

  const handleEditTrip = (trip: Trip) => {
    setEditingTrip(trip);
    setView('new_trip');
  };

  const logout = () => {
    localStorage.removeItem('logitrans_session');
    window.location.reload();
  };

  const NavItem = ({ icon: Icon, label, target }: { icon: any, label: string, target: ViewState }) => (
    <button
      onClick={() => navigate(target)}
      className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
        view === target 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
          : 'text-slate-600 hover:bg-slate-100'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  // Tela de Login
  if (!isAuthenticated && !isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className={`bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl transition-all duration-300 ${loginError ? 'shake border-4 border-red-500' : ''}`}>
          <div className="text-center mb-10">
            <div className="bg-blue-600 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl shadow-blue-200 rotate-3">
              <Truck size={40} className="text-white" />
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tighter">LogiTrans v2.0</h1>
            <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-2">Acesso Restrito</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Código de Acesso</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                <input 
                  type="password" 
                  autoFocus
                  className="w-full pl-12 pr-4 py-5 bg-slate-100 border-none rounded-2xl outline-none focus:ring-4 focus:ring-blue-500/10 font-black text-2xl tracking-[0.5em] text-center"
                  placeholder="••••"
                  value={passcode}
                  onChange={e => setPasscode(e.target.value)}
                />
              </div>
            </div>

            <button 
              type="submit"
              className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg flex items-center justify-center space-x-3 hover:bg-blue-600 transition-all shadow-xl active:scale-95"
            >
              <span>Entrar no Sistema</span>
              <ArrowRight size={20} />
            </button>
          </form>

          <p className="text-center mt-8 text-slate-300 text-[10px] font-bold uppercase tracking-widest">
            LogiTrans Operational Security
          </p>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center text-white space-y-4">
        <RefreshCw size={48} className="animate-spin text-blue-500" />
        <h2 className="text-xl font-black tracking-widest uppercase">Validando Credenciais...</h2>
        <p className="text-slate-400">Sincronizando com nuvem segura</p>
      </div>
    );
  }

  if (loadError) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl border border-red-100 max-w-md w-full space-y-6">
          <div className="bg-red-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto text-red-500">
            <WifiOff size={40} />
          </div>
          <div className="space-y-2">
            <h2 className="text-2xl font-black text-slate-900">Erro de Segurança</h2>
            <p className="text-slate-500">O servidor recusou a conexão ou a chave de segurança expirou.</p>
            <div className="bg-slate-50 p-3 rounded-xl text-xs font-mono text-red-400 break-all border border-red-50">
              {loadError}
            </div>
          </div>
          <button 
            onClick={loadData}
            className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 hover:bg-blue-700 transition-all flex items-center justify-center space-x-2"
          >
            <RefreshCw size={20} />
            <span>Tentar Novamente</span>
          </button>
          <button onClick={logout} className="text-slate-400 text-xs font-bold uppercase hover:text-slate-600">
            Sair e Fazer Login Novamente
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sync Status Notifications */}
      <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end space-y-2">
        {isSyncing && (
          <div className="bg-slate-900 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-white/10 animate-pulse">
            <RefreshCw size={18} className="text-blue-400 animate-spin" />
            <span className="text-xs font-black uppercase tracking-widest">Sincronizando...</span>
          </div>
        )}
        {syncStatus === 'success' && (
          <div className="bg-emerald-600 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-emerald-400 animate-in fade-in slide-in-from-right-4">
            <CheckCircle2 size={18} />
            <span className="text-xs font-black uppercase tracking-widest">Salvo no Google</span>
          </div>
        )}
        {syncStatus === 'error' && (
          <div className="bg-red-600 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-red-400 animate-in shake">
            <AlertTriangle size={18} />
            <div className="flex flex-col">
              <span className="text-xs font-black uppercase tracking-widest">Erro ao Salvar</span>
              <span className="text-[10px] opacity-80">Tentando novamente em segundo plano</span>
            </div>
          </div>
        )}
      </div>

      {/* Mobile Header */}
      <header className="md:hidden bg-white border-b px-4 py-3 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center space-x-2">
          <div className="bg-blue-600 p-1.5 rounded-lg text-white">
            <Truck size={20} />
          </div>
          <h1 className="font-bold text-lg text-slate-800">LogiTrans</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-600">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </header>

      {/* Sidebar */}
      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-200 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-4">
          <div className="hidden md:flex items-center space-x-3 px-2 mb-8 mt-2">
            <div className="bg-blue-600 p-2 rounded-xl text-white">
              <Truck size={24} />
            </div>
            <h1 className="font-extrabold text-xl tracking-tight text-slate-800">LogiTrans</h1>
          </div>

          <nav className="flex-1 space-y-2">
            <NavItem icon={BarChart3} label="Dashboard" target="dashboard" />
            <NavItem icon={Plus} label="Nova Viagem" target="new_trip" />
            <NavItem icon={History} label="Histórico" target="history" />
            <NavItem icon={Settings} label="Cadastros" target="registrations" />
            <NavItem icon={TableIcon} label="Tabela de Fretes" target="freight_table" />
          </nav>

          <div className="pt-4 border-t mt-auto">
             <button 
              onClick={logout}
              className="w-full flex items-center space-x-3 px-4 py-3 rounded-lg text-red-500 hover:bg-red-50 transition-colors mb-4"
            >
              <X size={20} />
              <span className="font-bold text-xs uppercase tracking-widest">Sair do Sistema</span>
            </button>
            <div className="bg-slate-50 p-3 rounded-lg flex items-center space-x-3">
              <div className="w-8 h-8 rounded-full bg-emerald-100 flex items-center justify-center text-[10px] font-black text-emerald-600 uppercase">
                SH
              </div>
              <div>
                <p className="text-sm font-semibold text-slate-700 leading-none text-[10px] uppercase">Planilha Protegida</p>
                <p className="text-[10px] font-bold mt-1 text-emerald-600 uppercase">
                  Conexão Cripto
                </p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 overflow-auto">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {view === 'dashboard' && (
            <Dashboard 
              navigate={navigate} 
              db={db} 
              onSearch={setGlobalSearch} 
            />
          )}
          {view === 'new_trip' && (
            <NewTripForm 
              db={db} 
              initialData={editingTrip || undefined}
              onSave={(savedTrip) => {
                if (editingTrip) {
                  updateDB({ 
                    ...db, 
                    trips: db.trips.map(t => t.id === savedTrip.id ? savedTrip : t) 
                  });
                } else {
                  updateDB({ ...db, trips: [savedTrip, ...db.trips] });
                }
                setEditingTrip(null);
                navigate('history');
              }}
              onCancel={() => {
                setEditingTrip(null);
                navigate('dashboard');
              }}
            />
          )}
          {view === 'history' && (
            <TripHistory 
              db={db} 
              initialSearch={globalSearch} 
              onEdit={handleEditTrip}
              onDelete={(id) => updateDB({ ...db, trips: db.trips.filter(t => t.id !== id) })}
            />
          )}
          {view === 'registrations' && (
            <Registrations db={db} setDb={(updater) => {
              const newDb = updater(db);
              updateDB(newDb);
            }} />
          )}
          {view === 'freight_table' && (
            <FreightTable db={db} setDb={(updater) => {
              const newDb = updater(db);
              updateDB(newDb);
            }} />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

