### Lembrete Importante (Pulo do Gato):

Para que esta segurança funcione, você **DEVE** atualizar o código do seu Google Apps Script (onde está sua planilha) para incluir a verificação do token. Sem isso, a planilha continuará aceitando qualquer requisição externa.

Adicione esta trava no topo do seu arquivo `.gs` no Google:

```javascript
const SECURITY_TOKEN = "LOGITRANS_SECRET_2025";

function doGet(e) {
  if (e.parameter.token !== SECURITY_TOKEN) {
    return ContentService.createTextOutput(JSON.stringify({error: "Unauthorized"})).setMimeType(ContentService.MimeType.JSON);
  }
  // ... resto do seu doGet ...
}

function doPost(e) {
  var data = JSON.parse(e.postData.contents);
  if (data.token !== SECURITY_TOKEN) {
    return ContentService.createTextOutput(JSON.stringify({error: "Unauthorized"})).setMimeType(ContentService.MimeType.JSON);
  }
  // ... resto do seu doPost ...
}
```

O código de acesso ao aplicativo agora é **`2025`**. Qualquer pessoa que não saiba este código ou que tente acessar os dados diretamente pela URL da planilha sem o token secreto será bloqueada.

Para garantir que a segurança funcione, você deve substituir **todo o conteúdo** do seu arquivo no Google Apps Script pelo código abaixo. 

Este código é completo e já está preparado para:
1.  **Validar o Token:** Ele só libera os dados se o App enviar a chave `LOGITRANS_SECRET_2025`.
2.  **Gerenciar as Abas:** Ele lê e grava automaticamente nas abas "Clientes", "Motoristas", "Veiculos", "Locais", "Materiais", "Fretes", "Viagens" e "Metadata".

### 1. Copie o código abaixo:

```javascript
/**
 * LOGITRANS - BACKEND GOOGLE SHEETS v2.5
 * Instruções:
 * 1. Cole este código no Editor de Script da sua Planilha.
 * 2. Certifique-se de que sua planilha tenha as abas com os nomes exatos:
 *    "Clientes", "Motoristas", "Veiculos", "Locais", "Materiais", "Fretes", "Viagens", "Metadata"
 * 3. Clique em "Implantar" -> "Nova Implantação" -> Tipo: "App da Web".
 * 4. Quem pode acessar: "Qualquer pessoa".
 */

const SECURITY_TOKEN = "LOGITRANS_SECRET_2025";

// Função para ler dados (GET)
function doGet(e) {
  // TRAVA DE SEGURANÇA
  if (!e.parameter || e.parameter.token !== SECURITY_TOKEN) {
    return createJsonResponse({ error: "Unauthorized", message: "Token de segurança inválido ou ausente." });
  }

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheets = ["Clientes", "Motoristas", "Veiculos", "Locais", "Materiais", "Fretes", "Viagens", "Metadata"];
    const db = {};

    sheets.forEach(sheetName => {
      const sheet = ss.getSheetByName(sheetName);
      if (!sheet) {
        db[sheetName] = [];
        return;
      }

      const data = sheet.getDataRange().getValues();
      const headers = data.shift();

      if (sheetName === "Metadata") {
        // Metadata é tratado como um objeto JSON na primeira célula
        try {
          db[sheetName] = data.length > 0 && data[0][0] ? JSON.parse(data[0][0]) : {};
        } catch(e) {
          db[sheetName] = {};
        }
      } else {
        db[sheetName] = data.map(row => {
          const obj = {};
          headers.forEach((header, i) => obj[header] = row[i]);
          return obj;
        });
      }
    });

    return createJsonResponse(db);
  } catch (err) {
    return createJsonResponse({ error: "Server Error", details: err.toString() });
  }
}

// Função para gravar dados (POST)
function doPost(e) {
  let contents;
  try {
    contents = JSON.parse(e.postData.contents);
  } catch (err) {
    return createJsonResponse({ error: "Invalid JSON" });
  }

  // TRAVA DE SEGURANÇA
  if (!contents || contents.token !== SECURITY_TOKEN) {
    return createJsonResponse({ error: "Unauthorized" });
  }

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheetsToUpdate = ["Clientes", "Motoristas", "Veiculos", "Locais", "Materiais", "Fretes", "Viagens", "Metadata"];

    sheetsToUpdate.forEach(sheetName => {
      let sheet = ss.getSheetByName(sheetName);
      if (!sheet) sheet = ss.insertSheet(sheetName);

      sheet.clear();
      const data = contents[sheetName];

      if (sheetName === "Metadata") {
        sheet.getRange(1, 1).setValue(JSON.stringify(data || {}));
      } else if (data && data.length > 0) {
        const headers = Object.keys(data[0]);
        sheet.appendRow(headers);
        const rows = data.map(item => headers.map(h => item[h]));
        sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
      }
    });

    return createJsonResponse({ success: true });
  } catch (err) {
    return createJsonResponse({ error: "Update Failed", details: err.toString() });
  }
}

// Helper para formatar resposta JSON
function createJsonResponse(data) {
  return ContentService.createTextOutput(JSON.stringify(data))
    .setMimeType(ContentService.MimeType.JSON);
}
```

### 2. Onde substituir?

1.  Abra sua planilha do Google.
2.  Vá em **Extensões** -> **Apps Script**.
3.  **Apague tudo** o que estiver escrito no arquivo (geralmente chamado `Código.gs`).
4.  **Cole o código acima.**
5.  Clique no ícone de **Salvar** (disquete).
6.  Clique no botão azul **Implantar** (canto superior direito).
7.  Escolha **Gerenciar Implantações**.
8.  Clique no **Lápis (Editar)** na implantação ativa.
9.  Em "Versão", selecione **Nova Versão**.
10. Clique em **Implantar**.

### 3. Por que isso é seguro agora?

*   **Acesso Direto Bloqueado:** Se alguém descobrir o link da sua planilha e colar no navegador, verá a mensagem `{"error":"Unauthorized"}`. O acesso só é permitido para quem enviar o código "secreto" que está embutido no seu App.
*   **Controle de Entrada:** O App agora pede a senha `2025` antes de sequer tentar conectar com a planilha.
*   **Chave Invisível:** O `SECURITY_TOKEN` (a chave mestra) não aparece para o usuário comum, ela viaja "escondida" dentro dos pedidos que o App faz para o Google.

