                            <span className="text-slate-300">→</span>
                            <span>{dest?.name}</span>
                          </div>
                          <span className="text-sm font-bold text-red-600 mt-0.5">{vehicle?.plate}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="font-semibold text-slate-700">{trip.qtyTons}t</span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="font-bold text-slate-900">
                          {isAdmin ? `R$ ${trip.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` : '***'}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <div className="flex justify-end space-x-2 opacity-0 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={() => onEdit(trip)}
                            className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                            title="Editar lançamento"
                          >
                            <Edit2 size={18} />
                          </button>
                          {isAdmin && (
                            <button 
                              onClick={() => onDelete(trip.id)}
                              className="p-2 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                              title="Excluir lançamento"
                            >
                              <Trash2 size={18} />
                            </button>
                          )}
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
};

export default TripHistory;

import React, { useState } from 'react';
import { Search, Plus, Edit2, Trash2, X, Check, User, Users, Truck, MapPin, Package } from 'lucide-react';
import { RegistrationType } from '../types';
import { generateId } from '../db';

interface RegistrationsProps {
  db: any;
  setDb: (fn: (prev: any) => any) => void;
}

const Registrations: React.FC<RegistrationsProps> = ({ db, setDb }) => {
  const [activeTab, setActiveTab] = useState<RegistrationType>('customers');
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [newValue, setNewValue] = useState('');

  const tabs = [
    { id: 'customers', label: 'Clientes', icon: Users, list: db.customers },
    { id: 'drivers', label: 'Motoristas', icon: User, list: db.drivers },
    { id: 'vehicles', label: 'Veículos', icon: Truck, list: db.vehicles },
    { id: 'locations', label: 'Locais', icon: MapPin, list: db.locations },
    { id: 'materials', label: 'Materiais', icon: Package, list: db.materials },
  ];

  const currentTab = tabs.find(t => t.id === activeTab)!;

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newValue.trim()) return;

    setDb(prev => ({
      ...prev,
      [activeTab]: [...prev[activeTab], { 
        id: generateId(), 
        [activeTab === 'vehicles' ? 'plate' : 'name']: newValue 
      }]
    }));
    setNewValue('');
  };

  const handleUpdate = (id: string) => {
    setDb(prev => ({
      ...prev,
      [activeTab]: prev[activeTab].map((item: any) => 
        item.id === id ? { ...item, [activeTab === 'vehicles' ? 'plate' : 'name']: editValue } : item
      )
    }));
    setIsEditing(null);
  };

  const handleDelete = (id: string) => {
    if (!confirm('Deseja excluir este registro?')) return;
    setDb(prev => ({
      ...prev,
      [activeTab]: prev[activeTab].filter((item: any) => item.id !== id)
    }));
  };

  const filteredItems = currentTab.list.filter((item: any) => {
    const val = item.name || item.plate || '';
    return val.toLowerCase().includes(searchTerm.toLowerCase());
  });

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header>
        <h2 className="text-2xl font-bold text-slate-900">Cadastros do Sistema</h2>
        <p className="text-slate-500 text-sm">Gerencie as entidades base da sua operação.</p>
      </header>

      <div className="flex overflow-x-auto pb-2 gap-2 scrollbar-hide">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as RegistrationType)}
            className={`flex items-center space-x-2 px-6 py-3 rounded-xl font-bold transition-all whitespace-nowrap ${
              activeTab === tab.id 
                ? 'bg-red-600 text-white shadow-lg shadow-red-100' 
                : 'bg-white text-slate-600 hover:bg-slate-50 border border-slate-100'
            }`}
          >
            <tab.icon size={18} />
            <span>{tab.label}</span>
          </button>
        ))}
      </div>

      <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
        <div className="p-6 border-b border-slate-50 bg-slate-50/30 flex flex-col md:flex-row gap-4">
          <form onSubmit={handleAdd} className="flex-1 flex gap-2">
            <input 
              type="text" 
              placeholder={`Novo ${currentTab.label.slice(0, -1)}...`}
              className="flex-1 px-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white placeholder-slate-400 focus:ring-2 focus:ring-red-500 outline-none shadow-inner transition-all"
              value={newValue}
              onChange={e => setNewValue(e.target.value)}
            />
            <button 
              type="submit"
              className="bg-red-600 text-white px-6 py-3 rounded-xl font-bold hover:bg-red-700 transition-colors flex items-center space-x-2"
            >
              <Plus size={20} />
              <span className="hidden md:inline">Adicionar</span>
            </button>
          </form>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Pesquisar..."
              className="pl-10 pr-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white placeholder-slate-400 focus:ring-2 focus:ring-red-500 outline-none w-full md:w-64 shadow-inner"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="divide-y divide-slate-50">
          {filteredItems.length === 0 ? (
            <div className="p-12 text-center text-slate-400 font-medium">
              Nenhum item encontrado.
            </div>
          ) : (
            filteredItems.map((item: any) => (
              <div key={item.id} className="p-4 flex items-center justify-between hover:bg-slate-50 transition-colors">
                {isEditing === item.id ? (
                  <div className="flex-1 flex gap-2 items-center">
                    <input 
                      autoFocus
                      type="text" 
                      className="flex-1 px-3 py-2 rounded-lg border border-slate-700 bg-slate-900 text-white outline-none focus:ring-2 focus:ring-red-500"
                      value={editValue}
                      onChange={e => setEditValue(e.target.value)}
                    />
                    <button onClick={() => handleUpdate(item.id)} className="p-2 text-emerald-600 hover:bg-emerald-50 rounded-lg">
                      <Check size={20} />
                    </button>
                    <button onClick={() => setIsEditing(null)} className="p-2 text-red-600 hover:bg-red-50 rounded-lg">
                      <X size={20} />
                    </button>
                  </div>
                ) : (
                  <>
                    <div className="flex items-center space-x-3">
                      <div className="p-2 bg-slate-100 rounded-lg text-slate-500">
                        <currentTab.icon size={18} />
                      </div>
                      <span className="font-semibold text-slate-700">{item.name || item.plate}</span>
                    </div>
                    <div className="flex space-x-2">
                      <button 
                        onClick={() => {
                          setIsEditing(item.id);
                          setEditValue(item.name || item.plate);
                        }}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => handleDelete(item.id)}
                        className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </>
                )}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
};

export default Registrations;

import React, { useState } from 'react';
import { Search, Plus, Trash2, MapPin, Calculator, AlertCircle } from 'lucide-react';
import { FreightRate } from '../types';
import { generateId } from '../db';

interface FreightTableProps {
  db: any;
  setDb: (fn: (prev: any) => any) => void;
}

const FreightTable: React.FC<FreightTableProps> = ({ db, setDb }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [newRate, setNewRate] = useState({
    originId: '',
    destinationId: '',
    pricePerTon: 0
  });
  const [error, setError] = useState('');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!newRate.originId || !newRate.destinationId || newRate.pricePerTon <= 0) {
      setError('Preencha todos os campos corretamente.');
      return;
    }

    if (newRate.originId === newRate.destinationId) {
      setError('Origem e destino não podem ser iguais.');
      return;
    }

    const exists = db.freightRates.some(
      (fr: FreightRate) => fr.originId === newRate.originId && fr.destinationId === newRate.destinationId
    );

    if (exists) {
      setError('Esta rota já está cadastrada.');
      return;
    }

    setDb(prev => ({
      ...prev,
      freightRates: [...prev.freightRates, { id: generateId(), ...newRate }]
    }));

    setNewRate({ originId: '', destinationId: '', pricePerTon: 0 });
  };

  const handleDelete = (id: string) => {
    if (!confirm('Deseja excluir esta rota?')) return;
    setDb(prev => ({
      ...prev,
      freightRates: prev.freightRates.filter((fr: FreightRate) => fr.id !== id)
    }));
  };

  const filteredRates = db.freightRates.filter((rate: FreightRate) => {
    const origin = db.locations.find((l: any) => l.id === rate.originId)?.name || '';
    const dest = db.locations.find((l: any) => l.id === rate.destinationId)?.name || '';
    const term = searchTerm.toLowerCase();
    return origin.toLowerCase().includes(term) || dest.toLowerCase().includes(term);
  });

  const inputBaseClass = "w-full px-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white placeholder-slate-400 outline-none focus:ring-2 focus:ring-red-500 transition-all shadow-inner";

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <header>
        <h2 className="text-2xl font-bold text-slate-900">Tabela de Fretes</h2>
        <p className="text-slate-500 text-sm">Configure os valores padrões por rota (tonelada).</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm sticky top-6">
            <h3 className="font-bold text-slate-800 mb-6 flex items-center space-x-2">
              <Plus size={20} className="text-red-600" />
              <span>Nova Rota</span>
            </h3>

            <form onSubmit={handleAdd} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Origem</label>
                <select 
                  className={inputBaseClass + " dark-select"}
                  value={newRate.originId}
                  onChange={e => setNewRate(prev => ({ ...prev, originId: e.target.value }))}
                >
                  <option value="" className="bg-slate-900">Selecione...</option>
                  {db.locations.map((l: any) => <option key={l.id} value={l.id} className="bg-slate-900">{l.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Destino</label>
                <select 
                  className={inputBaseClass + " dark-select"}
                  value={newRate.destinationId}
                  onChange={e => setNewRate(prev => ({ ...prev, destinationId: e.target.value }))}
                >
                  <option value="" className="bg-slate-900">Selecione...</option>
                  {db.locations.map((l: any) => <option key={l.id} value={l.id} className="bg-slate-900">{l.name}</option>)}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-600 mb-1">Valor por Tonelada (R$)</label>
                <div className="relative">
                  <Calculator className="absolute right-3 top-3 text-slate-400" size={18} />
                  <input 
                    type="number" 
                    step="0.01"
                    className={inputBaseClass}
                    value={newRate.pricePerTon || ''}
                    onChange={e => setNewRate(prev => ({ ...prev, pricePerTon: Number(e.target.value) }))}
                    placeholder="Ex: 150.00"
                  />
                </div>
              </div>

              {error && (
                <div className="p-3 bg-red-50 border border-red-100 rounded-xl flex items-center space-x-2 text-red-600 text-sm font-medium">
                  <AlertCircle size={16} />
                  <span>{error}</span>
                </div>
              )}

              <button 
                type="submit"
                className="w-full bg-red-600 text-white py-4 rounded-xl font-bold hover:bg-red-700 transition-all shadow-lg shadow-red-100 active:scale-95"
              >
                Salvar Rota
              </button>
            </form>
          </div>
        </div>

        <div className="lg:col-span-2 space-y-4">
          <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center">
            <Search className="text-slate-400 ml-2" size={20} />
            <input 
              type="text" 
              placeholder="Pesquisar rotas..."
              className="flex-1 px-4 py-2 bg-slate-900 text-white rounded-xl border border-slate-700 outline-none placeholder-slate-400 ml-4 shadow-inner"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden">
            <table className="w-full text-left">
              <thead className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                <tr>
                  <th className="px-6 py-4">Rota de Transporte</th>
                  <th className="px-6 py-4 text-right">Valor / Tonelada</th>
                  <th className="px-6 py-4"></th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-50">
                {filteredRates.length === 0 ? (
                  <tr>
                    <td colSpan={3} className="p-12 text-center text-slate-400 font-medium">Nenhuma rota cadastrada.</td>
                  </tr>
                ) : (
                  filteredRates.map((rate: FreightRate) => {
                    const origin = db.locations.find((l: any) => l.id === rate.originId);
                    const dest = db.locations.find((l: any) => l.id === rate.destinationId);
                    return (
                      <tr key={rate.id} className="hover:bg-slate-50 transition-colors group">
                        <td className="px-6 py-4">
                          <div className="flex flex-col">
                            <span className="font-bold text-slate-700">{origin?.name}</span>
                            <div className="flex items-center space-x-1 text-slate-300">
                              <MapPin size={10} />
                              <span className="text-[10px] uppercase font-black tracking-widest">Até</span>
                            </div>
                            <span className="font-bold text-slate-700">{dest?.name}</span>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <span className="text-lg font-black text-slate-900">
                            R$ {rate.pricePerTon.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                          </span>
                        </td>
                        <td className="px-6 py-4 text-right">
                          <button 
                            onClick={() => handleDelete(rate.id)}
                            className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                          >
                            <Trash2 size={18} />
                          </button>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    </div>
  );
};

export default FreightTable;

