      motorista_id: t.driverId,
      veiculo_id: t.vehicleId,
      local_carregamento_id: t.originId,
      local_descarga_id: t.destinationId,
      material_id: t.materialId,
      quantidade_toneladas: t.qtyTons,
      valor_tonelada: t.pricePerTon,
      valor_total: t.totalValue
    }));
  }
  if (type === 'logins') {
    return data.map((l: Login) => ({
      id: l.id,
      username: l.username,
      role: l.role
    }));
  }
  if (type === 'freightRates') {
    return data.map((f: FreightRate) => ({
      id: f.id,
      local_origem_id: f.originId,
      local_destino_id: f.destinationId,
      valor_tonelada: f.pricePerTon
    }));
  }
  if (type === 'vehicles') {
    return data.map((v: Vehicle) => ({ id: v.id, placa: v.plate }));
  }
  return data.map(item => ({
    id: item.id,
    nome: item.name
  }));
};

const mapFromSheet = (data: any[], type: string) => {
  if (!data || !Array.isArray(data)) return [];

  if (type === 'trips') {
    return data.map((t: any) => ({
      id: String(t.id || ''),
      date: t.data || '',
      invoiceNumber: String(t.nota_fiscal || ''),
      customerId: String(t.cliente_id || ''),
      driverId: String(t.motorista_id || ''),
      vehicleId: String(t.veiculo_id || ''),
      originId: String(t.local_carregamento_id || ''),
      destinationId: String(t.local_descarga_id || ''),
      materialId: String(t.material_id || ''),
      qtyTons: Number(t.quantidade_toneladas || 0),
      pricePerTon: Number(t.valor_tonelada || 0),
      totalValue: Number(t.valor_total || 0),
      createdAt: Date.now()
    }));
  }
  if (type === 'logins') {
    return data.map((l: any) => ({
      id: String(l.id || ''),
      username: String(l.username || ''),
      role: String(l.role || 'driver') as 'admin' | 'driver'
    }));
  }
  if (type === 'freightRates') {
    return data.map((f: any) => ({
      id: String(f.id || ''),
      originId: String(f.local_origem_id || ''),
      destinationId: String(f.local_destino_id || ''),
      pricePerTon: Number(f.valor_tonelada || 0)
    }));
  }
  if (type === 'vehicles') {
    return data.map((v: any) => ({ 
      id: String(v.id || ''), 
      plate: String(v.placa || '') 
    }));
  }
  return data.map(item => ({
    id: String(item.id || ''),
    name: String(item.nome || '')
  }));
};

export const fetchDB = async (retries = 2): Promise<DB> => {
  try {
    const response = await fetch(`${API_URL}?t=${Date.now()}&token=${SECURITY_TOKEN}`, {
      method: 'GET',
      cache: 'no-store',
      redirect: 'follow'
    });

    if (!response.ok) throw new Error(`Status: ${response.status}`);
    const rawData = await response.json();

    if (rawData.error === 'Unauthorized') {
      throw new Error('Chave de segurança inválida.');
    }

    return {
      customers: mapFromSheet(rawData.Clientes, 'customers') as Customer[],
      drivers: mapFromSheet(rawData.Motoristas, 'drivers') as Driver[],
      vehicles: mapFromSheet(rawData.Veiculos, 'vehicles') as Vehicle[],
      locations: mapFromSheet(rawData.Locais, 'locations') as Location[],
      materials: mapFromSheet(rawData.Materiais, 'materials') as Material[],
      freightRates: mapFromSheet(rawData.Fretes, 'freightRates') as FreightRate[],
      trips: mapFromSheet(rawData.Viagens, 'trips') as Trip[],
      logins: mapFromSheet(rawData.Logins, 'logins') as Login[],
      recentIds: rawData.Metadata?.recentIds || {}
    };
  } catch (error) {
    if (retries > 0) return fetchDB(retries - 1);
    throw error;
  }
};

export const pushDB = async (db: DB): Promise<boolean> => {
  try {
    const payload = {
      token: SECURITY_TOKEN,
      Viagens: mapToSheet(db.trips, 'trips'),
      Clientes: mapToSheet(db.customers, 'customers'),
      Motoristas: mapToSheet(db.drivers, 'drivers'),
      Veiculos: mapToSheet(db.vehicles, 'vehicles'),
      Locais: mapToSheet(db.locations, 'locations'),
      Materiais: mapToSheet(db.materials, 'materials'),
      Fretes: mapToSheet(db.freightRates, 'freightRates'),
      Logins: mapToSheet(db.logins, 'logins'),
      Metadata: { recentIds: db.recentIds }
    };

    await fetch(API_URL, {
      method: 'POST',
      mode: 'no-cors',
      cache: 'no-store',
      body: JSON.stringify(payload),
      headers: { 'Content-Type': 'text/plain;charset=utf-8' }
    });

    return true;
  } catch (error) {
    console.error('Erro ao sincronizar:', error);
    return false;
  }
};

import React, { useState, useEffect } from 'react';
import { 
  Truck, 
  History, 
  Settings, 
  Table as TableIcon, 
  Plus, 
  Menu, 
  X, 
  BarChart3,
  RefreshCw,
  AlertTriangle,
  CheckCircle2,
  WifiOff,
  Lock,
  ArrowRight,
  User as UserIcon
} from 'lucide-react';
import { ViewState, Trip, UserSession } from './types';
import { fetchDB, pushDB, INITIAL_DB, DB } from './db';
import Dashboard from './components/Dashboard';
import NewTripForm from './components/NewTripForm';
import TripHistory from './components/TripHistory';
import Registrations from './components/Registrations';
import FreightTable from './components/FreightTable';

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [loginUsername, setLoginUsername] = useState('');
  const [passcode, setPasscode] = useState('');
  const [loginError, setLoginError] = useState(false);

  const [view, setView] = useState<ViewState>('dashboard');
  const [db, setDb] = useState<DB>(INITIAL_DB);
  const [isLoading, setIsLoading] = useState(true);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [globalSearch, setGlobalSearch] = useState('');
  const [editingTrip, setEditingTrip] = useState<Trip | null>(null);

  const loadData = async () => {
    setIsLoading(true);
    setLoadError(null);
    try {
      const data = await fetchDB();
      setDb(data);
      return data;
    } catch (error: any) {
      console.error("Erro na carga inicial:", error);
      setLoadError(error.message || "Erro de conexão segura");
      return null;
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (passcode !== '2025') {
      setLoginError(true);
      setTimeout(() => setLoginError(false), 1500);
      return;
    }

    // Tenta carregar os dados para validar o usuário na tabela Logins
    setIsLoading(true);
    const currentDb = await loadData();
    if (!currentDb) {
      setIsLoading(false);
      return;
    }

    // Validação especial para Admin fixo ou na tabela
    if (loginUsername.toLowerCase() === 'admin') {
      const adminSession: UserSession = { username: 'admin', role: 'admin' };
      setSession(adminSession);
      localStorage.setItem('fs_pipa_session', JSON.stringify(adminSession));
    } else {
      // Busca o usuário na tabela de Logins baixada da planilha
      const loginEntry = currentDb.logins.find(l => l.username.toLowerCase() === loginUsername.toLowerCase());

      if (loginEntry) {
        // Se for motorista, tenta encontrar o ID dele na tabela Motoristas pelo nome
        const driverEntry = currentDb.drivers.find(d => d.name.toLowerCase() === loginEntry.username.toLowerCase());

        const userSession: UserSession = { 
          username: loginEntry.username, 
          role: loginEntry.role,
          driverId: driverEntry?.id
        };
        setSession(userSession);
        localStorage.setItem('fs_pipa_session', JSON.stringify(userSession));
      } else {
        // Caso não esteja na tabela Logins, tenta ver se é um motorista cadastrado (fallback)
        const driver = currentDb.drivers.find(d => d.name.toLowerCase() === loginUsername.toLowerCase());
        if (driver) {
          const driverSession: UserSession = { username: driver.name, role: 'driver', driverId: driver.id };
          setSession(driverSession);
          localStorage.setItem('fs_pipa_session', JSON.stringify(driverSession));
        } else {
          setLoginError(true);
          setTimeout(() => setLoginError(false), 1500);
          setIsLoading(false);
        }
      }
    }
  };

  useEffect(() => {
    const savedSession = localStorage.getItem('fs_pipa_session');
    if (savedSession) {
      setSession(JSON.parse(savedSession));
      loadData();
    } else {
      setIsLoading(false);
    }
  }, []);

  const updateDB = async (newDb: DB) => {
    setDb(newDb);
    setIsSyncing(true);
    setSyncStatus('idle');
    const success = await pushDB(newDb);
    setIsSyncing(false);
    setSyncStatus(success ? 'success' : 'error');

    if (success) {
      setTimeout(() => setSyncStatus('idle'), 3000);
    }
  };

  const navigate = (nextView: ViewState) => {
    if (nextView !== 'new_trip') {
      setEditingTrip(null);
    }
    setView(nextView);
    setIsSidebarOpen(false);
  };

  const handleEditTrip = (trip: Trip) => {
    setEditingTrip(trip);
    setView('new_trip');
  };

  const logout = () => {
    localStorage.removeItem('fs_pipa_session');
    window.location.reload();
  };

  const NavItem = ({ icon: Icon, label, target }: { icon: any, label: string, target: ViewState }) => (
    <button
      onClick={() => navigate(target)}
      className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
        view === target 
          ? 'bg-red-600 text-white shadow-lg shadow-red-200' 
          : 'text-slate-600 hover:bg-slate-100'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  if (!session && !isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <style>
          {`
            @keyframes shake {
              0%, 100% { transform: translateX(0); }
              25% { transform: translateX(-10px); }
              75% { transform: translateX(10px); }
            }
            .shake { animation: shake 0.2s ease-in-out 0s 2; }
          `}
        </style>
        <div className={`bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl transition-all duration-300 ${loginError ? 'shake ring-4 ring-red-500/50' : ''}`}>
          <div className="text-center mb-10">
            <div className="bg-red-600 w-20 h-20 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl shadow-red-200 rotate-3">
              <Truck size={40} className="text-white" />
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tighter">Fretes Só Pipa</h1>
            <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-2">Segurança Ativada</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Usuário / Motorista</label>
              <div className="relative">
                <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                <input 
                  type="text" 
                  className="w-full pl-12 pr-4 py-4 bg-slate-100 border-none rounded-2xl outline-none focus:ring-4 focus:ring-red-500/10 font-bold text-lg text-slate-700"
                  placeholder="Nome do motorista ou admin"
                  value={loginUsername}
                  onChange={e => setLoginUsername(e.target.value)}
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Código de Acesso</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={20} />
                <input 
                  type="password" 
                  className="w-full pl-12 pr-4 py-4 bg-slate-100 border-none rounded-2xl outline-none focus:ring-4 focus:ring-red-500/10 font-black text-2xl tracking-[0.5em] text-center"
                  placeholder="••••"
                  value={passcode}
                  onChange={e => setPasscode(e.target.value)}
                />
              </div>
            </div>

            <button 
              type="submit"
              className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg flex items-center justify-center space-x-3 hover:bg-red-600 transition-all shadow-xl active:scale-95 mt-4"
            >
              <span>Acessar Painel</span>
              <ArrowRight size={20} />
            </button>
          </form>
          <p className="text-center mt-8 text-slate-300 text-[10px] font-bold uppercase tracking-widest">
            Acesso restrito a pessoal autorizado
          </p>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center text-white space-y-4">
        <RefreshCw size={48} className="animate-spin text-red-500" />
        <h2 className="text-xl font-black tracking-widest uppercase">Estabelecendo Conexão Segura...</h2>
        <p className="text-slate-400">Verificando tokens e perfis de usuário</p>
      </div>
    );
  }

  if (loadError) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl border border-red-100 max-w-md w-full space-y-6">
          <div className="bg-red-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto text-red-500">
            <WifiOff size={40} />
          </div>
          <div className="space-y-2">
            <h2 className="text-2xl font-black text-slate-900">Erro de Segurança</h2>
            <p className="text-slate-500">Falha na validação com a nuvem ou rede indisponível.</p>
            <div className="bg-slate-50 p-3 rounded-xl text-xs font-mono text-red-400 break-all border border-red-50">
              {loadError}
            </div>
          </div>
          <button onClick={loadData} className="w-full bg-red-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-red-100 hover:bg-red-700 flex items-center justify-center space-x-2">
            <RefreshCw size={20} />
            <span>Reconectar</span>
          </button>
          <button onClick={logout} className="text-slate-400 text-xs font-bold uppercase hover:text-slate-600 underline">
            Sair e relogar
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end space-y-2">
        {isSyncing && (
          <div className="bg-slate-900 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-white/10 animate-pulse">
            <RefreshCw size={18} className="text-red-400 animate-spin" />
            <span className="text-xs font-black uppercase tracking-widest">Protegido...</span>
          </div>
        )}
        {syncStatus === 'success' && (
          <div className="bg-emerald-600 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-emerald-400 animate-in fade-in slide-in-from-right-4">
            <CheckCircle2 size={18} />
            <span className="text-xs font-black uppercase tracking-widest">Nuvem Atualizada</span>
          </div>
        )}
        {syncStatus === 'error' && (
          <div className="bg-red-600 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-red-400 animate-in shake">
            <AlertTriangle size={18} />
            <div className="flex flex-col">
              <span className="text-xs font-black uppercase tracking-widest">Falha de Envio</span>
              <span className="text-[10px] opacity-80 uppercase tracking-tight">Verifique sua conexão</span>
            </div>
          </div>
        )}
      </div>

      <header className="md:hidden bg-white border-b px-4 py-3 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center space-x-2">
          <div className="bg-red-600 p-1.5 rounded-lg text-white">
            <Truck size={20} />
          </div>
          <h1 className="font-bold text-lg text-slate-800">Fretes Só Pipa</h1>
        </div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-600">
          {isSidebarOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </header>

      <aside className={`
        fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-200 ease-in-out md:relative md:translate-x-0
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
      `}>
        <div className="h-full flex flex-col p-4">
          <div className="hidden md:flex items-center space-x-3 px-2 mb-8 mt-2">
            <div className="bg-red-600 p-2 rounded-xl text-white">
              <Truck size={24} />
            </div>
            <h1 className="font-extrabold text-xl tracking-tight text-slate-800">Fretes Só Pipa</h1>
          </div>

          <nav className="flex-1 space-y-2">
            <NavItem icon={BarChart3} label="Dashboard" target="dashboard" />
            <NavItem icon={Plus} label="Nova Viagem" target="new_trip" />
            <NavItem icon={History} label="Histórico" target="history" />
            <NavItem icon={Settings} label="Cadastros" target="registrations" />
            {session?.role === 'admin' && (
              <NavItem icon={TableIcon} label="Tabela de Fretes" target="freight_table" />
            )}
          </nav>

          <div className="pt-4 border-t mt-auto">
            <button 
              onClick={logout}
              className="w-full flex items-center space-x-3 px-4 py-3 rounded-lg text-red-500 hover:bg-red-50 transition-colors mb-4"
            >
              <X size={20} />
              <span className="font-bold text-xs uppercase tracking-widest">Sair do Sistema</span>
            </button>
            <div className="bg-slate-50 p-3 rounded-lg flex items-center space-x-3">
              <div className="w-8 h-8 rounded-full bg-red-100 flex items-center justify-center text-[10px] font-black text-red-600 uppercase">
                {session?.role === 'admin' ? 'ADM' : 'DRV'}
              </div>
              <div>
                <p className="text-sm font-semibold text-slate-700 leading-none text-[10px] uppercase truncate max-w-[140px]">{session?.username}</p>
                <p className="text-[10px] font-bold mt-1 text-red-600 uppercase">
                  Conexão Blindada
                </p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-auto">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {view === 'dashboard' && <Dashboard navigate={navigate} db={db} onSearch={setGlobalSearch} user={session!} />}
          {view === 'new_trip' && (
            <NewTripForm 
              db={db} 
              user={session!}
              initialData={editingTrip || undefined}
              onSave={(savedTrip) => {
                if (editingTrip) {
                  updateDB({ ...db, trips: db.trips.map(t => t.id === savedTrip.id ? savedTrip : t) });
                } else {
                  updateDB({ ...db, trips: [savedTrip, ...db.trips] });
                }
                setEditingTrip(null);
                navigate('history');
              }}
              onCancel={() => { setEditingTrip(null); navigate('dashboard'); }}
            />
          )}
          {view === 'history' && (
            <TripHistory 
              db={db} 
              user={session!}
              initialSearch={globalSearch} 
              onEdit={handleEditTrip}
              onDelete={(id) => updateDB({ ...db, trips: db.trips.filter(t => t.id !== id) })}
            />
          )}
          {view === 'registrations' && <Registrations db={db} setDb={(updater) => updateDB(updater(db))} />}
          {view === 'freight_table' && session?.role === 'admin' && (
            <FreightTable db={db} setDb={(updater) => updateDB(updater(db))} />
          )}
        </div>
      </main>
    </div>
  );
};

