    };
  };

  const processImageBase64 = async (base64Data: string, mimeType: string) => {
    setIsScanning(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: "Extraia os seguintes campos desta Nota Fiscal (DANFE): data_emissao (formato YYYY-MM-DD), numero_nota (apenas dígitos), peso_bruto_toneladas (número decimal, procure por 'Peso Bruto'). Se não encontrar peso bruto em toneladas, converta de KG se necessário. Retorne apenas JSON puro." }
          ]
        },
        config: { responseMimeType: "application/json" }
      });

      const result = JSON.parse(response.text || '{}');
      setExtractedData(result);
      setShowConfirmModal(true);
    } catch (error) {
      console.error("Erro na leitura da IA:", error);
      alert("Não foi possível extrair dados desta imagem. Tente uma foto mais nítida.");
    } finally {
      setIsScanning(false);
    }
  };

  const confirmExtractedData = () => {
    if (extractedData) {
      setFormData(prev => ({
        ...prev,
        date: extractedData.data_emissao || prev.date,
        invoiceNumber: extractedData.numero_nota || prev.invoiceNumber,
        qtyTons: Number(extractedData.peso_bruto_toneladas) || prev.qtyTons
      }));
    }
    setShowConfirmModal(false);
  };

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.invoiceNumber) newErrors.invoiceNumber = 'Campo obrigatório';

    const nfConflict = db.trips.some((t: Trip) => 
      t.invoiceNumber === formData.invoiceNumber && t.id !== initialData?.id
    );
    if (nfConflict) {
      newErrors.invoiceNumber = 'Nota fiscal já cadastrada';
    }

    if (!formData.customerId) newErrors.customerId = 'Selecione o cliente';
    if (!formData.driverId) newErrors.driverId = 'Selecione o motorista';
    if (!formData.vehicleId) newErrors.vehicleId = 'Selecione o veículo';
    if (!formData.originId) newErrors.originId = 'Selecione a origem';
    if (!formData.destinationId) newErrors.destinationId = 'Selecione o destino';
    if (formData.qtyTons <= 0) newErrors.qtyTons = 'Deve ser maior que zero';

    if (isAdmin) {
      const routeExists = db.freightRates.some(
        (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
      );
      if (!routeExists && formData.originId && formData.destinationId) {
        newErrors.route = 'Rota não cadastrada na Tabela de Fretes';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    const savedTrip: Trip = {
      ...formData,
      id: initialData?.id || generateId(),
      createdAt: initialData?.createdAt || Date.now()
    };
    onSave(savedTrip);
  };

  const inputClass = (field: string, isSelect: boolean = false) => `
    w-full px-4 py-4 rounded-xl border outline-none transition-all
    bg-slate-900 text-white placeholder-slate-400 font-bold text-base shadow-inner
    ${isSelect ? 'dark-select' : ''}
    ${errors[field] ? 'border-red-500 ring-2 ring-red-500/20' : 'border-slate-700 focus:ring-4 focus:ring-red-500/20 focus:border-red-500'}
  `;

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight">
          {initialData ? 'Editar Lançamento' : 'Novo Lançamento'}
        </h2>
        <div className="flex items-center space-x-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={onFileChange} 
            accept="image/*" 
            className="hidden" 
          />
          {!initialData && (
            <div className="flex space-x-2">
              <button 
                onClick={handleGalleryClick}
                disabled={isScanning}
                className="flex items-center space-x-2 bg-slate-800 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-all shadow-lg active:scale-95 disabled:opacity-50"
                title="Subir foto da galeria"
              >
                <ImageIcon size={20} />
                <span className="hidden sm:inline">Galeria</span>
              </button>
              <button 
                onClick={startCamera}
                disabled={isScanning}
                className="flex items-center space-x-2 bg-red-600 text-white px-4 py-2 rounded-xl font-bold hover:bg-red-700 transition-all shadow-lg active:scale-95 disabled:opacity-50"
                title="Tirar foto agora"
              >
                {isScanning ? <Loader2 className="animate-spin" size={20} /> : <Camera size={20} />}
                <span>{isScanning ? 'Lendo...' : 'Câmera'}</span>
              </button>
            </div>
          )}
          <button onClick={onCancel} className="p-2 text-slate-400 hover:text-slate-600 transition-colors ml-2">
            <X size={28} />
          </button>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-50 pb-3">
              <Info size={18} className="text-red-500" />
              <span>Dados da Operação</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Data</label>
                <input 
                  type="date" 
                  value={formData.date}
                  onChange={e => setFormData(prev => ({ ...prev, date: e.target.value }))}
                  className={inputClass('date')}
                />
              </div>
              <div className="space-y-1.5">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Nota Fiscal</label>
                <input 
                  type="text" 
                  placeholder="000.000"
                  value={formData.invoiceNumber}
                  onChange={e => setFormData(prev => ({ ...prev, invoiceNumber: e.target.value }))}
                  className={inputClass('invoiceNumber')}
                />
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Cliente</label>
              <select 
                value={formData.customerId}
                onChange={e => setFormData(prev => ({ ...prev, customerId: e.target.value }))}
                className={inputClass('customerId', true)}
              >
                <option value="" className="bg-slate-900 text-slate-400">Selecionar Cliente</option>
                {getSortedOptions(db.customers, 'customers').map((c: any) => (
                  <option key={c.id} value={c.id} className="bg-slate-900">{c.name}</option>
                ))}
              </select>
            </div>

            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Motorista</label>
              <select 
                value={formData.driverId}
                onChange={e => !initialData && !isAdmin ? null : setFormData(prev => ({ ...prev, driverId: e.target.value }))}
                disabled={!isAdmin && !initialData}
                className={inputClass('driverId', true) + ( !isAdmin && !initialData ? " opacity-50 cursor-not-allowed" : "")}
              >
                <option value="" className="bg-slate-900 text-slate-400">Selecionar Motorista</option>
                {getSortedOptions(db.drivers, 'drivers').map((d: any) => (
                  <option key={d.id} value={d.id} className="bg-slate-900">{d.name}</option>
                ))}
              </select>
              {!isAdmin && <p className="text-[10px] text-slate-400 italic">Identificado automaticamente pelo seu login.</p>}
            </div>

            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Veículo</label>
              <select 
                value={formData.vehicleId}
                onChange={e => setFormData(prev => ({ ...prev, vehicleId: e.target.value }))}
                className={inputClass('vehicleId', true)}
              >
                <option value="" className="bg-slate-900 text-slate-400">Selecionar Placa</option>
                {getSortedOptions(db.vehicles, 'vehicles').map((v: any) => (
                  <option key={v.id} value={v.id} className="bg-slate-900">{v.plate}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-50 pb-3">
              <Truck size={18} className="text-red-500" />
              <span>Logística</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Origem</label>
                <select 
                  value={formData.originId}
                  onChange={e => setFormData(prev => ({ ...prev, originId: e.target.value }))}
                  className={inputClass('originId', true)}
                >
                  <option value="" className="bg-slate-900 text-slate-400">Local de Carga</option>
                  {getSortedOptions(db.locations, 'locations').map((l: any) => (
                    <option key={l.id} value={l.id} className="bg-slate-900">{l.name}</option>
                  ))}
                </select>
              </div>
              <div className="space-y-1.5">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Destino</label>
                <select 
                  value={formData.destinationId}
                  onChange={e => setFormData(prev => ({ ...prev, destinationId: e.target.value }))}
                  className={inputClass('destinationId', true)}
                >
                  <option value="" className="bg-slate-900 text-slate-400">Local de Descarga</option>
                  {getSortedOptions(db.locations, 'locations').map((l: any) => (
                    <option key={l.id} value={l.id} className="bg-slate-900">{l.name}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="space-y-1.5">
              <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Material</label>
              <select 
                value={formData.materialId}
                onChange={e => setFormData(prev => ({ ...prev, materialId: e.target.value }))}
                className={inputClass('materialId', true)}
              >
                <option value="" className="bg-slate-900 text-slate-400">Tipo de Carga</option>
                {getSortedOptions(db.materials, 'materials').map((m: any) => (
                  <option key={m.id} value={m.id} className="bg-slate-900">{m.name}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="bg-red-600 p-8 rounded-3xl shadow-2xl shadow-red-200 text-white space-y-6">
            <h3 className="font-black flex items-center space-x-2 border-b border-white/20 pb-3 uppercase tracking-tighter text-sm">
              <Calculator size={16} />
              <span>Resumo do Faturamento</span>
            </h3>

            <div className={`grid ${isAdmin ? 'grid-cols-2' : 'grid-cols-1'} gap-4`}>
              <div className="space-y-1.5">
                <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-red-100">Quantidade (t)</label>
                <input 
                  type="number" 
                  step="0.01"
                  value={formData.qtyTons || ''}
                  onChange={e => setFormData(prev => ({ ...prev, qtyTons: Number(e.target.value) }))}
                  className="w-full bg-slate-900 text-white border border-red-400/30 rounded-2xl px-4 py-4 outline-none focus:ring-4 focus:ring-white/20 placeholder-red-300 shadow-inner font-black text-2xl text-center"
                  placeholder="0.00"
                />
              </div>
              {isAdmin && (
                <div className="space-y-1.5">
                  <label className="block text-[10px] font-black uppercase tracking-[0.2em] text-red-100">Valor/Ton (R$)</label>
                  <input 
                    type="number" 
                    step="0.01"
                    value={formData.pricePerTon || ''}
                    onChange={e => setFormData(prev => ({ ...prev, pricePerTon: Number(e.target.value) }))}
                    className="w-full bg-slate-900 text-white border border-red-400/30 rounded-2xl px-4 py-4 outline-none focus:ring-4 focus:ring-white/20 placeholder-red-300 shadow-inner font-black text-2xl text-center"
                    placeholder="0.00"
                  />
                </div>
              )}
            </div>

            <div className="bg-black/20 p-6 rounded-2xl border border-white/10 backdrop-blur-md">
              <p className="text-[10px] font-black uppercase tracking-widest text-red-200 mb-2">Total Estimado</p>
              <p className="text-4xl font-black tracking-tighter">
                {isAdmin ? `R$ ${formData.totalValue.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}` : '***'}
              </p>
            </div>
          </div>
        </div>

        <div className="md:col-span-2 flex items-center justify-end space-x-4 pt-6 mt-4 border-t border-slate-200">
          <button 
            type="button" 
            onClick={onCancel}
            className="px-8 py-4 rounded-xl font-black text-slate-500 hover:text-red-600 transition-all uppercase text-xs tracking-widest"
          >
            Descartar
          </button>
          <button 
            type="submit" 
            className="flex items-center justify-center space-x-3 bg-red-600 text-white px-14 py-5 rounded-2xl font-black hover:bg-red-700 transition-all shadow-xl shadow-red-200 active:scale-95 text-xl uppercase tracking-tighter"
          >
            <Save size={24} />
            <span>{initialData ? 'Salvar Alterações' : 'Confirmar Lançamento'}</span>
          </button>
        </div>
      </form>

      {/* Camera Modal */}
      {isCameraActive && (
        <div className="fixed inset-0 z-[110] flex flex-col items-center justify-center bg-black/95 animate-in fade-in duration-300">
          <div className="relative w-full h-full max-w-4xl flex flex-col items-center justify-center p-4">
            <button 
              onClick={stopCamera}
              className="absolute top-6 right-6 z-20 bg-white/10 p-3 rounded-full text-white hover:bg-white/20 transition-all"
            >
              <X size={32} />
            </button>

            <div className="relative w-full aspect-[3/4] max-h-[70vh] rounded-[2rem] overflow-hidden border-2 border-white/10 shadow-2xl">
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                className="w-full h-full object-cover"
              />
              <div className="absolute inset-0 pointer-events-none border-[40px] border-black/20">
                <div className="w-full h-full border-2 border-white/30 border-dashed rounded-xl flex items-center justify-center">
                  <p className="text-white/50 font-black text-xs uppercase tracking-[0.3em] rotate-90 sm:rotate-0">Enquadre a Nota Fiscal</p>
                </div>
              </div>
            </div>

            <div className="mt-12 flex items-center space-x-8">
              <button 
                onClick={stopCamera}
                className="bg-white/10 p-4 rounded-full text-white hover:bg-white/20 transition-all"
              >
                <RefreshCcw size={28} />
              </button>
              <button 
                onClick={capturePhoto}
                className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center bg-red-600 shadow-xl active:scale-90 transition-transform"
              >
                <div className="w-14 h-14 rounded-full border-2 border-white/50"></div>
              </button>
              <div className="w-14"></div> {/* Placeholder for balance */}
            </div>

            <p className="mt-6 text-white/40 text-[10px] font-black uppercase tracking-[0.5em]">Scanner Inteligente Só Pipa</p>
          </div>
          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}

      {/* Confirm AI Extraction Modal */}
      {showConfirmModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 bg-slate-900/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white w-full max-w-md rounded-[2.5rem] p-10 shadow-2xl">
            <div className="flex flex-col items-center text-center space-y-4 mb-8">
              <div className="bg-red-100 p-4 rounded-3xl text-red-600">
                <Sparkles size={40} />
              </div>
              <h3 className="text-2xl font-black text-slate-900">IA: Dados Extraídos</h3>
              <p className="text-slate-500 font-medium">Confirme se os dados da nota fiscal estão corretos antes de preencher o formulário.</p>
            </div>

            <div className="space-y-4 bg-slate-50 p-6 rounded-3xl mb-8">
              <div className="flex justify-between items-center pb-3 border-b border-slate-200">
                <span className="text-xs font-black uppercase text-slate-400">Nota Fiscal</span>
                <input 
                  type="text" 
                  className="font-bold text-right bg-transparent outline-none focus:text-red-600"
                  value={extractedData?.numero_nota || ''}
                  onChange={e => setExtractedData({...extractedData, numero_nota: e.target.value})}
                />
              </div>
              <div className="flex justify-between items-center pb-3 border-b border-slate-200">
                <span className="text-xs font-black uppercase text-slate-400">Data Emissão</span>
                <input 
                  type="date" 
                  className="font-bold text-right bg-transparent outline-none focus:text-red-600"
                  value={extractedData?.data_emissao || ''}
                  onChange={e => setExtractedData({...extractedData, data_emissao: e.target.value})}
                />
              </div>
              <div className="flex justify-between items-center">
                <span className="text-xs font-black uppercase text-slate-400">Peso (Toneladas)</span>
                <input 
                  type="number" 
                  step="0.001"
                  className="font-bold text-right bg-transparent outline-none focus:text-red-600"
                  value={extractedData?.peso_bruto_toneladas || ''}
                  onChange={e => setExtractedData({...extractedData, peso_bruto_toneladas: e.target.value})}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setShowConfirmModal(false)}
                className="py-4 rounded-2xl font-black text-slate-400 hover:bg-slate-100 uppercase text-xs tracking-widest"
              >
                Cancelar
              </button>
              <button 
                onClick={confirmExtractedData}
                className="bg-red-600 text-white py-4 rounded-2xl font-black hover:bg-red-700 shadow-xl shadow-red-100 flex items-center justify-center space-x-2"
              >
                <CheckCircle2 size={18} />
                <span>Confirmar</span>
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default NewTripForm;

import React, { useState, useEffect, useRef } from 'react';
import { Save, X, Info, Calculator, Calendar, Truck, Camera, Sparkles, Loader2, CheckCircle2, Image as ImageIcon, RefreshCcw } from 'lucide-react';
import { Trip, FreightRate, UserSession } from '../types';
import { generateId } from '../db';
import { GoogleGenAI } from "@google/genai";

interface NewTripFormProps {
  db: any;
  user: UserSession;
  initialData?: Trip;
  onSave: (trip: Trip) => void;
  onCancel: () => void;
}

const NewTripForm: React.FC<NewTripFormProps> = ({ db, user, initialData, onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    date: initialData?.date || new Date().toISOString().split('T')[0],
    invoiceNumber: initialData?.invoiceNumber || '',
    customerId: initialData?.customerId || '',
    driverId: initialData?.driverId || (user.role === 'driver' ? user.driverId : ''),
    vehicleId: initialData?.vehicleId || '',
    originId: initialData?.originId || '',
    destinationId: initialData?.destinationId || '',
    materialId: initialData?.materialId || '',
    qtyTons: initialData?.qtyTons || 0,
    pricePerTon: initialData?.pricePerTon || 0,
    totalValue: initialData?.totalValue || 0
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isScanning, setIsScanning] = useState(false);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [extractedData, setExtractedData] = useState<any>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isAdmin = user.role === 'admin';

  const getSortedOptions = <T extends { id: string; name?: string; plate?: string }>(
    list: T[], 
    category: string
  ) => {
    const recents = db.recentIds[category] || [];
    return [...list].sort((a, b) => {
      const aRecent = recents.indexOf(a.id);
      const bRecent = recents.indexOf(b.id);
      if (aRecent !== -1 && bRecent !== -1) return aRecent - bRecent;
      if (aRecent !== -1) return -1;
      if (bRecent !== -1) return 1;
      const aName = a.name || a.plate || '';
      const bName = b.name || b.plate || '';
      return aName.localeCompare(bName);
    });
  };

  useEffect(() => {
    if (formData.originId && formData.destinationId) {
      const rate = db.freightRates.find(
        (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
      );

      if (initialData && formData.originId === initialData.originId && formData.destinationId === initialData.destinationId) {
        return;
      }

      if (rate) {
        setFormData(prev => ({ ...prev, pricePerTon: rate.pricePerTon }));
      }
    }
  }, [formData.originId, formData.destinationId, db.freightRates]);

  useEffect(() => {
    setFormData(prev => ({ 
      ...prev, 
      totalValue: Number((prev.qtyTons * prev.pricePerTon).toFixed(2)) 
    }));
  }, [formData.qtyTons, formData.pricePerTon]);

  // CAMERA LOGIC
  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' }, 
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      setIsCameraActive(true);
    } catch (err) {
      console.error("Erro ao acessar câmera:", err);
      alert("Não foi possível acessar a câmera. Verifique as permissões.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraActive(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg');
        const base64 = dataUrl.split(',')[1];
        processImageBase64(base64, 'image/jpeg');
        stopCamera();
      }
    }
  };

  const handleGalleryClick = () => {
    fileInputRef.current?.click();
  };

  const onFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const base64 = (reader.result as string).split(',')[1];
      processImageBase64(base64, file.type);
    };
  };

  const processImageBase64 = async (base64Data: string, mimeType: string) => {
    setIsScanning(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: "Extraia os seguintes campos desta Nota Fiscal (DANFE): data_emissao (formato YYYY-MM-DD), numero_nota (apenas dígitos), peso_liquido_toneladas (número decimal, procure especificamente por 'Peso Líquido'). Se não encontrar peso líquido em toneladas, converta de KG se necessário. Retorne apenas JSON puro." }
          ]
        },
        config: { responseMimeType: "application/json" }
      });

      const result = JSON.parse(response.text || '{}');
      setExtractedData(result);
      setShowConfirmModal(true);
    } catch (error) {
      console.error("Erro na leitura da IA:", error);
      alert("Não foi possível extrair dados desta imagem. Tente uma foto mais nítida.");
    } finally {
      setIsScanning(false);
    }
  };

  const confirmExtractedData = () => {
    if (extractedData) {
      setFormData(prev => ({
        ...prev,
        date: extractedData.data_emissao || prev.date,
        invoiceNumber: extractedData.numero_nota || prev.invoiceNumber,
        qtyTons: Number(extractedData.peso_liquido_toneladas) || prev.qtyTons
      }));
    }
    setShowConfirmModal(false);
  };

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.invoiceNumber) newErrors.invoiceNumber = 'Campo obrigatório';

    const nfConflict = db.trips.some((t: Trip) => 
      t.invoiceNumber === formData.invoiceNumber && t.id !== initialData?.id
    );
    if (nfConflict) {
      newErrors.invoiceNumber = 'Nota fiscal já cadastrada';
    }

    if (!formData.customerId) newErrors.customerId = 'Selecione o cliente';
    if (!formData.driverId) newErrors.driverId = 'Selecione o motorista';
    if (!formData.vehicleId) newErrors.vehicleId = 'Selecione o veículo';
    if (!formData.originId) newErrors.originId = 'Selecione a origem';
    if (!formData.destinationId) newErrors.destinationId = 'Selecione o destino';
    if (formData.qtyTons <= 0) newErrors.qtyTons = 'Deve ser maior que zero';

    if (isAdmin) {
      const routeExists = db.freightRates.some(
        (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
      );
      if (!routeExists && formData.originId && formData.destinationId) {
        newErrors.route = 'Rota não cadastrada na Tabela de Fretes';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    const savedTrip: Trip = {
      ...formData,
      id: initialData?.id || generateId(),
      createdAt: initialData?.createdAt || Date.now()
    };
    onSave(savedTrip);
  };

  const inputClass = (field: string, isSelect: boolean = false) => `
    w-full px-4 py-4 rounded-xl border outline-none transition-all
    bg-slate-900 text-white placeholder-slate-400 font-bold text-base shadow-inner
    ${isSelect ? 'dark-select' : ''}
    ${errors[field] ? 'border-red-500 ring-2 ring-red-500/20' : 'border-slate-700 focus:ring-4 focus:ring-red-500/20 focus:border-red-500'}
  `;

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight">
          {initialData ? 'Editar Lançamento' : 'Novo Lançamento'}
        </h2>
        <div className="flex items-center space-x-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={onFileChange} 
            accept="image/*" 
            className="hidden" 
          />
          {!initialData && (
            <div className="flex space-x-2">
              <button 
                onClick={handleGalleryClick}
                disabled={isScanning}
                className="flex items-center space-x-2 bg-slate-800 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-all shadow-lg active:scale-95 disabled:opacity-50"
                title="Subir foto da galeria"
              >
                <ImageIcon size={20} />
                <span className="hidden sm:inline">Galeria</span>
              </button>
              <button 
                onClick={startCamera}
                disabled={isScanning}
                className="flex items-center space-x-2 bg-red-600 text-white px-4 py-2 rounded-xl font-bold hover:bg-red-700 transition-all shadow-lg active:scale-95 disabled:opacity-50"
                title="Tirar foto agora"
              >
                {isScanning ? <Loader2 className="animate-spin" size={20} /> : <Camera size={20} />}
                <span>{isScanning ? 'Lendo...' : 'Câmera'}</span>
              </button>
            </div>
          )}
          <button onClick={onCancel} className="p-2 text-slate-400 hover:text-slate-600 transition-colors ml-2">
            <X size={28} />
          </button>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-6">
          <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm space-y-6">
            <h3 className="font-bold text-slate-800 flex items-center space-x-2 border-b border-slate-50 pb-3">
              <Info size={18} className="text-red-500" />
              <span>Dados da Operação</span>
            </h3>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-1.5">
                <label className="block text-xs font-black text-slate-400 uppercase tracking-widest">Data</label>
                <input 
                  type="date" 
                  value={formData.date}
                  onChange={e => setFormData(prev => ({ ...prev, date: e.target.value }))}
