      </form>

      {/* Camera Modal */}
      {isCameraActive && (
        <div className="fixed inset-0 z-[110] flex flex-col items-center justify-center bg-black/95 animate-in fade-in duration-300">
          <div className="relative w-full h-full max-w-4xl flex flex-col items-center justify-center p-4">
