                      </div>
                      <div className="flex space-x-2 mt-4 md:mt-0 opacity-100 md:opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => { setIsEditing(item.id); setEditName(item.name || item.plate); setEditUsername(driverLogin?.username || ''); setEditPassword(driverLogin?.password || ''); }} className="flex-1 md:flex-none flex items-center space-x-2 bg-white px-4 py-2.5 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs hover:border-red-600 hover:text-red-600 transition-all shadow-sm"><Edit2 size={14} /><span className="uppercase tracking-widest">Editar</span></button>
                        <button onClick={() => handleDelete(item.id)} className="p-2.5 bg-white rounded-xl border border-slate-200 text-slate-400 hover:border-red-600 hover:text-red-600 transition-all shadow-sm"><Trash2 size={16} /></button>
                      </div>
                    </>
                  )}
                </div>
              )
            })
          )}
        </div>
      </div>
    </div>
  );
};

export default Registrations;

payload.text:
Para garantir que a exclusão de motoristas e a sincronização de senhas funcionem corretamente, o seu script no Google Sheets precisa ser capaz de **sobrescrever** os dados antigos pelos novos. Se o script apenas "acrescentar" linhas, o que você excluiu no app continuará existindo na planilha e reaparecerá ao atualizar.

Aqui está o código completo e otimizado para o seu `code.gs`. 

### Instruções de Instalação:
1. No seu Google Sheets, vá em **Extensões** > **Apps Script**.
2. Apague todo o código existente e cole o código abaixo.
3. **Importante**: Clique no ícone de disquete (Salvar).
4. Clique em **Implantar** > **Nova Implantação**.
5. Escolha o tipo **App da Web**.
6. Em "Quem pode acessar", selecione **Qualquer pessoa** (isso é necessário para o token de segurança que definimos no código funcionar).
7. Clique em **Implantar** e autorize as permissões.

```javascript
/**
 * SISTEMA FRETES SÓ PIPA - BACKEND v2.5
 * Este script gerencia a sincronização total entre o App e a Planilha.
 * Ele limpa os dados antigos e grava o estado atual, permitindo EXCLUSÕES reais.
 */

var SECURITY_TOKEN = "LOGITRANS_SECRET_2025";

function doGet(e) {
  var token = e.parameter.token;
  if (token !== SECURITY_TOKEN) {
    return ContentService.createTextOutput(JSON.stringify({error: "Unauthorized"})).setMimeType(ContentService.MimeType.JSON);
  }

  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var result = {};
  var sheets = ss.getSheets();

  sheets.forEach(function(sheet) {
    var name = sheet.getName();
    var data = sheet.getDataRange().getValues();

    if (data.length <= 1) {
      result[name] = [];
      return;
    }

    var headers = data[0];
    var rows = data.slice(1);

    result[name] = rows.map(function(row) {
      var obj = {};
      headers.forEach(function(header, i) {
        obj[header] = row[i];
      });
      return obj;
    });
  });

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  var payload;
  try {
    payload = JSON.parse(e.postData.contents);
  } catch (err) {
    return ContentService.createTextOutput("Error: Invalid JSON").setMimeType(ContentService.MimeType.TEXT);
  }

  if (payload.token !== SECURITY_TOKEN) {
    return ContentService.createTextOutput("Error: Unauthorized").setMimeType(ContentService.MimeType.TEXT);
  }

  var ss = SpreadsheetApp.getActiveSpreadsheet();

  // Mapeamento exato entre as chaves do payload (Frontend) e os nomes das Abas (Spreadsheet)
  var sheetsMap = {
    "Viagens": "Viagens",
    "Clientes": "Clientes",
    "Motoristas": "Motoristas",
    "Veiculos": "Veiculos",
    "Locais": "Locais",
    "Materiais": "Materiais",
    "Fretes": "Fretes",
    "Logins": "Logins"
  };

  for (var key in sheetsMap) {
    var sheetName = sheetsMap[key];
    var sheet = ss.getSheetByName(sheetName);

    if (!sheet) continue; // Pula se a aba não existir

    var data = payload[key];
    if (!data || !Array.isArray(data)) continue;

    // 1. LIMPEZA TOTAL (EXCETO CABEÇALHO)
    // Isso garante que o que foi excluído no App suma da planilha
    if (sheet.getLastRow() > 1) {
      sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();
    }

    // 2. GRAVAÇÃO DOS NOVOS DADOS
    if (data.length > 0) {
      var headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];

      var rows = data.map(function(item) {
        return headers.map(function(h) {
          // Garante que valores nulos ou indefinidos virem string vazia
          var val = item[h];
          return (val === undefined || val === null) ? "" : val;
        });
      });

      sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
    }
  }

  return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
}
```

### Por que esta é a solução?
1. **`clearContent()`**: A linha `sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();` é o "segredo". Ela apaga todos os motoristas da planilha antes de escrever a lista vinda do aplicativo. Se o motorista não estiver na lista enviada pelo aplicativo (porque você o excluiu), ele não será escrito de volta.
2. **Mapeamento por Cabeçalho**: O código olha para a primeira linha da sua planilha para saber onde colocar cada informação. Se você mudar a ordem das colunas no Google Sheets, o script continuará funcionando.
3. **Consistência de Senha**: O campo `senha` no `doPost` agora é tratado explicitamente para garantir que o login do motorista seja preservado corretamente.

**Dica**: Verifique se as abas na sua planilha têm exatamente estes nomes: `Viagens`, `Clientes`, `Motoristas`, `Veiculos`, `Locais`, `Materiais`, `Fretes` e `Logins`. O nome deve ser idêntico (maiúsculas e minúsculas).

