### 2. O seu `code.gs` (Apps Script)

Para que o App consiga apagar as linhas fisicamente na planilha, o script do Google **precisa limpar a aba antes de gravar os dados novos**. Se o seu script atual apenas usa `.appendRow()` ou não limpa a área de dados, a exclusão nunca vai funcionar.

Certifique-se de que o seu `code.gs` no Google Sheets esteja exatamente assim:

```javascript
var SECURITY_TOKEN = "LOGITRANS_SECRET_2025";

function doGet(e) {
  var token = e.parameter.token;
  if (token !== SECURITY_TOKEN) return ContentService.createTextOutput(JSON.stringify({error: "Unauthorized"})).setMimeType(ContentService.MimeType.JSON);

  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var result = {};
  var sheets = ss.getSheets();

  sheets.forEach(function(sheet) {
    var name = sheet.getName();
    var data = sheet.getDataRange().getValues();
    if (data.length <= 1) { result[name] = []; return; }
    var headers = data[0];
    var rows = data.slice(1);
    result[name] = rows.map(function(row) {
      var obj = {};
      headers.forEach(function(header, i) { obj[header] = row[i]; });
      return obj;
    });
  });
  return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  var payload = JSON.parse(e.postData.contents);
  if (payload.token !== SECURITY_TOKEN) return ContentService.createTextOutput("Error").setMimeType(ContentService.MimeType.TEXT);

  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheetsMap = {
    "Viagens": "Viagens", "Clientes": "Clientes", "Motoristas": "Motoristas", 
    "Veiculos": "Veiculos", "Locais": "Locais", "Materiais": "Materiais", 
    "Fretes": "Fretes", "Logins": "Logins"
  };

  for (var key in sheetsMap) {
    var sheet = ss.getSheetByName(sheetsMap[key]);
    if (!sheet) continue;
    var data = payload[key];
    if (!data || !Array.isArray(data)) continue;

    // CRUCIAL: Limpa a aba antes de gravar (isso remove o que você excluiu no App)
    if (sheet.getLastRow() > 1) {
      sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();
    }

    if (data.length > 0) {
      var headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
      var rows = data.map(function(item) {
        return headers.map(function(h) { return (item[h] === undefined || item[h] === null) ? "" : item[h]; });
      });
      sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
    }
  }
  return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
}
```

**O que mudou agora?**
- **IDs Casados**: Agora um motorista e seu login têm o mesmo ID. Ao deletar o ID no App, o sistema remove o objeto de ambas as listas internas.
- **Sincronização Atômica**: O App envia a lista de motoristas *sem* o deletado. O Google Script recebe essa lista, limpa a planilha e grava apenas os motoristas que sobraram.
- **Botão de Emergência**: No topo da tela de motoristas, adicionei o botão "Sincronizar IDs de Acesso". Se você já tem motoristas cadastrados com IDs diferentes dos logins, clique nele uma vez para forçar o emparelhamento de todos.

