                  <div className="md:w-48 relative"><Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} /><input type="text" placeholder="Senha (123456)" className="w-full pl-11 pr-4 py-4 rounded-2xl border border-slate-700 bg-slate-900 text-white placeholder-slate-500 focus:ring-4 focus:ring-red-500/20 outline-none shadow-inner font-bold" value={newPassword} onChange={e => setNewPassword(e.target.value)} /></div>
                </>
              )}
              <button type="submit" className="bg-red-600 text-white px-8 py-4 rounded-2xl font-black hover:bg-red-700 transition-all flex items-center justify-center space-x-2 shadow-lg shadow-red-200 active:scale-95 uppercase text-xs tracking-widest"><Plus size={20} /><span>Adicionar</span></button>
            </div>
            <div className="flex items-center space-x-4">
              <div className="h-[1px] flex-1 bg-slate-200"></div>
              <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Filtrar lista..." className="pl-12 pr-6 py-2.5 rounded-full border border-slate-200 bg-white text-slate-600 placeholder-slate-400 focus:ring-4 focus:ring-slate-100 outline-none w-full md:w-80 shadow-sm text-sm font-medium" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
            </div>
          </form>
        </div>

        <div className="divide-y divide-slate-50 max-h-[500px] overflow-y-auto">
          {filteredItems.length === 0 ? (
            <div className="p-20 text-center"><div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300"><currentTab.icon size={40} /></div><p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Lista vazia ou sem resultados</p></div>
          ) : (
            filteredItems.map((item: any) => {
              const driverLogin = activeTab === 'drivers' ? findDriverLogin(item.id, item.name) : null;
              return (
                <div key={item.id} className="p-6 flex flex-col md:flex-row md:items-center justify-between hover:bg-slate-50 transition-colors group">
                  {isEditing === item.id ? (
                    <div className="flex-1 space-y-3">
                      <div className="flex flex-col md:flex-row gap-2">
                        <input autoFocus type="text" className="flex-1 px-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white outline-none focus:ring-4 focus:ring-red-500/20 font-bold" value={editName} onChange={e => setEditName(e.target.value)} />
                        {activeTab === 'drivers' && (
                          <><input type="text" className="md:w-48 px-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white outline-none focus:ring-4 focus:ring-red-500/20 font-bold" value={editUsername} onChange={e => setEditUsername(e.target.value)} placeholder="Usuário" /><input type="text" className="md:w-48 px-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white outline-none focus:ring-4 focus:ring-red-500/20 font-bold" value={editPassword} onChange={e => setEditPassword(e.target.value)} placeholder="Nova Senha" /></>
                        )}
                        <div className="flex space-x-2"><button onClick={() => handleUpdate(item.id)} className="flex-1 md:flex-none p-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700"><Check size={20} className="mx-auto" /></button><button onClick={() => setIsEditing(null)} className="flex-1 md:flex-none p-3 bg-slate-200 text-slate-600 rounded-xl"><X size={20} className="mx-auto" /></button></div>
                      </div>
                    </div>
                  ) : (
                    <>
                      <div className="flex items-center space-x-4">
                        <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-slate-400 shadow-sm border border-slate-100 group-hover:border-red-100 group-hover:text-red-500 transition-all"><currentTab.icon size={24} /></div>
                        <div>
                          <span className="font-black text-slate-800 text-lg tracking-tight">{item.name || item.plate}</span>
                          {activeTab === 'drivers' && (
                            <div className="flex items-center space-x-3 mt-1">
                              <div className="flex items-center space-x-1 text-[10px] font-black uppercase text-slate-400 tracking-tighter"><KeyRound size={12} className="text-red-400" /><span>Acesso: <span className="text-slate-900">{driverLogin?.username || 'Pendente'}</span></span></div>
                              <div className="w-1 h-1 rounded-full bg-slate-200"></div>
                              <div className="flex items-center space-x-1 text-[10px] font-black uppercase text-slate-400 tracking-tighter"><ShieldCheck size={12} className="text-emerald-500" /><span>ID Link: <span className="text-slate-900">{item.id.substring(0,8)}...</span></span></div>
                            </div>
                          )}
                        </div>
                      </div>
                      <div className="flex space-x-2 mt-4 md:mt-0 opacity-100 md:opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => { setIsEditing(item.id); setEditName(item.name || item.plate); setEditUsername(driverLogin?.username || ''); setEditPassword(driverLogin?.password || ''); }} className="flex-1 md:flex-none flex items-center space-x-2 bg-white px-4 py-2.5 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs hover:border-red-600 hover:text-red-600 transition-all shadow-sm"><Edit2 size={14} /><span className="uppercase tracking-widest">Editar</span></button>
                        <button onClick={() => handleDelete(item.id)} className="p-2.5 bg-white rounded-xl border border-slate-200 text-slate-400 hover:border-red-600 hover:text-red-600 transition-all shadow-sm"><Trash2 size={16} /></button>
                      </div>
                    </>
                  )}
                </div>
              )
            })
          )}
        </div>
      </div>
    </div>
  );
};

export default Registrations;

import React, { useState, useEffect } from 'react';
import { 
  Truck, 
  History, 
  Settings, 
  Table as TableIcon, 
  Plus, 
  Menu, 
  X, 
  BarChart3,
  RefreshCw,
  AlertTriangle,
  CheckCircle2,
  WifiOff,
  Lock,
  ArrowRight,
  User as UserIcon,
  ShieldCheck,
  Loader2
} from 'lucide-react';
import { ViewState, Trip, UserSession } from './types';
import { fetchDB, pushDB, INITIAL_DB, DB } from './db';
import Dashboard from './components/Dashboard';
import NewTripForm from './components/NewTripForm';
import TripHistory from './components/TripHistory';
import Registrations from './components/Registrations';
import FreightTable from './components/FreightTable';

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(null);
  const [loginUsername, setLoginUsername] = useState('');
  const [userPassword, setUserPassword] = useState('');
  const [passcode, setPasscode] = useState('');
  const [loginError, setLoginError] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');

  const [view, setView] = useState<ViewState>('dashboard');
  const [db, setDb] = useState<DB>(INITIAL_DB);
  const [isLoading, setIsLoading] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [loadError, setLoadError] = useState<string | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [syncStatus, setSyncStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [globalSearch, setGlobalSearch] = useState('');
  const [editingTrip, setEditingTrip] = useState<Trip | null>(null);

  const loadData = async () => {
    setIsLoading(true);
    setLoadError(null);
    try {
      const data = await fetchDB();
      setDb(data);
      return data;
    } catch (error: any) {
      console.error("Erro na carga inicial:", error);
      setLoadError(error.message || "Erro de conexão segura");
      return null;
    } finally {
      setIsLoading(false);
    }
  };

  const syncToCloud = async (targetDb: DB) => {
    setIsSyncing(true);
    setSyncStatus('idle');
    try {
      const success = await pushDB(targetDb);
      setSyncStatus(success ? 'success' : 'error');
      if (success) {
        setTimeout(() => setSyncStatus('idle'), 3000);
        return true;
      }
      return false;
    } catch (e) {
      setSyncStatus('error');
      return false;
    } finally {
      setIsSyncing(false);
    }
  };

  // Função centralizada e robusta para qualquer alteração no banco (Adição/Edição/Exclusão)
  const updateDB = async (updater: (prev: DB) => DB) => {
    setIsProcessing(true);
    let success = false;

    try {
      // 1. Calculamos o novo estado com base no estado ATUAL (evita race conditions)
      // Usamos uma variável local para garantir que enviamos o dado exato
      let nextDb: DB | null = null;

      setDb(prev => {
        nextDb = updater(prev);
        return nextDb;
      });

      // Aguardamos o ciclo do React ou usamos a variável local capturada
      // Pequeno timeout para garantir que o setDb disparou a atualização da UI
      await new Promise(resolve => setTimeout(resolve, 0));

      if (nextDb) {
        // 2. Sincronizamos a lista COMPLETA (já sem o item excluído) para a nuvem
        success = await syncToCloud(nextDb);
      }

      if (!success) {
        alert("Atenção: Os dados foram alterados no App, mas a sincronização com a nuvem falhou. Verifique sua internet.");
      }
    } catch (err) {
      console.error("Erro fatal no updateDB:", err);
    } finally {
      setIsProcessing(false);
    }
    return success;
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (passcode !== '2025') {
      setErrorMessage('Código de Acesso Geral incorreto.');
      setLoginError(true);
      setTimeout(() => { setLoginError(false); setErrorMessage(''); }, 2000);
      return;
    }

    setIsLoading(true);
    const currentDb = await loadData();

    if (loginUsername.toLowerCase() === 'admin' && userPassword === '2025') {
      const adminSession: UserSession = { username: 'admin', role: 'admin' };
      setSession(adminSession);
      localStorage.setItem('fs_pipa_session', JSON.stringify(adminSession));
      return;
    }

    if (!currentDb) {
      setIsLoading(false);
      setErrorMessage('Erro ao validar na nuvem. Tente admin/2025.');
      return;
    }

    let foundLogin = currentDb.logins.find(l => l.username.toLowerCase() === loginUsername.toLowerCase());

    if (foundLogin && String(foundLogin.password) === String(userPassword)) {
      const driverEntry = currentDb.drivers.find(d => d.name.toLowerCase() === foundLogin?.username.toLowerCase());

      const userSession: UserSession = { 
        username: foundLogin.username, 
        role: foundLogin.role,
        driverId: driverEntry?.id
      };
      setSession(userSession);
      localStorage.setItem('fs_pipa_session', JSON.stringify(userSession));
    } else {
      setErrorMessage('Usuário ou Senha Pessoal incorretos.');
      setLoginError(true);
      setTimeout(() => { setLoginError(false); setErrorMessage(''); }, 2000);
      setIsLoading(false);
    }
  };

  useEffect(() => {
    const savedSession = localStorage.getItem('fs_pipa_session');
    if (savedSession) {
      const parsedSession = JSON.parse(savedSession);
      setSession(parsedSession);
      loadData();
    } else {
      setIsLoading(false);
    }
  }, []);

  const navigate = (nextView: ViewState) => {
    if (nextView !== 'new_trip') setEditingTrip(null);
    setView(nextView);
    setIsSidebarOpen(false);
  };

  const handleEditTrip = (trip: Trip) => {
    setEditingTrip(trip);
    setView('new_trip');
  };

  const logout = () => {
    localStorage.removeItem('fs_pipa_session');
    window.location.reload();
  };

  const NavItem = ({ icon: Icon, label, target }: { icon: any, label: string, target: ViewState }) => (
    <button
      onClick={() => navigate(target)}
      className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-colors ${
        view === target 
          ? 'bg-red-600 text-white shadow-lg shadow-red-200' 
          : 'text-slate-600 hover:bg-slate-100'
      }`}
    >
      <Icon size={20} />
      <span className="font-medium">{label}</span>
    </button>
  );

  if (!session && !isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6 py-12">
        <style>{`@keyframes shake { 0%, 100% { transform: translateX(0); } 25% { transform: translateX(-10px); } 75% { transform: translateX(10px); } } .shake { animation: shake 0.2s ease-in-out 0s 2; }`}</style>
        <div className={`bg-white w-full max-w-md rounded-[3rem] p-8 md:p-10 shadow-2xl transition-all duration-300 ${loginError ? 'shake ring-4 ring-red-500/50' : ''}`}>
          <div className="text-center mb-8">
            <div className="bg-red-600 w-16 h-16 md:w-20 md:h-20 rounded-3xl flex items-center justify-center mx-auto mb-6 shadow-2xl shadow-red-200 rotate-3">
              <Truck size={36} className="text-white" />
            </div>
            <h1 className="text-3xl font-black text-slate-900 tracking-tighter">Fretes Só Pipa</h1>
            <p className="text-slate-400 font-bold uppercase text-[10px] tracking-[0.3em] mt-2">Segurança Multi-Fator</p>
          </div>
          <form onSubmit={handleLogin} className="space-y-4">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Usuário / Motorista</label>
              <div className="relative">
                <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                <input type="text" className="w-full pl-12 pr-4 py-3.5 bg-slate-100 border-none rounded-2xl outline-none focus:ring-4 focus:ring-red-500/10 font-bold text-slate-700" placeholder="Seu nome de usuário" value={loginUsername} onChange={e => setLoginUsername(e.target.value)} />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Senha Pessoal</label>
              <div className="relative">
                <ShieldCheck className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300" size={18} />
                <input type="password" className="w-full pl-12 pr-4 py-3.5 bg-slate-100 border-none rounded-2xl outline-none focus:ring-4 focus:ring-red-500/10 font-bold text-slate-700" placeholder="••••••••" value={userPassword} onChange={e => setUserPassword(e.target.value)} />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1 text-red-600">Código de Acesso Geral</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-red-400" size={18} />
                <input type="password" className="w-full pl-12 pr-4 py-3.5 bg-red-50 border-2 border-red-100 rounded-2xl outline-none focus:ring-4 focus:ring-red-500/10 font-black text-xl tracking-[0.5em] text-center text-red-600" placeholder="••••" maxLength={4} value={passcode} onChange={e => setPasscode(e.target.value)} />
              </div>
            </div>
            {errorMessage && <p className="text-center text-red-500 text-[10px] font-black uppercase tracking-widest bg-red-50 py-2 rounded-xl border border-red-100">{errorMessage}</p>}
            <button type="submit" className="w-full bg-slate-900 text-white py-4 rounded-2xl font-black text-lg flex items-center justify-center space-x-3 hover:bg-red-600 transition-all shadow-xl active:scale-95 mt-4">
              <span>Entrar no Sistema</span>
              <ArrowRight size={20} />
            </button>
          </form>
          <div className="mt-8 flex items-center justify-center space-x-2 text-slate-300">
            <div className="h-[1px] w-8 bg-slate-200"></div>
            <p className="text-[10px] font-bold uppercase tracking-widest whitespace-nowrap">Ambiente Criptografado</p>
            <div className="h-[1px] w-8 bg-slate-200"></div>
          </div>
        </div>
      </div>
    );
  }

  if (isLoading) {
    return (
      <div className="min-h-screen bg-slate-900 flex flex-col items-center justify-center text-white space-y-4">
        <RefreshCw size={48} className="animate-spin text-red-500" />
        <h2 className="text-xl font-black tracking-widest uppercase">Validando Credenciais...</h2>
        <p className="text-slate-400">Verificando camadas de proteção</p>
      </div>
    );
  }

  if (loadError) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl border border-red-100 max-w-md w-full space-y-6">
          <div className="bg-red-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto text-red-500"><WifiOff size={40} /></div>
          <div className="space-y-2">
            <h2 className="text-2xl font-black text-slate-900">Erro de Segurança</h2>
            <p className="text-slate-500">Falha na validação com a nuvem ou rede indisponível.</p>
            <div className="bg-slate-50 p-3 rounded-xl text-xs font-mono text-red-400 break-all border border-red-50">{loadError}</div>
          </div>
          <button onClick={loadData} className="w-full bg-red-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-red-100 hover:bg-red-700 flex items-center justify-center space-x-2"><RefreshCw size={20} /><span>Reconectar</span></button>
          <button onClick={logout} className="text-slate-400 text-xs font-bold uppercase hover:text-slate-600 underline">Sair e relogar</button>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Overlay de Bloqueio durante exclusão/sincronização */}
      {isProcessing && (
        <div className="fixed inset-0 z-[150] bg-slate-900/60 backdrop-blur-sm flex flex-col items-center justify-center text-white space-y-4">
          <Loader2 size={64} className="text-red-500 animate-spin" />
          <div className="text-center">
            <h2 className="text-2xl font-black uppercase tracking-widest">Sincronizando Banco</h2>
            <p className="text-slate-300 font-bold">Por favor, não feche o aplicativo...</p>
          </div>
        </div>
      )}

      <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end space-y-2">
        {isSyncing && (
          <div className="bg-slate-900 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-white/10 animate-pulse">
            <RefreshCw size={18} className="text-red-400 animate-spin" />
            <span className="text-xs font-black uppercase tracking-widest">Protegido...</span>
          </div>
        )}
        {syncStatus === 'success' && (
          <div className="bg-emerald-600 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-emerald-400 animate-in fade-in slide-in-from-right-4">
            <CheckCircle2 size={18} />
            <span className="text-xs font-black uppercase tracking-widest">Nuvem Atualizada</span>
          </div>
        )}
        {syncStatus === 'error' && (
          <div className="bg-red-600 text-white px-5 py-3 rounded-2xl shadow-2xl flex items-center space-x-3 border border-red-400 animate-in shake">
            <AlertTriangle size={18} />
            <div className="flex flex-col">
              <span className="text-xs font-black uppercase tracking-widest">Falha de Envio</span>
              <span className="text-[10px] opacity-80 uppercase tracking-tight">Verifique sua conexão</span>
            </div>
          </div>
        )}
      </div>

      <header className="md:hidden bg-white border-b px-4 py-3 flex items-center justify-between sticky top-0 z-50">
        <div className="flex items-center space-x-2"><div className="bg-red-600 p-1.5 rounded-lg text-white"><Truck size={20} /></div><h1 className="font-bold text-lg text-slate-800">Fretes Só Pipa</h1></div>
        <button onClick={() => setIsSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-600">{isSidebarOpen ? <X size={24} /> : <Menu size={24} />}</button>
      </header>

      <aside className={`fixed inset-y-0 left-0 z-40 w-64 bg-white border-r transform transition-transform duration-200 ease-in-out md:relative md:translate-x-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col p-4">
          <div className="hidden md:flex items-center space-x-3 px-2 mb-8 mt-2"><div className="bg-red-600 p-2 rounded-xl text-white"><Truck size={24} /></div><h1 className="font-extrabold text-xl tracking-tight text-slate-800">Fretes Só Pipa</h1></div>
          <nav className="flex-1 space-y-2">
            <NavItem icon={BarChart3} label="Dashboard" target="dashboard" />
            <NavItem icon={Plus} label="Nova Viagem" target="new_trip" />
            <NavItem icon={History} label="Histórico" target="history" />
            <NavItem icon={Settings} label="Cadastros" target="registrations" />
            {session?.role === 'admin' && <NavItem icon={TableIcon} label="Tabela de Fretes" target="freight_table" />}
          </nav>
          <div className="pt-4 border-t mt-auto">
            <button onClick={logout} className="w-full flex items-center space-x-3 px-4 py-3 rounded-lg text-red-500 hover:bg-red-50 transition-colors mb-4"><X size={20} /><span className="font-bold text-xs uppercase tracking-widest">Sair do Sistema</span></button>
            <div className="bg-slate-50 p-3 rounded-lg flex items-center space-x-3">
              <div className="w-8 h-8 rounded-full bg-red-100 flex items-center justify-center text-[10px] font-black text-red-600 uppercase">{session?.role === 'admin' ? 'ADM' : 'DRV'}</div>
              <div>
                <p className="text-sm font-semibold text-slate-700 leading-none text-[10px] uppercase truncate max-w-[140px]">{session?.username}</p>
                <p className="text-[10px] font-bold mt-1 text-red-600 uppercase">Conexão Blindada</p>
              </div>
            </div>
          </div>
        </div>
      </aside>

      <main className="flex-1 overflow-auto">
        <div className="p-4 md:p-8 max-w-7xl mx-auto">
          {view === 'dashboard' && <Dashboard navigate={navigate} db={db} onSearch={setGlobalSearch} user={session!} />}
          {view === 'new_trip' && (
            <NewTripForm 
              db={db} 
              user={session!}
              initialData={editingTrip || undefined}
              onSave={async (savedTrip) => {
                await updateDB(prev => ({
                  ...prev,
                  trips: editingTrip 
                    ? prev.trips.map(t => t.id === savedTrip.id ? savedTrip : t)
                    : [savedTrip, ...prev.trips]
                }));
                setEditingTrip(null);
                navigate('history');
              }}
              onCancel={() => { setEditingTrip(null); navigate('dashboard'); }}
            />
          )}
          {view === 'history' && (
            <TripHistory 
              db={db} 
              user={session!}
              initialSearch={globalSearch} 
              onEdit={handleEditTrip}
              onDelete={async (id) => {
                if(confirm("Deseja excluir esta viagem permanentemente do banco de dados?")) {
                  await updateDB(prev => ({ ...prev, trips: prev.trips.filter(t => t.id !== id) }));
                }
              }}
            />
          )}
          {view === 'registrations' && <Registrations db={db} setDb={updateDB} />}
          {view === 'freight_table' && session?.role === 'admin' && (
            <FreightTable db={db} setDb={updateDB} />
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Search, Plus, Edit2, Trash2, X, Check, User, Users, Truck, MapPin, Package, Lock, ShieldCheck, KeyRound, RefreshCcw, AlertTriangle } from 'lucide-react';
import { RegistrationType, Driver, Login } from '../types';
import { generateId } from '../db';

interface RegistrationsProps {
  db: any;
  setDb: (updater: (prev: any) => any) => Promise<boolean>;
}

const Registrations: React.FC<RegistrationsProps> = ({ db, setDb }) => {
  const [activeTab, setActiveTab] = useState<RegistrationType>('customers');
  const [searchTerm, setSearchTerm] = useState('');
  const [isEditing, setIsEditing] = useState<string | null>(null);

  const [newName, setNewName] = useState('');
  const [newUsername, setNewUsername] = useState('');
  const [newPassword, setNewPassword] = useState('');

  const [editName, setEditName] = useState('');
  const [editUsername, setEditUsername] = useState('');
  const [editPassword, setEditPassword] = useState('');

  const tabs = [
    { id: 'customers', label: 'Clientes', icon: Users, list: db.customers },
    { id: 'drivers', label: 'Motoristas', icon: User, list: db.drivers },
    { id: 'vehicles', label: 'Veículos', icon: Truck, list: db.vehicles },
    { id: 'locations', label: 'Locais', icon: MapPin, list: db.locations },
    { id: 'materials', label: 'Materiais', icon: Package, list: db.materials },
  ];

  const currentTab = tabs.find(t => t.id === activeTab)!;

  const normalizeForLogin = (str: string) => {
    if (!str) return "";
    return str.normalize("NFD")
              .replace(/[\u0300-\u036f]/g, "")
              .toLowerCase()
              .trim()
              .replace(/\s/g, '.');
  };

  const findDriverLogin = (driverId: string, driverName: string) => {
    let login = db.logins.find((l: Login) => l.id === driverId);
    if (login) return login;

    const normalizedName = normalizeForLogin(driverName);
    return db.logins.find((l: Login) => 
      l.role === 'driver' && 
      (l.username.toLowerCase() === normalizedName || l.username.toLowerCase() === driverName.toLowerCase().trim())
    );
  };

  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newName.trim()) return;

    const sharedId = generateId();
    const field = activeTab === 'vehicles' ? 'plate' : 'name';
    const cleanName = newName.trim();
    const newItem = { id: sharedId, [field]: cleanName };

    await setDb(prev => {
      const next = { ...prev };
      next[activeTab] = [...prev[activeTab], newItem];

      if (activeTab === 'drivers') {
        const username = (newUsername.trim() || normalizeForLogin(cleanName));
        next.logins = [...prev.logins, {
          id: sharedId,
          username: username,
          password: (newPassword.trim() || '123456'),
          role: 'driver' as const
        }];
      }
      return next;
    });

    setNewName('');
    setNewUsername('');
    setNewPassword('');
  };

  const handleUpdate = async (id: string) => {
    const field = activeTab === 'vehicles' ? 'plate' : 'name';
    const cleanNewName = editName.trim();

    await setDb(prev => {
      const next = { ...prev };
      next[activeTab] = prev[activeTab].map((item: any) => 
        item.id === id ? { ...item, [field]: cleanNewName } : item
      );

      if (activeTab === 'drivers') {
        next.logins = prev.logins.map((l: Login) => {
          if (l.id === id) {
            return { 
              ...l, 
              username: editUsername.trim() || l.username, 
              password: editPassword.trim() || l.password 
            };
          }
          return l;
        });
      }
      return next;
    });

    setIsEditing(null);
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Deseja excluir este registro PERMANENTEMENTE de todos os dispositivos e da planilha?')) return;

    // Dispara a atualização funcional para garantir que usamos a versão mais recente do DB
    await setDb(prev => {
      const next = { ...prev };

      // Filtra o item da aba ativa
      next[activeTab] = (prev[activeTab] as any[]).filter(item => item.id !== id);

      // Se for motorista, removemos o login correspondente para segurança
      if (activeTab === 'drivers') {
        next.logins = prev.logins.filter((l: Login) => {
          if (l.role === 'admin') return true;
          return l.id !== id;
        });
      }

      return next;
    });
  };

  const resetAllLogins = async () => {
    if (!confirm('Isso resetará os acessos com base nos IDs atuais dos motoristas. Continuar?')) return;

    await setDb(prev => {
      const adminLogins = prev.logins.filter((l: Login) => l.role === 'admin');
      const newDriverLogins = prev.drivers.map((driver: Driver) => ({
        id: driver.id,
        username: normalizeForLogin(driver.name),
        password: '123456',
        role: 'driver' as const
      }));

      return {
        ...prev,
        logins: [...adminLogins, ...newDriverLogins]
      };
    });
  };

  const filteredItems = (currentTab.list || []).filter((item: any) => {
    const val = item.name || item.plate || '';
    return val.toLowerCase().includes(searchTerm.toLowerCase());
  });

  return (
    <div className="space-y-6 animate-in fade-in duration-500 pb-10">
      <header className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Gestão de Cadastros</h2>
          <p className="text-slate-500 text-sm font-medium">Controle de base operacional e acessos de motoristas.</p>
        </div>
        {activeTab === 'drivers' && (
          <button onClick={resetAllLogins} className="flex items-center space-x-2 bg-slate-900 text-white px-5 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-red-600 transition-all shadow-lg active:scale-95">
            <RefreshCcw size={14} /><span>Sincronizar IDs de Acesso</span>
          </button>
        )}
      </header>

      <div className="flex overflow-x-auto pb-2 gap-2 scrollbar-hide">
        {tabs.map(tab => (
          <button key={tab.id} onClick={() => { setActiveTab(tab.id as RegistrationType); setIsEditing(null); }} className={`flex items-center space-x-2 px-6 py-4 rounded-2xl font-black transition-all whitespace-nowrap uppercase text-[10px] tracking-widest ${activeTab === tab.id ? 'bg-red-600 text-white shadow-xl shadow-red-200 ring-4 ring-red-500/20' : 'bg-white text-slate-500 hover:bg-slate-50 border border-slate-100 shadow-sm'}`}>
            <tab.icon size={16} /><span>{tab.label}</span>
          </button>
        ))}
      </div>

      <div className="bg-white rounded-[2rem] border border-slate-100 shadow-xl overflow-hidden">
        <div className="p-8 border-b border-slate-50 bg-slate-50/30">
          <form onSubmit={handleAdd} className="space-y-4">
            <div className="flex flex-col md:flex-row gap-3">
              <div className="flex-1">
                <input type="text" placeholder={activeTab === 'vehicles' ? 'Placa (ABC-1234)' : `Nome do ${currentTab.label.slice(0, -1)}...`} className="w-full px-5 py-4 rounded-2xl border border-slate-700 bg-slate-900 text-white placeholder-slate-400 focus:ring-4 focus:ring-red-500/20 outline-none shadow-inner font-bold" value={newName} onChange={e => setNewName(e.target.value)} />
              </div>
              {activeTab === 'drivers' && (
                <>
                  <div className="md:w-48 relative"><User className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} /><input type="text" placeholder="Usuário" className="w-full pl-11 pr-4 py-4 rounded-2xl border border-slate-700 bg-slate-900 text-white placeholder-slate-500 focus:ring-4 focus:ring-red-500/20 outline-none shadow-inner font-bold" value={newUsername} onChange={e => setNewUsername(e.target.value)} /></div>
                  <div className="md:w-48 relative"><Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500" size={18} /><input type="text" placeholder="Senha (123456)" className="w-full pl-11 pr-4 py-4 rounded-2xl border border-slate-700 bg-slate-900 text-white placeholder-slate-500 focus:ring-4 focus:ring-red-500/20 outline-none shadow-inner font-bold" value={newPassword} onChange={e => setNewPassword(e.target.value)} /></div>
                </>
              )}
              <button type="submit" className="bg-red-600 text-white px-8 py-4 rounded-2xl font-black hover:bg-red-700 transition-all flex items-center justify-center space-x-2 shadow-lg shadow-red-200 active:scale-95 uppercase text-xs tracking-widest"><Plus size={20} /><span>Adicionar</span></button>
            </div>
            <div className="flex items-center space-x-4">
              <div className="h-[1px] flex-1 bg-slate-200"></div>
              <div className="relative"><Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} /><input type="text" placeholder="Filtrar lista..." className="pl-12 pr-6 py-2.5 rounded-full border border-slate-200 bg-white text-slate-600 placeholder-slate-400 focus:ring-4 focus:ring-slate-100 outline-none w-full md:w-80 shadow-sm text-sm font-medium" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
            </div>
          </form>
        </div>

        <div className="divide-y divide-slate-50 max-h-[500px] overflow-y-auto">
          {filteredItems.length === 0 ? (
            <div className="p-20 text-center"><div className="bg-slate-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300"><currentTab.icon size={40} /></div><p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Lista vazia ou sem resultados</p></div>
          ) : (
            filteredItems.map((item: any) => {
              const driverLogin = activeTab === 'drivers' ? findDriverLogin(item.id, item.name) : null;
              return (
                <div key={item.id} className="p-6 flex flex-col md:flex-row md:items-center justify-between hover:bg-slate-50 transition-colors group">
                  {isEditing === item.id ? (
                    <div className="flex-1 space-y-3">
                      <div className="flex flex-col md:flex-row gap-2">
                        <input autoFocus type="text" className="flex-1 px-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white outline-none focus:ring-4 focus:ring-red-500/20 font-bold" value={editName} onChange={e => setEditName(e.target.value)} />
                        {activeTab === 'drivers' && (
                          <><input type="text" className="md:w-48 px-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white outline-none focus:ring-4 focus:ring-red-500/20 font-bold" value={editUsername} onChange={e => setEditUsername(e.target.value)} placeholder="Usuário" /><input type="text" className="md:w-48 px-4 py-3 rounded-xl border border-slate-700 bg-slate-900 text-white outline-none focus:ring-4 focus:ring-red-500/20 font-bold" value={editPassword} onChange={e => setEditPassword(e.target.value)} placeholder="Nova Senha" /></>
                        )}
                        <div className="flex space-x-2"><button onClick={() => handleUpdate(item.id)} className="flex-1 md:flex-none p-3 bg-emerald-600 text-white rounded-xl hover:bg-emerald-700"><Check size={20} className="mx-auto" /></button><button onClick={() => setIsEditing(null)} className="flex-1 md:flex-none p-3 bg-slate-200 text-slate-600 rounded-xl"><X size={20} className="mx-auto" /></button></div>
                      </div>
                    </div>
                  ) : (
                    <>
                      <div className="flex items-center space-x-4">
                        <div className="w-12 h-12 bg-white rounded-2xl flex items-center justify-center text-slate-400 shadow-sm border border-slate-100 group-hover:border-red-100 group-hover:text-red-500 transition-all"><currentTab.icon size={24} /></div>
                        <div>
                          <span className="font-black text-slate-800 text-lg tracking-tight">{item.name || item.plate}</span>
                          {activeTab === 'drivers' && (
                            <div className="flex items-center space-x-3 mt-1">
                              <div className="flex items-center space-x-1 text-[10px] font-black uppercase text-slate-400 tracking-tighter"><KeyRound size={12} className="text-red-400" /><span>Acesso: <span className="text-slate-900">{driverLogin?.username || 'Pendente'}</span></span></div>
                              <div className="w-1 h-1 rounded-full bg-slate-200"></div>
                              <div className="flex items-center space-x-1 text-[10px] font-black uppercase text-slate-400 tracking-tighter"><ShieldCheck size={12} className="text-emerald-500" /><span>ID Link: <span className="text-slate-900">{item.id.substring(0,8)}...</span></span></div>
                            </div>
                          )}
                        </div>
                      </div>
                      <div className="flex space-x-2 mt-4 md:mt-0 opacity-100 md:opacity-0 group-hover:opacity-100 transition-all">
                        <button onClick={() => { setIsEditing(item.id); setEditName(item.name || item.plate); setEditUsername(driverLogin?.username || ''); setEditPassword(driverLogin?.password || ''); }} className="flex-1 md:flex-none flex items-center space-x-2 bg-white px-4 py-2.5 rounded-xl border border-slate-200 text-slate-600 font-bold text-xs hover:border-red-600 hover:text-red-600 transition-all shadow-sm"><Edit2 size={14} /><span className="uppercase tracking-widest">Editar</span></button>
                        <button onClick={() => handleDelete(item.id)} className="p-2.5 bg-white rounded-xl border border-slate-200 text-slate-400 hover:border-red-600 hover:text-red-600 transition-all shadow-sm"><Trash2 size={16} /></button>
                      </div>
                    </>
                  )}
                </div>
              )
            })
          )}
        </div>
      </div>
    </div>
  );
};

export default Registrations;

