### 2. Correção do seu Google Apps Script (Importante!)

O seu erro de `parameter` é apenas porque você clicou em **Executar** no editor do Google. Mas, para a exclusão funcionar, você deve garantir que o seu script esteja assim (especialmente a parte do `clearContent`):

```javascript
// No seu Código.gs do Google Sheets
function doPost(e) {
  var payload = JSON.parse(e.postData.contents);
  if (payload.token !== "LOGITRANS_SECRET_2025") return ContentService.createTextOutput("Erro").setMimeType(ContentService.MimeType.TEXT);

  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var sheetsMap = {
    "Viagens": "Viagens", "Clientes": "Clientes", "Motoristas": "Motoristas", 
    "Veiculos": "Veiculos", "Locais": "Locais", "Materiais": "Materiais", 
    "Fretes": "Fretes", "Logins": "Logins"
  };

  for (var key in sheetsMap) {
    var sheet = ss.getSheetByName(sheetsMap[key]);
    if (!sheet) continue;
    var data = payload[key];
    if (!data || !Array.isArray(data)) continue;

    // === ESSA PARTE É O SEGREDO DA EXCLUSÃO ===
    // Limpa os dados antigos (linha 2 em diante) antes de gravar a nova lista (que vem sem o item excluído)
    if (sheet.getLastRow() > 1) {
      sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();
    }

    // Grava a nova lista (se houver itens)
    if (data.length > 0) {
      var headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
      var rows = data.map(function(item) {
        return headers.map(function(h) { 
          return (item[h] === undefined || item[h] === null) ? "" : item[h]; 
        });
      });
      sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
    }
  }
  return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
}
```

**Resumo das melhorias:**
1.  **Bloqueio de UI:** Agora o app mostra uma tela de "Sincronizando Banco" durante a exclusão. Isso garante que o usuário espere a resposta do servidor.
2.  **Lógica Funcional:** O `updateDB` agora usa o estado mais recente (`prev`) para garantir que se você excluir dois itens rápidos, o segundo não ignore a exclusão do primeiro.
3.  **Explicação do Erro:** O erro de `parameter` no Google Script é normal se você tentar rodar o script manualmente. Simplesmente salve o script, clique em **Implantar > Nova Implantação > App da Web** e use a URL gerada no seu `db.ts`.

