    try {
      const data = await fetchDB();
      setDb(data);
      return data;
    } catch (error: any) {
      console.error("Erro na carga inicial:", error);
      setLoadError(error.message || "Erro de conexão segura");
      return null;
    } finally {
      setIsLoading(false);
    }
  };

  const syncToCloud = async (targetDb: DB) => {
    setIsSyncing(true);
    setSyncStatus('idle');
    try {
      const success = await pushDB(targetDb);
      setSyncStatus(success ? 'success' : 'error');
      if (success) {
        setTimeout(() => setSyncStatus('idle'), 3000);
        return true;
      }
      return false;
    } catch (e) {
      setSyncStatus('error');
      return false;
    } finally {
      setIsSyncing(false);
    }
