  /**
   * Função robusta para atualizar o banco de dados.
   * Garante que a exclusão ocorra no estado local E seja enviada para a nuvem.
   */
  const updateDB = async (updater: (prev: DB) => DB) => {
    setIsProcessing(true);
    let success = false;

    try {
      let nextDbState: DB | null = null;

      // Atualiza o estado do React
      setDb(prev => {
        const next = updater(prev);
        nextDbState = next;
        return next;
      });

      // Aguarda um tick para garantir que a variável local foi populada pelo callback
      await new Promise(resolve => setTimeout(resolve, 10));

      if (nextDbState) {
        // Envia a nova lista completa para o Google Sheets (sobrescrevendo o antigo)
        success = await syncToCloud(nextDbState);
      }

      if (!success) {
        alert("Atenção: Os dados foram alterados no app, mas houve um erro ao salvar na planilha. Verifique sua internet.");
      }
    } catch (err) {
      console.error("Erro no updateDB:", err);
      alert("Erro ao processar a operação.");
