### Instruções Importantes para o Google Apps Script:

Para que a conexão funcione e você não receba mais o erro de `parameter` ou `Failed to fetch`, seu código no **Apps Script** deve ser atualizado para este formato robusto:

```javascript
// No editor do Google Sheets (Extensões > Apps Script)
function doGet(e) {
  // Se o objeto 'e' não existir (teste manual), retorna erro amigável
  if (!e || !e.parameter) {
    return ContentService.createTextOutput("Erro: O script deve ser acessado via URL. Não clique em 'Executar' no editor.").setMimeType(ContentService.MimeType.TEXT);
  }

  var token = e.parameter.token;
  if (token !== "LOGITRANS_SECRET_2025") {
    return ContentService.createTextOutput(JSON.stringify({error: "Unauthorized"})).setMimeType(ContentService.MimeType.JSON);
  }

  var ss = SpreadsheetApp.getActiveSpreadsheet();
  var result = {};
  var sheets = ss.getSheets();

  sheets.forEach(function(sheet) {
    var name = sheet.getName();
    var data = sheet.getDataRange().getValues();
    var headers = data[0];
    var rows = [];

    for (var i = 1; i < data.length; i++) {
      var obj = {};
      headers.forEach(function(header, index) {
        obj[header] = data[i][index];
      });
      rows.push(obj);
    }
    result[name] = rows;
  });

  return ContentService.createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

function doPost(e) {
  try {
    var payload = JSON.parse(e.postData.contents);
    if (payload.token !== "LOGITRANS_SECRET_2025") return ContentService.createTextOutput("Unauthorized");

    var ss = SpreadsheetApp.getActiveSpreadsheet();

    // Lista de abas que o sistema gerencia
    var sheetsMap = ["Viagens", "Clientes", "Motoristas", "Veiculos", "Locais", "Materiais", "Fretes", "Logins"];

    sheetsMap.forEach(function(key) {
      var sheet = ss.getSheetByName(key);
      if (!sheet) return;

      var data = payload[key];
      if (!data || !Array.isArray(data)) return;

      // Limpa dados antigos mantendo o cabeçalho
      if (sheet.getLastRow() > 1) {
        sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();
      }

      if (data.length > 0) {
        var headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
        var rows = data.map(function(item) {
          return headers.map(function(h) { 
            return (item[h] === undefined || item[h] === null) ? "" : item[h]; 
          });
        });
        sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
      }
    });

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
}
```

**Como Implantar Corretamente:**
1. No editor do Apps Script, clique em **Implantar > Nova Implantação**.
2. Selecione o tipo **App da Web**.
3. Em "Quem pode acessar", selecione obrigatoriamente **Qualquer pessoa** (isso é vital para evitar o erro de fetch).
4. Clique em **Implantar**, autorize o acesso e copie a **URL do App da Web**.
5. Cole essa URL na constante `API_URL` no arquivo `db.ts` do seu projeto.

