import { 
  Customer, Driver, Vehicle, Location, Material, FreightRate, Trip, Login 
} from './types';

// URL da API do Google Apps Script
const API_URL = 'https://script.google.com/macros/s/AKfycbzk7E2yRlmtn2oz9GZWoLAsv2wCW47KKRkKA6OhGHUydzqhss_F39D9k9f7cpbxvpiJ/exec';

// Token de Segurança (Deve ser igual no Apps Script)
const SECURITY_TOKEN = 'LOGITRANS_SECRET_2025';

export interface DB {
  customers: Customer[];
  drivers: Driver[];
  vehicles: Vehicle[];
  locations: Location[];
  materials: Material[];
  freightRates: FreightRate[];
  trips: Trip[];
  logins: Login[];
  recentIds: Record<string, string[]>;
}

export const INITIAL_DB: DB = {
  customers: [],
  drivers: [],
  vehicles: [],
  locations: [],
  materials: [],
  freightRates: [],
  trips: [],
  logins: [],
  recentIds: {}
};

export const generateId = () => {
  try {
    return crypto.randomUUID();
  } catch (e) {
    return 'id-' + Math.random().toString(36).substring(2, 11) + '-' + Date.now();
  }
};

const mapToSheet = (data: any[], type: string) => {
  if (!data || !Array.isArray(data)) return [];

  if (type === 'trips') {
    return data.map((t: Trip) => ({
      id: String(t.id),
      data: t.date,
      nota_fiscal: String(t.invoiceNumber),
      cliente_id: String(t.customerId),
      motorista_id: String(t.driverId),
      veiculo_id: String(t.vehicleId),
      local_carregamento_id: String(t.originId),
      local_descarga_id: String(t.destinationId),
      material_id: String(t.materialId),
      quantidade_toneladas: Number(t.qtyTons),
      valor_tonelada: Number(t.pricePerTon),
      valor_total: Number(t.totalValue),
      foto_nota: t.invoiceImageUrl || '' // Novo campo para persistência de imagem
    }));
  }
  if (type === 'logins') {
    return data.map((l: Login) => ({
      id: String(l.id),
      username: String(l.username),
      senha: String(l.password || '').trim(),
      role: String(l.role)
    }));
  }
  if (type === 'freightRates') {
    return data.map((f: FreightRate) => ({
      id: String(f.id),
      local_origem_id: String(f.originId),
      local_destino_id: String(f.destinationId),
      valor_tonelada: Number(f.pricePerTon)
    }));
  }
  if (type === 'vehicles') {
    return data.map((v: Vehicle) => ({ id: String(v.id), placa: String(v.plate) }));
  }
  return data.map(item => ({
    id: String(item.id),
    nome: String(item.name)
  }));
};

const mapFromSheet = (data: any[], type: string) => {
  if (!data || !Array.isArray(data)) return [];

  if (type === 'trips') {
    return data.map((t: any) => ({
      id: String(t.id || ''),
      date: t.data || '',
      invoiceNumber: String(t.nota_fiscal || ''),
      customerId: String(t.cliente_id || ''),
      driverId: String(t.motorista_id || ''),
      vehicleId: String(t.veiculo_id || ''),
      originId: String(t.local_carregamento_id || ''),
      destinationId: String(t.local_descarga_id || ''),
      materialId: String(t.material_id || ''),
      qtyTons: Number(t.quantidade_toneladas || 0),
      pricePerTon: Number(t.valor_tonelada || 0),
      totalValue: Number(t.valor_total || 0),
      createdAt: Date.now(),
      invoiceImageUrl: String(t.foto_nota || '') // Recuperação da imagem
    }));
  }
  if (type === 'logins') {
    return data.map((l: any) => ({
      id: String(l.id || ''),
      username: String(l.username || ''),
      password: String(l.senha || ''), 
      role: String(l.role || 'driver') as 'admin' | 'driver'
    }));
  }
  if (type === 'freightRates') {
    return data.map((f: any) => ({
      id: String(f.id || ''),
      originId: String(f.local_origem_id || ''),
      destinationId: String(f.local_destino_id || ''),
      pricePerTon: Number(f.valor_tonelada || 0)
    }));
  }
  if (type === 'vehicles') {
    return data.map((v: any) => ({ 
      id: String(v.id || ''), 
      plate: String(v.placa || '') 
    }));
  }
  return data.map(item => ({
    id: String(item.id || ''),
    name: String(item.nome || '')
  }));
};

export const fetchDB = async (retries = 2): Promise<DB> => {
  try {
    const url = `${API_URL}?token=${SECURITY_TOKEN}&action=read&_t=${Date.now()}`;
    const response = await fetch(url, {
      method: 'GET',
      mode: 'cors',
      credentials: 'omit'
    });

    if (!response.ok) {
      throw new Error(`Erro na rede (Status: ${response.status}). Verifique se o script está publicado como 'Qualquer pessoa'.`);
    }

    const rawData = await response.json();

    if (rawData.error) {
      throw new Error(`Erro do Servidor: ${rawData.error}`);
    }

    return {
      customers: mapFromSheet(rawData.Clientes, 'customers') as Customer[],
      drivers: mapFromSheet(rawData.Motoristas, 'drivers') as Driver[],
      vehicles: mapFromSheet(rawData.Veiculos, 'vehicles') as Vehicle[],
      locations: mapFromSheet(rawData.Locais, 'locations') as Location[],
      materials: mapFromSheet(rawData.Materiais, 'materials') as Material[],
      freightRates: mapFromSheet(rawData.Fretes, 'freightRates') as FreightRate[],
      trips: mapFromSheet(rawData.Viagens, 'trips') as Trip[],
      logins: mapFromSheet(rawData.Logins, 'logins') as Login[],
      recentIds: rawData.Metadata?.recentIds || {}
    };
  } catch (error: any) {
    if (retries > 0) return fetchDB(retries - 1);
    console.error("Erro detalhado fetchDB:", error);
    throw new Error(error.message === 'Failed to fetch' 
      ? "Erro de CORS ou Rede. Certifique-se de que a URL do Script está correta e implantada como Web App para 'Qualquer Pessoa'." 
      : error.message);
  }
};

export const pushDB = async (db: DB): Promise<boolean> => {
  try {
    const payload = {
      token: SECURITY_TOKEN,
      Viagens: mapToSheet(db.trips, 'trips'),
      Clientes: mapToSheet(db.customers, 'customers'),
      Motoristas: mapToSheet(db.drivers, 'drivers'),
      Veiculos: mapToSheet(db.vehicles, 'vehicles'),
      Locais: mapToSheet(db.locations, 'locations'),
      Materiais: mapToSheet(db.materials, 'materials'),
      Fretes: mapToSheet(db.freightRates, 'freightRates'),
      Logins: mapToSheet(db.logins, 'logins')
    };

    // O POST para o Google Apps Script é sensível ao Content-Type.
    // Usamos text/plain para evitar o Preflight OPTIONS que o Google não suporta nativamente.
    const response = await fetch(API_URL, {
      method: 'POST',
      mode: 'cors',
      redirect: 'follow', 
      body: JSON.stringify(payload),
      headers: { 
        'Content-Type': 'text/plain;charset=utf-8' 
      }
    });

    if (!response.ok) {
      console.error("Erro na resposta do POST:", response.status);
      return false;
    }

    const result = await response.text();
    const isSuccess = result.trim().toLowerCase().includes("success");

    if (!isSuccess) {
      console.warn("Resposta do servidor não indica sucesso:", result);
    }

    return isSuccess;
  } catch (error) {
    console.error('Erro de rede ao sincronizar:', error);
    return false;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Save, X, Info, Calculator, Calendar, Truck, Camera, Sparkles, Loader2, CheckCircle2, Image as ImageIcon, RefreshCcw, Eye, Trash2 } from 'lucide-react';
import { Trip, FreightRate, UserSession } from '../types';
import { generateId } from '../db';
import { GoogleGenAI } from "@google/genai";

interface NewTripFormProps {
  db: any;
  user: UserSession;
  initialData?: Trip;
  onSave: (trip: Trip) => void;
  onCancel: () => void;
}

const NewTripForm: React.FC<NewTripFormProps> = ({ db, user, initialData, onSave, onCancel }) => {
  const [formData, setFormData] = useState({
    date: initialData?.date || new Date().toISOString().split('T')[0],
    invoiceNumber: initialData?.invoiceNumber || '',
    customerId: initialData?.customerId || '',
    driverId: initialData?.driverId || (user.role === 'driver' ? user.driverId : ''),
    vehicleId: initialData?.vehicleId || '',
    originId: initialData?.originId || '',
    destinationId: initialData?.destinationId || '',
    materialId: initialData?.materialId || '',
    qtyTons: initialData?.qtyTons || 0,
    pricePerTon: initialData?.pricePerTon || 0,
    totalValue: initialData?.totalValue || 0,
    invoiceImageUrl: initialData?.invoiceImageUrl || ''
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isScanning, setIsScanning] = useState(false);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const [showConfirmModal, setShowConfirmModal] = useState(false);
  const [extractedData, setExtractedData] = useState<any>(null);
  const [showFullImage, setShowFullImage] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const isAdmin = user.role === 'admin';

  const getSortedOptions = <T extends { id: string; name?: string; plate?: string }>(
    list: T[], 
    category: string
  ) => {
    const recents = db.recentIds[category] || [];
    return [...list].sort((a, b) => {
      const aRecent = recents.indexOf(a.id);
      const bRecent = recents.indexOf(b.id);
      if (aRecent !== -1 && bRecent !== -1) return aRecent - bRecent;
      if (aRecent !== -1) return -1;
      if (bRecent !== -1) return 1;
      const aName = a.name || a.plate || '';
      const bName = b.name || b.plate || '';
      return aName.localeCompare(bName);
    });
  };

  useEffect(() => {
    if (formData.originId && formData.destinationId) {
      const rate = db.freightRates.find(
        (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
      );

      if (initialData && formData.originId === initialData.originId && formData.destinationId === initialData.destinationId) {
        return;
      }

      if (rate) {
        setFormData(prev => ({ ...prev, pricePerTon: rate.pricePerTon }));
      }
    }
  }, [formData.originId, formData.destinationId, db.freightRates]);

  useEffect(() => {
    setFormData(prev => ({ 
      ...prev, 
      totalValue: Number((prev.qtyTons * prev.pricePerTon).toFixed(2)) 
    }));
  }, [formData.qtyTons, formData.pricePerTon]);

  // CAMERA LOGIC
  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'environment' }, 
        audio: false 
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      setIsCameraActive(true);
    } catch (err) {
      console.error("Erro ao acessar câmera:", err);
      alert("Não foi possível acessar a câmera. Verifique as permissões.");
    }
  };

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop());
      streamRef.current = null;
    }
    setIsCameraActive(false);
  };

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL('image/jpeg', 0.7); // Comprimindo um pouco para o Sheets
        const base64 = dataUrl.split(',')[1];
        processImageBase64(base64, 'image/jpeg');
        stopCamera();
      }
    }
  };

  const handleGalleryClick = () => {
    fileInputRef.current?.click();
  };

  const onFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => {
      const result = reader.result as string;
      const base64 = result.split(',')[1];
      processImageBase64(base64, file.type);
    };
  };

  const processImageBase64 = async (base64Data: string, mimeType: string) => {
    setIsScanning(true);
    const fullBase64Url = `data:${mimeType};base64,${base64Data}`;

    // Armazena a imagem no formulário mesmo antes do processamento da IA
    setFormData(prev => ({ ...prev, invoiceImageUrl: fullBase64Url }));

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: "Extraia os seguintes campos desta Nota Fiscal (DANFE): data_emissao (formato YYYY-MM-DD), numero_nota (apenas dígitos), peso_liquido_toneladas (número decimal, procure especificamente por 'Peso Líquido'). Se não encontrar peso líquido em toneladas, converta de KG se necessário. Retorne apenas JSON puro." }
          ]
        },
        config: { responseMimeType: "application/json" }
      });

      const result = JSON.parse(response.text || '{}');
      setExtractedData(result);
      setShowConfirmModal(true);
    } catch (error) {
      console.error("Erro na leitura da IA:", error);
      alert("Imagem anexada, mas não foi possível extrair dados automaticamente. Preencha manualmente.");
    } finally {
      setIsScanning(false);
    }
  };

  const confirmExtractedData = () => {
    if (extractedData) {
      setFormData(prev => ({
        ...prev,
        date: extractedData.data_emissao || prev.date,
        invoiceNumber: extractedData.numero_nota || prev.invoiceNumber,
        qtyTons: Number(extractedData.peso_liquido_toneladas) || prev.qtyTons
      }));
    }
    setShowConfirmModal(false);
  };

  const validate = () => {
    const newErrors: Record<string, string> = {};
    if (!formData.invoiceNumber) newErrors.invoiceNumber = 'Campo obrigatório';

    const nfConflict = db.trips.some((t: Trip) => 
      t.invoiceNumber === formData.invoiceNumber && t.id !== initialData?.id
    );
    if (nfConflict) {
      newErrors.invoiceNumber = 'Nota fiscal já cadastrada';
    }

    if (!formData.customerId) newErrors.customerId = 'Selecione o cliente';
    if (!formData.driverId) newErrors.driverId = 'Selecione o motorista';
    if (!formData.vehicleId) newErrors.vehicleId = 'Selecione o veículo';
    if (!formData.originId) newErrors.originId = 'Selecione a origem';
    if (!formData.destinationId) newErrors.destinationId = 'Selecione o destino';
    if (formData.qtyTons <= 0) newErrors.qtyTons = 'Deve ser maior que zero';

    if (isAdmin) {
      const routeExists = db.freightRates.some(
        (fr: FreightRate) => fr.originId === formData.originId && fr.destinationId === formData.destinationId
      );
      if (!routeExists && formData.originId && formData.destinationId) {
        newErrors.route = 'Rota não cadastrada na Tabela de Fretes';
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!validate()) return;

    const savedTrip: Trip = {
      ...formData,
      id: initialData?.id || generateId(),
      createdAt: initialData?.createdAt || Date.now()
    };
    onSave(savedTrip);
  };

  const inputClass = (field: string, isSelect: boolean = false) => `
    w-full px-4 py-4 rounded-xl border outline-none transition-all
    bg-slate-900 text-white placeholder-slate-400 font-bold text-base shadow-inner
    ${isSelect ? 'dark-select' : ''}
    ${errors[field] ? 'border-red-500 ring-2 ring-red-500/20' : 'border-slate-700 focus:ring-4 focus:ring-red-500/20 focus:border-red-500'}
  `;

  return (
    <div className="max-w-4xl mx-auto space-y-6 animate-in slide-in-from-bottom-4 duration-500 pb-20">
      <div className="flex items-center justify-between">
        <h2 className="text-2xl font-black text-slate-900 tracking-tight">
          {initialData ? 'Editar Lançamento' : 'Novo Lançamento'}
        </h2>
        <div className="flex items-center space-x-2">
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={onFileChange} 
            accept="image/*" 
            className="hidden" 
          />
          {!initialData && (
            <div className="flex space-x-2">
              <button 
                type="button"
                onClick={handleGalleryClick}
                disabled={isScanning}
