Para a solução de longo prazo (Google Drive), precisamos de duas partes: o **Script do Google (Apps Script)** atualizado e o ajuste no **Frontend** para enviar as fotos com melhor qualidade (já que o Drive não tem o limite de 50 mil caracteres da célula do Sheets).

### 1. Novo Script do Google (Copie e cole no seu Apps Script)

Este script identifica se o campo `foto_nota` contém uma imagem em Base64. Se sim, ele cria um arquivo no Google Drive, gera um link público e salva esse link na planilha no lugar do texto gigante.

```javascript
// No seu Google Apps Script (Editor de Script)
const SECURITY_TOKEN = 'LOGITRANS_SECRET_2025';
const FOLDER_NAME = 'Comprovantes_LogiTrans';

function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);
    if (data.token !== SECURITY_TOKEN) return ContentService.createTextOutput("Unauthorized").setMimeType(ContentService.MimeType.TEXT);

    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const folder = getOrCreateFolder(FOLDER_NAME);

    // Processar Tabelas
    Object.keys(data).forEach(sheetName => {
      if (sheetName === 'token') return;
      const sheet = ss.getSheetByName(sheetName);
      if (!sheet) return;

      const rows = data[sheetName];
      if (!rows || rows.length === 0) return;

      // Se for a aba de Viagens, processar imagens para o Drive
      if (sheetName === 'Viagens') {
        rows.forEach(row => {
          if (row.foto_nota && row.foto_nota.startsWith('data:image')) {
            row.foto_nota = saveToDrive(row.foto_nota, `NF_${row.nota_fiscal}_${row.id}`, folder);
          }
        });
      }

      const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
      sheet.getRange(2, 1, sheet.getLastRow(), sheet.getLastColumn()).clearContent();

      const values = rows.map(row => headers.map(h => row[h] || ""));
      if (values.length > 0) {
        sheet.getRange(2, 1, values.length, headers.length).setValues(values);
      }
    });

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.toString()).setMimeType(ContentService.MimeType.TEXT);
  }
}

function saveToDrive(base64Data, fileName, folder) {
  try {
    const splitData = base64Data.split(',');
    const contentType = splitData[0].match(/:(.*?);/)[1];
    const bytes = Utilities.base64Decode(splitData[1]);
    const blob = Utilities.newBlob(bytes, contentType, fileName + ".jpg");

    const file = folder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);
    return file.getUrl(); // Retorna o link do arquivo no Drive
  } catch (e) {
    return "Error saving image: " + e.toString();
  }
}

function getOrCreateFolder(name) {
  const folders = DriveApp.getFoldersByName(name);
  if (folders.hasNext()) return folders.next();
  return DriveApp.createFolder(name);
}
```

### 2. Atualização no App (Frontend)

Agora que as fotos vão para o Drive, podemos aumentar a qualidade da captura para 800px e 0.7 de qualidade, garantindo que as notas fiquem nítidas.

