                    <button type="button" onClick={() => setShowFullImage(true)} className="p-3 bg-white rounded-full text-slate-900"><Eye size={24} /></button>
                    {!initialData && <button type="button" onClick={() => setFormData(p => ({ ...p, invoiceImageUrl: '' }))} className="p-3 bg-white rounded-full text-red-600"><Trash2 size={24} /></button>}
                  </div>
                </div>
                <div className="absolute top-2 right-2 bg-emerald-500 text-white p-1 rounded-full"><CheckCircle2 size={16} /></div>
                <p className="text-[10px] font-black text-slate-400 uppercase mt-2 tracking-widest text-center">Comprovante de Alta Resolução ✓</p>
              </div>
