            </div>
            <div className="mt-12 flex items-center space-x-8">
              <button type="button" onClick={stopCamera} className="bg-white/10 p-4 rounded-full text-white"><RefreshCcw size={28} /></button>
              <button type="button" onClick={capturePhoto} className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center bg-red-600 active:scale-90 transition-transform"><div className="w-14 h-14 rounded-full border-2 border-white/50"></div></button>
              <div className="w-14"></div>
            </div>
          </div>
          <canvas ref={canvasRef} className="hidden" />
