Para implementar a solução definitiva de longo prazo usando o **Google Drive**, você precisa de duas coisas: atualizar o seu código no Google Apps Script (para que ele crie as pastas e salve os arquivos) e ajustar o frontend para enviar imagens com melhor qualidade (já que o Drive não tem o limite de espaço de uma célula).

### 1. Novo Código para o Google Apps Script (código.gs)

Este script substitui o seu atual. Ele identifica automaticamente se o campo `foto_nota` contém uma imagem em Base64, cria uma pasta chamada "LogiTrans_Anexos" no seu Drive, salva a imagem lá e grava o **link direto** da foto na planilha.

```javascript
// CONFIGURAÇÕES
const SECURITY_TOKEN = 'LOGITRANS_SECRET_2025';
const FOLDER_NAME = 'LogiTrans_Anexos';

function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);

    // Validação de Token
    if (data.token !== SECURITY_TOKEN) {
      return ContentService.createTextOutput("Unauthorized").setMimeType(ContentService.MimeType.TEXT);
    }

    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const folder = getOrCreateFolder(FOLDER_NAME);

    // Iterar pelas abas enviadas no payload
    Object.keys(data).forEach(sheetName => {
      if (sheetName === 'token') return;

      const sheet = ss.getSheetByName(sheetName);
      if (!sheet) return;

      const rows = data[sheetName];
      if (!rows || rows.length === 0) return;

      // Se for a aba de Viagens, processamos as fotos para o Drive
      if (sheetName === 'Viagens') {
        rows.forEach(row => {
          // Se o campo foto_nota contiver um Base64 (data:image/...)
          if (row.foto_nota && row.foto_nota.toString().startsWith('data:image')) {
            const fileName = `NF_${row.nota_fiscal}_${row.id}`;
            row.foto_nota = saveBase64ToDrive(row.foto_nota, fileName, folder);
          }
        });
      }

      // Limpar e Reescrever (Sincronização Total)
      const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
      if (sheet.getLastRow() > 1) {
        sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();
      }

      const values = rows.map(row => headers.map(h => row[h] !== undefined ? row[h] : ""));
      if (values.length > 0) {
        sheet.getRange(2, 1, values.length, headers.length).setValues(values);
      }
    });

    return ContentService.createTextOutput("Success").setMimeType(ContentService.MimeType.TEXT);
  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.toString()).setMimeType(ContentService.MimeType.TEXT);
  }
}

// Função para salvar Base64 no Drive e retornar a URL
function saveBase64ToDrive(base64String, fileName, folder) {
  try {
    const parts = base64String.split(',');
    const contentType = parts[0].split(':')[1].split(';')[0];
    const decoded = Utilities.base64Decode(parts[1]);
    const blob = Utilities.newBlob(decoded, contentType, fileName);

    const file = folder.createFile(blob);
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    return file.getUrl(); // Retorna o link para salvar na célula
  } catch (e) {
    return "Erro ao salvar: " + e.toString();
  }
}

// Busca ou cria a pasta de anexos
function getOrCreateFolder(name) {
  const folders = DriveApp.getFoldersByName(name);
  if (folders.hasNext()) return folders.next();
  return DriveApp.createFolder(name);
}

function doGet(e) {
  // Mantém sua função doGet atual para leitura...
  // (Certifique-se de que ela retorna os dados das abas como Clientes, Viagens, etc.)
}
```

### 2. Ajustes no Aplicativo (Frontend)

Vou atualizar o `NewTripForm.tsx` para garantir que ele capture imagens com resolução maior (800px) e qualidade melhor, já que o Drive suporta arquivos maiores que as células da planilha.

