            </div>
            <div className="mt-12 flex items-center space-x-8">
              <button type="button" onClick={capturePhoto} className="w-20 h-20 rounded-full border-4 border-white flex items-center justify-center bg-red-600 active:scale-90"><div className="w-14 h-14 rounded-full border-2 border-white/50"></div></button>
            </div>
          </div>
          <canvas ref={canvasRef} className="hidden" />
