Aqui está o código completo e robusto para o seu **Google Apps Script (`código.gs`)**.

Este script realiza a sincronização total entre o App e a Planilha, detecta automaticamente quando uma imagem é enviada em Base64, salva o arquivo em uma pasta específica no seu **Google Drive**, gera um link público e salva esse link na célula da planilha, evitando o erro de limite de caracteres.

### Código do Google Apps Script (`código.gs`)

```javascript
/**
 * LogiTrans - Backend de Sincronização e Armazenamento no Drive
 * Desenvolvido para persistência de dados e imagens de Notas Fiscais.
 */

// CONFIGURAÇÕES GERAIS
const SECURITY_TOKEN = 'LOGITRANS_SECRET_2025'; // Deve ser igual ao db.ts do App
const FOLDER_NAME = 'LogiTrans_Anexos';        // Nome da pasta no seu Google Drive

/**
 * Função principal para receber dados do App (POST)
 */
function doPost(e) {
  try {
    const data = JSON.parse(e.postData.contents);

    // 1. Validação de Token de Segurança
    if (data.token !== SECURITY_TOKEN) {
      return ContentService.createTextOutput("Erro: Não autorizado").setMimeType(ContentService.MimeType.TEXT);
    }

    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const folder = getOrCreateFolder(FOLDER_NAME);

    // 2. Iterar sobre todas as abas enviadas no payload (Viagens, Clientes, Motoristas, etc)
    Object.keys(data).forEach(sheetName => {
      if (sheetName === 'token') return; // Pula o campo do token

      const sheet = ss.getSheetByName(sheetName);
      if (!sheet) return; // Pula se a aba não existir na planilha

      const rows = data[sheetName];
      if (!rows || !Array.isArray(rows)) return;

      // 3. Processamento especial para Fotos na aba de Viagens
      if (sheetName === 'Viagens') {
        rows.forEach(row => {
          // Se o campo 'foto_nota' contiver uma imagem em Base64 (começa com data:image)
          if (row.foto_nota && row.foto_nota.toString().startsWith('data:image')) {
            const fileName = `NF_${row.nota_fiscal || 'S_N'}_${row.id || 'ID'}`;
            // Substitui o código da imagem pelo link do Google Drive
            row.foto_nota = saveBase64ToDrive(row.foto_nota, fileName, folder);
          }
        });
      }

      // 4. Sincronização Total: Limpa e reescreve a aba
      const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];

      // Limpar dados antigos (preservando o cabeçalho)
      if (sheet.getLastRow() > 1) {
        sheet.getRange(2, 1, sheet.getLastRow() - 1, sheet.getLastColumn()).clearContent();
      }

      // Mapear os dados do JSON para as colunas baseadas nos nomes dos cabeçalhos
      const values = rows.map(row => {
        return headers.map(header => {
          return (row[header] !== undefined && row[header] !== null) ? row[header] : "";
        });
      });

      // Gravar novos dados na planilha
      if (values.length > 0) {
        sheet.getRange(2, 1, values.length, headers.length).setValues(values);
      }
    });

    return ContentService.createTextOutput("success").setMimeType(ContentService.MimeType.TEXT);

  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.toString()).setMimeType(ContentService.MimeType.TEXT);
  }
}

/**
 * Função para ler dados da Planilha (GET)
 */
function doGet(e) {
  try {
    const token = e.parameter.token;
    if (token !== SECURITY_TOKEN) {
      return ContentService.createTextOutput(JSON.stringify({ error: "Unauthorized" })).setMimeType(ContentService.MimeType.JSON);
    }

    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheets = ss.getSheets();
    const result = {};

    sheets.forEach(sheet => {
      const name = sheet.getName();
      const data = sheet.getDataRange().getValues();
      const headers = data.shift();

      const rows = data.map(r => {
        const obj = {};
        headers.forEach((h, i) => obj[h] = r[i]);
        return obj;
      });

      result[name] = rows;
    });

    return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);

  } catch (err) {
    return ContentService.createTextOutput(JSON.stringify({ error: err.toString() })).setMimeType(ContentService.MimeType.JSON);
  }
}

/**
 * Auxiliar: Salva a imagem Base64 no Google Drive e retorna o Link
 */
function saveBase64ToDrive(base64String, fileName, folder) {
  try {
    const parts = base64String.split(',');
    const contentType = parts[0].split(':')[1].split(';')[0];
    const decoded = Utilities.base64Decode(parts[1]);
    const blob = Utilities.newBlob(decoded, contentType, fileName);

    const file = folder.createFile(blob);

    // Define permissão para que qualquer pessoa com o link possa ver (importante para o App)
    file.setSharing(DriveApp.Access.ANYONE_WITH_LINK, DriveApp.Permission.VIEW);

    // O link retornado abaixo é o que será salvo na célula da planilha
    return file.getUrl(); 
  } catch (e) {
    return "Erro no upload: " + e.toString();
  }
}

/**
 * Auxiliar: Busca ou cria a pasta de destino no Drive
 */
function getOrCreateFolder(name) {
  const folders = DriveApp.getFoldersByName(name);
  if (folders.hasNext()) {
    return folders.next();
  } else {
    return DriveApp.createFolder(name);
  }
}
```

### Como configurar corretamente:

1.  No Google Sheets, vá em **Extensões > Apps Script**.
2.  Cole o código acima, substituindo tudo o que houver lá.
3.  Clique em **Salvar** (ícone de disquete).
4.  Clique em **Implantar > Nova implantação**.
5.  Selecione o tipo **App da Web**.
6.  **Configurações importantes:**
    *   **Descrição:** LogiTrans v2 (Drive)
    *   **Executar como:** Eu (seu e-mail)
    *   **Quem tem acesso:** Qualquer pessoa (isso é vital para o App conseguir se comunicar).
7.  Clique em **Implantar**. O Google pedirá para você autorizar o acesso ao seu Google Drive e Planilhas. Conceda as permissões.
8.  **Copie a nova URL do App da Web** gerada e verifique se ela é exatamente a mesma que está na constante `API_URL` dentro do seu arquivo `db.ts` no projeto React.

### Observação sobre a Planilha:
Certifique-se de que na aba **Viagens**, o cabeçalho da última coluna seja exatamente `foto_nota` (minúsculo, com underline), pois o script usa esse nome para localizar onde salvar o link da imagem.

