    if (payload.token !== SECURITY_TOKEN) {
      return ContentService.createTextOutput("Error: Unauthorized").setMimeType(ContentService.MimeType.TEXT);
    }

    const ss = SpreadsheetApp.getActiveSpreadsheet();

    // Processar cada aba enviada no payload
    Object.keys(payload).forEach(key => {
      if (key === 'token') return;

      let sheet = ss.getSheetByName(key);
      if (!sheet) {
        sheet = ss.insertSheet(key);
      }

      const data = payload[key];
      if (data.length === 0) return;

      const headers = Object.keys(data[0]);
      sheet.clear();
      sheet.appendRow(headers);

      const rows = data.map(item => {
        // Se for a aba de Viagens, processar a foto
        if (key === "Viagens" && item.foto_nota && item.foto_nota.startsWith("data:image")) {
          item.foto_nota = saveBase64Image(item.foto_nota, "NF_" + item.nota_fiscal + "_" + item.id);
        }
        return headers.map(h => item[h]);
      });

      if (rows.length > 0) {
        sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
      }
    });

    return ContentService.createTextOutput("success").setMimeType(ContentService.MimeType.TEXT);

  } catch (err) {
    return ContentService.createTextOutput("Error: " + err.message).setMimeType(ContentService.MimeType.TEXT);
  }
