 * 
 * FUNÇÕES:
 * - doGet: Lê todos os dados das planilhas e envia para o App.
 * - doPost: Recebe atualizações do App e salva fotos no Drive.
 */

const SECURITY_TOKEN = "LOGITRANS_SECRET_2025";
const FOLDER_NAME = "Comprovantes_LogiTrans";

/**
 * LÊ DADOS (GET)
 */
function doGet(e) {
  try {
    const token = e.parameter.token;
    if (token !== SECURITY_TOKEN) {
      return responseJSON({error: "Token de segurança inválido"});
    }

    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheets = ss.getSheets();
    const db = {};

    sheets.forEach(sheet => {
      const sheetName = sheet.getName();
      const data = sheet.getDataRange().getValues();
      if (data.length > 0) {
        const headers = data.shift();
        const rows = data.map(row => {
          const obj = {};
          headers.forEach((h, i) => {
            if (h) obj[h] = row[i];
          });
          return obj;
        });
        db[sheetName] = rows;
      } else {
        db[sheetName] = [];
      }
    });

    return responseJSON(db);
  } catch (err) {
    return responseJSON({error: err.toString()});
  }
}

/**
 * GRAVA DADOS (POST)
 */
function doPost(e) {
  try {
    const contents = e.postData.contents;
    const payload = JSON.parse(contents);

    if (payload.token !== SECURITY_TOKEN) {
      return responseText("Error: Unauthorized");
    }

    const ss = SpreadsheetApp.getActiveSpreadsheet();

    // Itera sobre cada chave do payload (cada chave é o nome de uma aba)
    for (const key in payload) {
      if (key === 'token') continue;

      const data = payload[key];
      if (!Array.isArray(data)) continue;

      let sheet = ss.getSheetByName(key);
      if (!sheet) {
        sheet = ss.insertSheet(key);
      }

      // Limpa a planilha antes de inserir novos dados (sincronização total)
      sheet.clearContents();

      if (data.length > 0) {
        const headers = Object.keys(data[0]);
        sheet.appendRow(headers); // Insere cabeçalhos

        const rows = data.map(item => {
          // Se for a aba de Viagens, verifica se há uma imagem nova em base64
          if (key === "Viagens" && item.foto_nota && typeof item.foto_nota === 'string' && item.foto_nota.indexOf("data:image") === 0) {
            item.foto_nota = saveBase64Image(item.foto_nota, "NF_" + item.nota_fiscal + "_" + item.id);
          }
          return headers.map(h => item[h] || "");
        });

        // Insere todas as linhas de uma vez para performance
        sheet.getRange(2, 1, rows.length, headers.length).setValues(rows);
      }
    }

    return responseText("success");

  } catch (err) {
    return responseText("Error: " + err.toString());
  }
}

