      if (!hasKey && !process.env.API_KEY) {
        await window.aistudio.openSelectKey();
      }

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: {
          parts: [
            { inlineData: { data: base64Data, mimeType: mimeType } },
            { text: "Extraia os seguintes campos desta Nota Fiscal (DANFE): data_emissao (formato YYYY-MM-DD), numero_nota (apenas dígitos), peso_liquido_toneladas (número decimal). Retorne apenas JSON puro." }
          ]
        },
        config: { responseMimeType: "application/json" }
      });

      const result = JSON.parse(response.text || '{}');
      setExtractedData(result);
      setShowConfirmModal(true);
    } catch (error: any) {
      console.error("Erro na extração IA:", error);

      if (error.message?.includes("Requested entity was not found")) {
        setApiError("Chave de API inválida ou não selecionada. Por favor, configure a chave paga.");
        await window.aistudio.openSelectKey();
      } else {
        setApiError("Não foi possível ler os dados da NF automaticamente, mas a imagem foi anexada.");
      }
    } finally {
      setIsScanning(false);
    }
  };

  const confirmExtractedData = () => {
    if (extractedData) {
      setFormData(prev => ({
        ...prev,
        invoiceNumber: extractedData.numero_nota || prev.invoiceNumber,
        date: extractedData.data_emissao || prev.date,
        qtyTons: extractedData.peso_liquido_toneladas ? Number(extractedData.peso_liquido_toneladas) : prev.qtyTons,
