    dbRef.current = db;
  }, [db]);

  const loadData = async () => {
    setIsLoading(true);
    setLoadError(null);
    try {
      const data = await fetchDB();
      setDb(data);
      return data;
    } catch (error: any) {
      console.error("Erro na carga inicial:", error);
      setLoadError(error.message || "Erro de conexão com o banco de dados.");
      return null;
    } finally {
      setIsLoading(false);
    }
  };

